-- Poems batch 375
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('bdd02776-337e-4a2a-bb59-b64f063b4d71','米元暉待制歲以賜冰及荔子分遺季共而今年荔枝不至有詩次韻三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','醉墨猶多御府珍，訪求公後出華勛。',32,'全唐诗/poet.song.88000.json','["醉墨猶多御府珍，訪求公後出華勛。", "知君家有荔枝帖，不减當年王右軍。"]'),
('3ca91795-e14b-471d-b42f-ba90a85f6ce3','謝陳仲襄主簿惠詩卷','周紫芝','宋','宋诗','song-poetry','','[]','霜雪頻欺老，芝蘭日鬬芳。',48,'全唐诗/poet.song.88000.json','["霜雪頻欺老，芝蘭日鬬芳。", "官猶似仇覽，句擬學韋郎。", "郊島無前輩，曹劉可雁行。", "他年尚相見，此地必升堂。"]'),
('27d6dcf3-789e-4f52-a3f4-6b3f926fa8e1','李太白畫像二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','欲與天仙論等差，短長何止但詞華。',32,'全唐诗/poet.song.88000.json','["欲與天仙論等差，短長何止但詞華。", "誰人觧屈將軍手，爲脱烏皮六縫鞾。"]'),
('2235c272-d784-4d8b-a0da-0b200105ff33','李太白畫像二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','少陵詩瘦平生苦，太白才高一醉間。',32,'全唐诗/poet.song.88000.json','["少陵詩瘦平生苦，太白才高一醉間。", "投得江心波底月，却歸天上玉歸仙。"]'),
('f807ef0b-1369-4b92-b4f1-0198c82e5346','季共置酒酒間出龍眠數馬以示坐客最後出起雲妙甚爲賦長句','周紫芝','宋','宋诗','song-poetry','','[]','君侯酌客黄金杯，六龍下食慈明催。',176,'全唐诗/poet.song.88000.json','["君侯酌客黄金杯，六龍下食慈明催。", "醉開畫苑出天馬，遠自大宛西極來。", "起雲礧碨最後出，真龍八尺高崔嵬。", "青天欲雨雨未作，怒雲潑墨烏成堆。", "長鳴自怪兩耳立，路轉欲從雙鐙回。", "王良造父眼未識，驊騮驌驦天與才。", "朝從燕代暮南粤，萬里一息何遼哉。", "公今此畫何處得，外家中郎李公客。", "人間英物有護持，世上丹青少顔色。", "雙花蜀錦青絲囊，還公此畫公須藏。", "天寒夜半黑風起，邂逅恐逐飛雲翔。"]'),
('2f54d24f-c6a9-4cca-828e-1ebaa7c7937d','韓幹畫郭家師子花此畫本江南故家物自腕而下絹素爛脱李伯時得之馬忠肅家補足之蔡天啟貌本以傳其甥王季共','周紫芝','宋','宋诗','song-poetry','','[]','神駒墮地無渥洼，象龍不復來流沙。',160,'全唐诗/poet.song.88000.json','["神駒墮地無渥洼，象龍不復來流沙。", "開元畫手老韓幹，爲作郭家師子花。", "當年故物不堪看，踣鐡四蹄俱脱腕。", "英姿逸態猶精神，仿彿風鬃血流汗。", "龍眠畫足不畫蛇，意象異世同一家。", "由來四大各假合，得此三昧無等差。", "中郎名高自年少，畫工如山不同調。", "人間意氣驚薾雲，筆下風流爾得妙。", "王家人物小安豐，作詩論畫公所同。", "一洗萬古凡馬空，九原誰喚杜陵翁。"]'),
('3552fd27-463c-43e4-8bc3-cdd7fa4a32ac','季共以師子花見借作詩歸之而報甚寵且言隆近爲余作數馬奇甚乃作此詩以見願借之意','周紫芝','宋','宋诗','song-poetry','','[]','畫史俗士非畫者，支郎好馬能畫馬。',64,'全唐诗/poet.song.88000.json','["畫史俗士非畫者，支郎好馬能畫馬。", "爲君肯作數驊騮，班郎應歌天馬下。", "前人妙筆俱絕倫，後人骨冷喚不聞。", "試借雲衢千里足，洗我眼中凡馬羣。"]'),
('12477328-e3ab-4e06-b83a-bedd03e1b65d','季共以隆師四馬見示後三日作長句以歸之','周紫芝','宋','宋诗','song-poetry','','[]','少陵說馬誰擅場，老韓曹覇江都王。',64,'全唐诗/poet.song.88000.json','["少陵說馬誰擅場，老韓曹覇江都王。", "只今傳法誰得妙，支郎爲爇龍眠香。", "沙平草細春日長，何人識此真乘黄。", "歸君蓬齋君卷藏，似君千里方騰驤。"]'),
('b46f3d91-0309-40f8-9093-6bbc8522752b','次韻相之木犀六首  其一','周紫芝','宋','宋诗','song-poetry','','[]','拂色青衫不是粧，蘂珠宮裏淡鵝黄。',32,'全唐诗/poet.song.88000.json','["拂色青衫不是粧，蘂珠宮裏淡鵝黄。", "紫羅裳亦元無用，薝蔔花應自有香。"]'),
('19b7b769-0c3f-45c6-ba4d-17a5392f1608','次韻相之木犀六首  其二','周紫芝','宋','宋诗','song-poetry','','[]','高樹層陰作翠雲，月華霜暈醒餘薫。',32,'全唐诗/poet.song.88000.json','["高樹層陰作翠雲，月華霜暈醒餘薫。", "人間韻少花俱俗，天上香來世未聞。"]'),
('e862e579-d499-4442-9004-ecfe2c208862','次韻相之木犀六首  其三','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖南北兩邊山，牢落孤芳不奈閑。',32,'全唐诗/poet.song.88000.json','["西湖南北兩邊山，牢落孤芳不奈閑。", "好遣長鬚挽黄粟，付他桃葉伴雲鬟。"]'),
('ce806a8c-7513-40be-8023-5089417f583b','次韻相之木犀六首  其四','周紫芝','宋','宋诗','song-poetry','','[]','故國幽姿想自妍，只今誰與著詩憐。',32,'全唐诗/poet.song.88000.json','["故國幽姿想自妍，只今誰與著詩憐。", "竹籬茅舍花開處，望斷江西眼欲穿。"]'),
('1cdd9bf0-83bd-4ab5-b25e-aee6d0560059','次韻相之木犀六首  其五','周紫芝','宋','宋诗','song-poetry','','[]','留香欲住正須陰，遠引山林却要侵。',32,'全唐诗/poet.song.88000.json','["留香欲住正須陰，遠引山林却要侵。", "絕韻有誰能畫得，郎潛詩妙最知心。"]'),
('481dc416-5278-4eb1-a65b-d7998942a7d2','次韻相之木犀六首  其六','周紫芝','宋','宋诗','song-poetry','','[]','玉折蘭摧事已休，倡條無數綠陰稠。',32,'全唐诗/poet.song.88000.json','["玉折蘭摧事已休，倡條無數綠陰稠。", "此花獨與蒼巖桂，風雨平分萬壑秋。"]'),
('9800bd75-6acf-4c2d-9922-8f708a3a0640','次韻吕晞樸九日見示','周紫芝','宋','宋诗','song-poetry','','[]','敢乞蘭金作詔泥，年今已是古來稀。',64,'全唐诗/poet.song.88000.json','["敢乞蘭金作詔泥，年今已是古來稀。", "一天細雨家何在，十載黄花客未歸。", "萬事可憐俱老境，故人猶欲借餘暉。", "但當洗眼秋風裏，飽看雲鵬作意飛。"]'),
('40251b5d-ea41-4483-93b2-ac341d036c8c','次韻陳簿席上見和','周紫芝','宋','宋诗','song-poetry','','[]','黄鵠摩霄未易知，倦飛寒雀本來卑。',64,'全唐诗/poet.song.88000.json','["黄鵠摩霄未易知，倦飛寒雀本來卑。", "頗慚陶令歸田早，政坐穰侯見事遲。", "偶有酒供鸜鵒舞，苦無人唱鷓鴣詞。", "秋來湖上山方好，食蛤重爲汗漫期。"]'),
('7a43e4aa-4f08-47af-ae05-fdf77c3c9f3d','河伯小史白事歌','周紫芝','宋','宋诗','song-poetry','','[]','馮夷宮中地無土，五更排衙朝擊鼓。',128,'全唐诗/poet.song.88000.json','["馮夷宮中地無土，五更排衙朝擊鼓。", "大官擁旆呵馬歸，小史白事當前語。", "自言賦命頗奇窮，一生自足風波苦。", "船須把纜始敢放，霧可藏身亦時吐。", "防危慮患豈不至，往往不知遭網罟。", "河神笑謂小史言，禍福不計愚與姦。", "恢恢天網自不失，瑣瑣爾曹何足論。", "小史速退卷舌走，顧視儔列圖前奔。"]'),
('8f95f65c-6b7e-4c07-9627-1c15a677c6aa','峡守秦德久楚塞樓成索詩爲作長句異時魯直遷涪江過之命此名且書牘今亡矣二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','使君才氣號無雙，千騎新來綰漢章。',64,'全唐诗/poet.song.88000.json','["使君才氣號無雙，千騎新來綰漢章。", "此日樓臺新楚塞，當年翰墨記黄香。", "民安樂歲州何事，江入清樽客滿床。", "十二巫山應在眼，定無遺事說襄王。"]'),
('faf64001-e5bc-4691-ba94-f82655b82602','峡守秦德久楚塞樓成索詩爲作長句異時魯直遷涪江過之命此名且書牘今亡矣二首  其二','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','淮上聲名徹冕旒，幾年邊鼓臥清秋。',64,'全唐诗/poet.song.88000.json','["淮上聲名徹冕旒，幾年邊鼓臥清秋。", "五花未從甘泉駕，百尺聊新楚塞樓。", "暮雨已隨烟珮去，長江空抱峽山流。", "客來欲吐窗閑句，莫把城南比閬州。"]'),
('057f4292-f55f-4a19-b660-ccad1c5fda31','題蘇養直畫像三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','先生初出後湖時，日落山寒醉不知。',32,'全唐诗/poet.song.88000.json','["先生初出後湖時，日落山寒醉不知。", "更上蹇驢何處去，灞橋風雪要渠詩。"]'),
('2634824f-7ae9-47d7-a4fc-e3219704ca8f','題蘇養直畫像三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','名滿人間未足多，胸中萬頃著烟波。',32,'全唐诗/poet.song.88000.json','["名滿人間未足多，胸中萬頃著烟波。", "松江風月無人見，誰與玄真畫釣蓑。"]'),
('6c325190-95f9-4869-a121-af5edae7d196','題蘇養直畫像三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','水上柴扉閉不開，蒼山羔雁九天來。',32,'全唐诗/poet.song.88000.json','["水上柴扉閉不開，蒼山羔雁九天來。", "玉京已有神仙籍，莫怪青山喚不回。"]'),
('62fd2e01-eb83-4018-bdb1-701c35c4e0c7','十月九日霽色可喜三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','屋角梅花欲弄晴，耐寒庭草尚晶瑩。',32,'全唐诗/poet.song.88000.json','["屋角梅花欲弄晴，耐寒庭草尚晶瑩。", "護霜雲重知何事，留得芭蕉作雨聲。"]'),
('ac5db8f6-7fea-4c10-8bfa-6602c4feb875','十月九日霽色可喜三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','朱門深閉得香多，曉日烘簾氣自和。',32,'全唐诗/poet.song.88000.json','["朱門深閉得香多，曉日烘簾氣自和。", "此地有窗無一席，固應宜著病維摩。"]'),
('5eb349ce-7ddf-402d-9fc0-33de4de482ad','十月九日霽色可喜三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','江上南枝暖欲妍，小春時節又經年。',32,'全唐诗/poet.song.88000.json','["江上南枝暖欲妍，小春時節又經年。", "誰知一點還鄉夢，直到梅花樹子邊。"]'),
('93880b68-647a-42a1-a77b-61a28b459dc7','次韻季共蓬齋新梅','周紫芝','宋','宋诗','song-poetry','','[]','王郎巧催花，妙語起槁枯。',192,'全唐诗/poet.song.88000.json','["王郎巧催花，妙語起槁枯。", "譬如返魂香，能使死者蘇。", "詩成花亦開，小草時卷舒。", "頗如風前柳，勝韻花中無。", "蓬齋姑射仙，不待折簡呼。", "芳姿倚醉玉，未用須人扶。", "自君作周旋，此德良不孤。", "移根始山中，一笑煩王都。", "坐令桃李花，淺俗皆凡夫。", "棐几滑以净，雲窗窈而虛。", "釅白奪寒雪，軟紅空九衢。", "我久離山中，問花今何如。", "殷勤培弱榦，何日課獠奴。", "於花苟得計，於我亦何愚。", "此意倘復遂，瘦地良可鋤。", "誦君種花句，撫卷長嗟吁。"]'),
('6111c3fd-246f-4f6a-976d-091243996331','聞朱虛真請老二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','平生恨未識朱游，毎得清詩慰客愁。',32,'全唐诗/poet.song.88000.json','["平生恨未識朱游，毎得清詩慰客愁。", "泛宅清苕真得句，掛冠神武更何求。"]'),
('2432b0e5-a2e8-4700-b069-58b33367b863','聞朱虛真請老二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','久厭朱袍裹玉仙，幅巾藜杖老山間。',32,'全唐诗/poet.song.88000.json','["久厭朱袍裹玉仙，幅巾藜杖老山間。", "從今魚鳥緣應熟，只恐鴛鴦債未還。"]'),
('cc04e8e5-e2d2-4b12-8212-27f01cdff3ff','次韻范元卿題友山堂','周紫芝','宋','宋诗','song-poetry','','[]','人間南北無同異，四海蒼生俱一世。',160,'全唐诗/poet.song.88000.json','["人間南北無同異，四海蒼生俱一世。", "借令賣友取封侯，一擲成盧亦兒戲。", "東平風度人所難，不將白眼看青山。", "少年結客知無益，老喚南山相與閑。", "人情自是有新故，相好乃能保朝暮。", "故人落井已下石，紅袖彈筝未移柱。", "玉巒排秀天清明，亂峰入眼心先傾。", "向來刎頸或蹀血，此地一笑終忘形。", "平生愛山心願見，喜色津津應滿面。", "寧愁偃蹇不受招，一鶚孤飛誰可見。"]'),
('e65ac2c0-7280-4314-81db-d1f338fb466d','無住庵主爲余寫真報之以詩','周紫芝','宋','宋诗','song-poetry','','[]','驊騮固絕足，韓幹真畫者。',120,'全唐诗/poet.song.88000.json','["驊騮固絕足，韓幹真畫者。", "儻欲萬口傳，當畫千里馬。", "吾才如跛鱉，子不觧騰跨。", "初無籋雲姿，何勞人摹寫。", "支郎妙人物，名聲遍日下。", "事苟不當急，操筆有用捨。", "一逢菘韭翁，終安陋樸野。", "無鹽元自醜，强欲相紛赭。", "至技不可名，厚意徒久假。", "我欲報之詩，有作非大雅。"]'),
('26c44ba3-dc5c-47fd-8c3b-0dc83424f2ca','孤山之顛舊有開氏四照閣次年部使者獻西湖圖神廟閲圖久之問開氏四照閣安在部使者失對其知名如此昨跋馬過下山見赭衣荷鍤數百人問之則軍中藏冰於此也','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','出頭傑閣想峥嶸，當日佳名達裕陵。',32,'全唐诗/poet.song.88000.json','["出頭傑閣想峥嶸，當日佳名達裕陵。", "豈料生存華屋處，將軍於此窖寒冰。"]'),
('aec8d9ee-d676-44dc-9ef9-155b5b5fda93','次韻相之見過口占雪中新句且許約季共携山谷書伯時畫過敝廬','周紫芝','宋','宋诗','song-poetry','','[]','寒欺玉樹雪横斜，遙想諸郎擬玉華。',64,'全唐诗/poet.song.88000.json','["寒欺玉樹雪横斜，遙想諸郎擬玉華。", "更借蟾蜍千里月，細看薝蔔一林花。", "公名已在曹劉上，我輩裁堪屈宋衙。", "聞道高軒開二妙，竹坡猶有雪煎茶。"]'),
('a6be752d-e5de-49c4-a47c-0763363d8c3b','次韻季共和相之前作二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','誰從玉闕蓬萊殿，吹下仙人蕚綠華。',64,'全唐诗/poet.song.88000.json','["誰從玉闕蓬萊殿，吹下仙人蕚綠華。", "風急有時翻柳絮，月寒無數著梅花。", "時開病眼看三徑，勝着青衫趁兩衙。", "欲煮南屏山下雪，問誰能點老謙茶。"]'),
('bfab2f28-48dc-4db9-8495-db07203e9462','次韻季共和相之前作二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雪意鬖鬖整復斜，似人霜髩不勝華。',64,'全唐诗/poet.song.88000.json','["雪意鬖鬖整復斜，似人霜髩不勝華。", "只今瘦骨欹風帽，空憶寒江釣浪花。", "妙舞正看回激楚，兩峰旋欲戰彭衙。", "不將鹽絮輕相比，似我南窗玉色茶。"]'),
('424b29f0-d79a-4632-b4f3-bb5a2971121c','寄題強常州烏墩新作濯纓亭二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','使君如冰壺，不受古俗塵。',48,'全唐诗/poet.song.88000.json','["使君如冰壺，不受古俗塵。", "何爲觧豸冠，濯髪天地津。", "開門納滄波，自與雲水親。", "知誰分清流，照此千載人。"]'),
('8716b072-166a-4e51-a8ae-e89c53121b84','寄題強常州烏墩新作濯纓亭二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','濯纓須滄浪，彈冠必新沐。',48,'全唐诗/poet.song.88000.json','["濯纓須滄浪，彈冠必新沐。", "昏昏不可受，皓皓亦易辱。", "借令困一塵，未易涴冰玉。", "勿從漁父談，恐自成窘束。"]'),
('01be30f6-8d65-4fa0-a677-cebafdfb4292','送孫求仁官黄岡','周紫芝','宋','宋诗','song-poetry','','[]','黄岡古淮邦，其大不如斗。',180,'全唐诗/poet.song.88000.json','["黄岡古淮邦，其大不如斗。", "誰知隔岸山，萬馬日奔走。", "有數着詩人，此地實林藪。", "頃來當盛年，王公號賢守。", "三年江上杯，快飲竹樓酒。", "東坡營雪堂，始種坡前柳。", "至今有遺跡，過者爲回首。", "後來老門生，詞翰玉堂手。", "謫官茅三間，門巷無鷄狗。", "孫郎飽文藝，貧病亦已久。", "着履知有土，捉衿乃見肘。", "抱經官殘州，一飽亦難偶。", "論文有餘日，爲我訪白叟。", "遺事倘可書，尚足寄衰朽。", "慎勿止寒温，作書問安否。"]'),
('d0c790f9-2ba6-4d10-983a-6132e95b2c24','謝吳司户寄舂陵四石  其一','周紫芝','宋','宋诗','song-poetry','','[]','何年山嶄巖，化作龍起伏。',24,'全唐诗/poet.song.88000.json','["何年山嶄巖，化作龍起伏。", "安得挽天河，著龍吐飛瀑。"]'),
('f138e56d-2a6d-449b-a14a-3ffcc90701b0','謝吳司户寄舂陵四石  其二','周紫芝','宋','宋诗','song-poetry','','[]','往穴城南窗，分山得遙碧。',24,'全唐诗/poet.song.88000.json','["往穴城南窗，分山得遙碧。", "誰持列玉峰，來照蝸牛席。"]'),
('adb09bf3-a592-46e9-b1c3-da24b417e092','謝吳司户寄舂陵四石  其三','周紫芝','宋','宋诗','song-poetry','','[]','吳山非不佳，故山終眼明。',24,'全唐诗/poet.song.88000.json','["吳山非不佳，故山終眼明。", "南來一拳石，似我小峥嶸。"]'),
('18638f43-51ec-4f65-945a-3871e325a5c8','謝吳司户寄舂陵四石  其四','周紫芝','宋','宋诗','song-poetry','','[]','孤峰真崛奇，凝目見太古。',24,'全唐诗/poet.song.88000.json','["孤峰真崛奇，凝目見太古。", "便悲江上山，培塿不足數。"]'),
('3a66d1c7-0579-4af4-bf75-52f7c6bcd67a','次韻季共蓬齋夜坐三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','幽人懷故鄉，夜坐聽秋雨。',72,'全唐诗/poet.song.88000.json','["幽人懷故鄉，夜坐聽秋雨。", "耿耿不成寐，悽悽亦良苦。", "酒白應自斟，茶甘爲誰煮。", "喜意入寒燈，詩成看花吐。", "樂饑焰短檠，玉蟲綴釵股。", "當亦念衰翁，秋風臥何許。"]'),
('99dadb26-0b25-4da1-b0c4-bdd210a0bc09','次韻季共蓬齋夜坐三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','寒齋秋意高，夜久羣籟息。',72,'全唐诗/poet.song.88000.json','["寒齋秋意高，夜久羣籟息。", "眼前無一塵，誰與共此席。", "平生樂虛曠，頗怪言不食。", "遙知高世意，仰面看屋脊。", "秋蟲曾何知，悲鳴亂胸臆。", "君亦意不眠，佳月良可惜。"]'),
('728532cc-312c-42e9-81a0-209ae2a11f5a','次韻季共蓬齋夜坐三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','露井飛彫梧，碧月借秋色。',72,'全唐诗/poet.song.88000.json','["露井飛彫梧，碧月借秋色。", "頗聞遭鼠輩，惱睡成反側。", "君豈劾鼠手，姑緩藁街磔。", "我亦見事慣，流年反多歷。", "誰能與此物，更較勝負敵。", "一笑謂狸奴，無乃爾不職。"]'),
('9e4c6589-7b78-425c-a196-8b9f749f19c2','讀韋莊浣花集戲題二詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','春風吹縐一池波，付與蛾眉席上歌。',32,'全唐诗/poet.song.88000.json','["春風吹縐一池波，付與蛾眉席上歌。", "試倩韋郎追正始，風流猶不似元和。"]'),
('9cd1e496-2f6c-425f-b9f5-41e6d2537930','讀韋莊浣花集戲題二詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','晚唐風月一番新，弄粉調膏點注勻。',32,'全唐诗/poet.song.88000.json','["晚唐風月一番新，弄粉調膏點注勻。", "誰與花材詩宰相，聘將花蘂作夫人。"]'),
('b215482a-b319-4453-8a56-725ea7fab963','相之季共各携李伯時畫軸見過分韻得人字','周紫芝','宋','宋诗','song-poetry','','[]','人生不相知，白頭反如新。',252,'全唐诗/poet.song.88000.json','["人生不相知，白頭反如新。", "知心不在久，覿面還成親。", "况我五安師，二妙俱可人。", "元龍百尺樓，人物誰與鄰。", "風流小安豐，玉樹高嶙峋。", "聯翩兩竹輿，訪我南坡春。", "遂遣小叔雅，娛此照坐賓。", "王春三月雨，浸浸如遊塵。", "是日天爲喜，霽色明清晨。", "各携古錦囊，共出畫苑珍。", "太邱重千載，高標澹風神。", "丹鉛表丘壑，制度殊冠巾。", "淵明擷秋菊，醉面玉色勻。", "龍眠賦遠遊，濯髪天池濱。", "二老不並世，異世真同論。", "當年天廄馬，調御皆服馴。", "絕域來象龍，地行俱麒麟。", "老眼閲神駿，摩挲得逡巡。", "客意亦復悦，領我杯中醇。", "尚苦江夏帖，入我幽夢頻。", "倒篋倘有意，叩門君勿嗔。"]'),
('753693d7-559d-4192-b495-afae211a05e7','文若自華亭携家來遊西湖袖出新詩其歸乃和前篇聊以當别','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄郎滿袖出新詩，别後篇章欲造微。',64,'全唐诗/poet.song.88000.json','["黄郎滿袖出新詩，别後篇章欲造微。", "老驥但含千里意，翔鸞還带九雛歸。", "如君好事真前輩，笑我爲生盡昨非。", "小别不堪頻作惡，灞橋楊柳亦依依。"]'),
('2b35a01f-7f5b-4a99-bd7e-bc354304151e','次韻林察院賀章正言得子','周紫芝','宋','宋诗','song-poetry','','[]','海中仙果著新枝，可是香山得子遲。',64,'全唐诗/poet.song.88000.json','["海中仙果著新枝，可是香山得子遲。", "雛鳯遠從丹穴至，神駒初出渥洼時。", "平生種德無遺恨，他日傳家有是兒。", "聞道長庚曾入夢，已應能作上樓詩。"]'),
('e3220178-7200-49e5-b6d7-3bdd34e785a0','全一道人分以石芝味極平淡咀留牙頰間良久乃甘而世罕有識者或云九華山中亦有之二首  其一','周紫芝','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','淡中得味世誰知，晚歲因君識石芝。',32,'全唐诗/poet.song.88000.json','["淡中得味世誰知，晚歲因君識石芝。", "甘蔗何曾有佳境，人間只好誑癡兒。"]'),
('1b7effa9-1774-4692-adff-9b33f865271c','全一道人分以石芝味極平淡咀留牙頰間良久乃甘而世罕有識者或云九華山中亦有之二首  其二','周紫芝','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','自聞青壁是芝田，心到蓮峰最上巔。',32,'全唐诗/poet.song.88000.json','["自聞青壁是芝田，心到蓮峰最上巔。", "且覓微甘供一笑，海中無藥觧長年。"]'),
('92c670c5-9961-4a7d-a499-5a3a7f483d4e','席間分韻送王季共得浦字','周紫芝','宋','宋诗','song-poetry','','[]','烏衣說諸王，人物世足數。',120,'全唐诗/poet.song.88000.json','["烏衣說諸王，人物世足數。", "至今有雲來，眼色照天宇。", "誰知静秀中，有志良未吐。", "時從雲夢胸，噴作秋江雨。", "中郎騎生駒，世亦號文虎。", "才高公自出，步驟真接武。", "名當在户前，意豈甘噲伍。", "三年隸工曹，一舸輔江浦。", "風流各雲散，相見定何許。", "臭味苦無多，酒行君竟舉。"]'),
('67324c00-fc19-4d14-8f52-e24b27dcb454','飛卿携去臘書見過中有詩次韻','周紫芝','宋','宋诗','song-poetry','','[]','强着玄端與沐猴，隨人作計偶乘流。',64,'全唐诗/poet.song.88000.json','["强着玄端與沐猴，隨人作計偶乘流。", "昔時來往從三徑，今日﨑嶇念一邱。", "千里回思家似夢，十年贏得髩雙秋。", "緇塵滿面君應笑，京洛相逢只自羞。"]'),
('a35b6b37-b8fa-4cdd-9f8f-ce2f28fad793','題錢少愚四畫 鴛浦','周紫芝','宋','宋诗','song-poetry','','[]','一點傷春恨，看成兩鬢霜。',24,'全唐诗/poet.song.88000.json','["一點傷春恨，看成兩鬢霜。", "如今無此夢，莫畫兩鴛鴦。"]'),
('7781431c-581f-4629-80fb-ec050d57b8b5','題錢少愚四畫 釣雪','周紫芝','宋','宋诗','song-poetry','','[]','一作東吳去，回頭又十年。',24,'全唐诗/poet.song.88000.json','["一作東吳去，回頭又十年。", "可憐江上雪，空落釣魚船。"]'),
('48c4e228-0e78-4516-8e63-0334fefc2c41','題錢少愚四畫 蘭亭','周紫芝','宋','宋诗','song-poetry','','[]','事去空千載，何曾有若人。',24,'全唐诗/poet.song.88000.json','["事去空千載，何曾有若人。", "只應煙樹裏，便是永和春。"]'),
('4f9ae6bd-5f48-41df-af37-a4d0262e407f','題錢少愚四畫 秋觀','周紫芝','宋','宋诗','song-poetry','','[]','雨足三湘岸，烟含七澤秋。',24,'全唐诗/poet.song.88000.json','["雨足三湘岸，烟含七澤秋。", "可能無尺地，分得庾郎愁。"]'),
('27e980ff-34da-449c-8f4c-d77438f60dae','隆茂宗鄙余所得蘇後湖像别爲作短軸超然有物外意','周紫芝','宋','宋诗','song-poetry','','[]','高人本難名，畫手不可俗。',132,'全唐诗/poet.song.88000.json','["高人本難名，畫手不可俗。", "世無癡虎頭，丹青涴冰玉。", "支郎唾俗畫，爲我作短軸。", "遂出三昧手，觀此真面目。", "衣冠有山林，風味到僮僕。", "悠悠跨蹇驢，眇眇出寒谷。", "薄暮殊未歸，落日下古木。", "未知適何門，敲門看修竹。", "無酒意闕然，鴟夷尚空腹。", "長鬚頗觧事，歸騎不敢趣。", "更復問前山，誰家酒堪漉。"]'),
('a6577013-4abf-42f7-9e72-b08d46151238','僕訪吕晞樸排岸方造舟翔鸞不及見後數日有詩次韻奉謝二首  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','太常何敢醉如泥，休沐相尋見亦稀。',64,'全唐诗/poet.song.88000.json','["太常何敢醉如泥，休沐相尋見亦稀。", "倦著青衫君未可，老遮烏帽我當歸。", "翔鸞寺裏停烟棹，西子湖邊看落暉。", "安得劇談同一笑，孤篷六尺去如飛。"]'),
('b7b6ebe6-4fbb-4e92-a0df-9c6de7c63046','僕訪吕晞樸排岸方造舟翔鸞不及見後數日有詩次韻奉謝二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','此生隨分本何知，人品非高論亦卑。',64,'全唐诗/poet.song.88000.json','["此生隨分本何知，人品非高論亦卑。", "早歲囊書羞賈傳，暮年學圃羡樊遲。", "江鄉老去多歸夢，樂府秋來得妙詞。", "八節上灘休入句，花姑載酒可相期。"]'),
('2da9bba4-6802-45ad-b1ce-7804aa61dd96','河魨之美唯西施乳得名舊矣而未有作詩者戲作此詩','周紫芝','宋','宋诗','song-poetry','','[]','吳王宮中半吳女，選入吳宮歌白苧。',194,'全唐诗/poet.song.88000.json','["吳王宮中半吳女，選入吳宮歌白苧。", "姑蘇臺上看西施，羞得紅粧不歌舞。", "青絲籠髻雲剪衣，玉垂雙乳膚凝脂。", "香羅對畫兩鸂鶒，半約胸酥人未知。", "邇來紅魚新入饌，西施乳入詩翁眼。", "釅白還驚春雪温，細理不知燕玉軟。", "坐中嘉名思昔人，未許八珍當禁臠。", "更將人乳作蒸豚，可笑此郎風味淺。", "不知柱下風流張相君，暮年飲乳不飲醇。", "帳中侍兒知有幾，當時西子今未聞。", "白頭自笑竹坡老，烹鮮誰餉杯中珍。", "江瑤歛袂敢争席，一尊伴我抛青春。"]'),
('e767e583-5c8b-4580-8715-808c99997978','寄秦峽州三首峽州書尾悼侍兒之亡故篇末及之  其一','周紫芝','宋','宋诗','song-poetry','','[]','當年淮水未歸時，紫塞天塵玉座知。',32,'全唐诗/poet.song.88000.json','["當年淮水未歸時，紫塞天塵玉座知。", "今日臨邊須老子，莫辭萬里擁雙麾。"]'),
('eeba8223-546b-408c-abf4-8fc8dba96ace','寄秦峽州三首峽州書尾悼侍兒之亡故篇末及之  其二','周紫芝','宋','宋诗','song-poetry','','[]','峽城真在楚雲間，聞說豐年訟亦閑。',32,'全唐诗/poet.song.88000.json','["峽城真在楚雲間，聞說豐年訟亦閑。", "獠洞無兵秋日永，滿傾醽醁看青山。"]'),
('60daf37c-1545-4a1b-81bd-7e356c9d1266','寄秦峽州三首峽州書尾悼侍兒之亡故篇末及之  其三','周紫芝','宋','宋诗','song-poetry','','[]','斷雲飛在舊陽臺，無復襄王夢裏來。',32,'全唐诗/poet.song.88000.json','["斷雲飛在舊陽臺，無復襄王夢裏來。", "十二峰前何處是，郡楼凝望想徘徊。"]'),
('6afbcff1-9e77-4160-bbe5-5f2decd9f939','吳中舟行口號七首  其一','周紫芝','宋','宋诗','song-poetry','','[]','白頭人自日邊來，澤國風帆破浪開。',32,'全唐诗/poet.song.88000.json','["白頭人自日邊來，澤國風帆破浪開。", "已近玉樓船又去，却回愁眼望蓬萊。"]'),
('e5f6a635-0dfe-41b6-80d4-910ee55eb6a0','吳中舟行口號七首  其二','周紫芝','宋','宋诗','song-poetry','','[]','雨入青秧水滿川，吳儂相對話豐年。',32,'全唐诗/poet.song.88000.json','["雨入青秧水滿川，吳儂相對話豐年。", "時人盡說吳中好，看我蘇常買薄田。"]'),
('4677bcca-275c-4df1-a3d5-3b8d7c9dc2fe','吳中舟行口號七首  其三','周紫芝','宋','宋诗','song-poetry','','[]','西來蕃使換氈裘，渡海風帆入帝州。',32,'全唐诗/poet.song.88000.json','["西來蕃使換氈裘，渡海風帆入帝州。", "醉裏宮花紅壓帽，千年今日記千秋。"]'),
('6a1bc178-bc68-4e03-997e-bbf8e2ec6d02','吳中舟行口號七首  其四','周紫芝','宋','宋诗','song-poetry','','[]','當年戈甲過垂虹，聞說樓船照水紅。',32,'全唐诗/poet.song.88000.json','["當年戈甲過垂虹，聞說樓船照水紅。", "賊去烟波已如鏡，却還風月與漁翁。"]'),
('0f391290-3293-469c-a07f-47f8f80c89e5','吳中舟行口號七首  其五','周紫芝','宋','宋诗','song-poetry','','[]','昔年誰此試青萍，很石中分劍氣精。',32,'全唐诗/poet.song.88000.json','["昔年誰此試青萍，很石中分劍氣精。", "光熖未消劉項起，始知不殺是神兵。"]'),
('39e480a9-3bfb-4a73-9381-61556ab195e7','吳中舟行口號七首  其六','周紫芝','宋','宋诗','song-poetry','','[]','久陪三館瀛洲客，屢拜蒼龍宰府茶。',32,'全唐诗/poet.song.88000.json','["久陪三館瀛洲客，屢拜蒼龍宰府茶。", "更覓惠山烹雪乳，餘甘歸與故人誇。"]'),
('9dbaf396-9556-44f4-a7d1-2461886d5570','吳中舟行口號七首  其七','周紫芝','宋','宋诗','song-poetry','','[]','水從吳尾入湖流，身到江南第二州。',32,'全唐诗/poet.song.88000.json','["水從吳尾入湖流，身到江南第二州。", "故國舊交應笑我，十年飛雪上人頭。"]'),
('493d824c-bb25-4e21-bdbd-9dcdf4a5db3b','海昌舟中雨過晚凉二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','白板艅艎鐡裹頭，吳歌聲在藕花洲。',32,'全唐诗/poet.song.88000.json','["白板艅艎鐡裹頭，吳歌聲在藕花洲。", "故來急雨歸何處，和月吹凉入柂樓。"]'),
('1ae293ec-41d4-473a-bbc0-2ef2154df3ff','海昌舟中雨過晚凉二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','臥隨鶴鷺入荷香，笑却蒲葵借晚凉。',32,'全唐诗/poet.song.88000.json','["臥隨鶴鷺入荷香，笑却蒲葵借晚凉。", "凍雨釀雲遮薄日，小舟添水送歸航。"]'),
('66700a16-767f-4bc7-9941-08641f4969f4','曉發吳江晚上姑蘇臺','周紫芝','宋','宋诗','song-poetry','','["\u592a\u6e56"]','掛帆早拍雲濤堆，落帆暮上姑蘇臺。',64,'全唐诗/poet.song.88000.json','["掛帆早拍雲濤堆，落帆暮上姑蘇臺。", "天沉海嶠鳥飛去，雨入太湖雲不來。", "西施白苧豈復唱，吳王故苑俱成灰。", "誰能與子論許事，倚欄共聽漁歌回。"]'),
('176fbba3-f85b-4993-9761-77c4645ccadd','登垂虹亭','周紫芝','宋','宋诗','song-poetry','','[]','雲水蒼茫共渺然，眼看飛鳥没蒼烟。',64,'全唐诗/poet.song.88000.json','["雲水蒼茫共渺然，眼看飛鳥没蒼烟。", "山圍百雉吳王國，風急千帆震澤船。", "白髪飄流身已老，斷編零落事空傳。", "誰將無色胸中畫，貌取吳中萬頃天。"]'),
('ff1ad88a-7f22-46ed-b033-df2d5622e7c3','惠山泉二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','石龍噴雪繞山斜，桑苧祠間一幅紗。',32,'全唐诗/poet.song.88000.json','["石龍噴雪繞山斜，桑苧祠間一幅紗。", "只對清流已無暑，未論絕品觧宜茶。"]'),
('2a5f10ac-370d-46ee-b645-39ddfd7f8a2a','惠山泉二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','山僧知我去匆匆，旋印紅泥乞老翁。',32,'全唐诗/poet.song.88000.json','["山僧知我去匆匆，旋印紅泥乞老翁。", "擬喚人間三昧手，共分天上小團龍。"]'),
('5e35713b-47cb-4bff-b122-e67ce4c0a6f4','僕歸自武林蒙舒元相徐美祖諸君皆惠詩乍歸老倦未蘇姑以二詩爲報聊以塞後時之責耳  其一','周紫芝','宋','宋诗','song-poetry','','[]','紅塵染盡去時衣，愁入雙蓬鬢髪稀。',64,'全唐诗/poet.song.88000.json','["紅塵染盡去時衣，愁入雙蓬鬢髪稀。", "故國幾番隨夢到，長安十度送春歸。", "懶看烏帽朝訶馬，却憶黄紬晝掩扉。", "鳥倦知還我已老，會令雙鵠貼雲飛。"]'),
('d3ea44cf-ee18-4554-a23a-ce67ecb5f975','僕歸自武林蒙舒元相徐美祖諸君皆惠詩乍歸老倦未蘇姑以二詩爲報聊以塞後時之責耳  其二','周紫芝','宋','宋诗','song-poetry','','[]','相國風流元有種，徐卿裙屐固應稀。',64,'全唐诗/poet.song.88000.json','["相國風流元有種，徐卿裙屐固應稀。", "青衫好着君猶未，黄髪無多我合歸。", "清夢曉聽湖上雨，暮年猶借水邊扉。", "南來未是安巢鳥，擬趁西風著處飛。"]'),
('4921da14-040a-475c-9f76-a2577dd3acb7','王元東寄長篇病中未能和韻先寄此詩爲謝','周紫芝','宋','宋诗','song-poetry','','[]','白璧嘗遭按劍疑，古來投分要相知。',64,'全唐诗/poet.song.88000.json','["白璧嘗遭按劍疑，古來投分要相知。", "驚人未有平生句，絕妙空貽幼婦詞。", "我亦去爲廬阜客，君應多寄輞川詩。", "來書更覺寛陳債，八節灘頭上水時。"]'),
('a9c3fc66-5bbc-4a23-871e-4b8cd1f18a25','次韻元相閲猥藁見贈二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','無物能娛老，冥搜興漫長。',48,'全唐诗/poet.song.88000.json','["無物能娛老，冥搜興漫長。", "數莖空撚頷，一瓣與誰香。", "歲月搖雙鬢，鶯花惱客腸。", "更哦秋士句，聊與伴啼螿。"]'),
('5fb2301a-685d-416b-ba95-949e0638cb09','次韻元相閲猥藁見贈二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','挽得非來句，頻哦送夜長。',48,'全唐诗/poet.song.88000.json','["挽得非來句，頻哦送夜長。", "詩今逼何遜，人亦似黄香。", "擬答琅玕贈，慚無錦繡腸。", "秋風又撩客，啾唧動寒螿。"]'),
('c5f5cd05-441f-468b-94df-50cbe84ab808','次韻美祖用元相韻以廣后山之意讀之汗下愧不自勝  其一','周紫芝','宋','宋诗','song-poetry','','[]','晉魏分騷雅，詩流本日長。',48,'全唐诗/poet.song.88000.json','["晉魏分騷雅，詩流本日長。", "應傳少陵鉢，莫炷老僧香。", "俗眼無涇渭，從誰話肺腸。", "感君韶濩耳，來聽菊籬螿。"]'),
('3c1ff517-79a6-419c-aea5-9e7f9ee5811e','次韻美祖用元相韻以廣后山之意讀之汗下愧不自勝  其二','周紫芝','宋','宋诗','song-poetry','','[]','白璧光元在，青雲路亦長。',48,'全唐诗/poet.song.88000.json','["白璧光元在，青雲路亦長。", "海天從逐臭，郎署會含香。", "唾玉分新句，澆愁浣俗腸。", "從今秋夜枕，霧草厭聞螿。"]'),
('302c0640-3804-40a2-b175-87544615fe38','謁梅公墓','周紫芝','宋','宋诗','song-poetry','','[]','當年蠻錦織梅花，此日蒼藤立暝鴉。',64,'全唐诗/poet.song.88000.json','["當年蠻錦織梅花，此日蒼藤立暝鴉。", "白水碑殘猶結客，潁州兵亂已無家。", "何年有客常留劍，舉世知誰可押衙。", "我一舉杯澆馬鬛，更從底處問侯芭。"]'),
('52419a20-e1d3-48ce-9c4e-fbb9edbdba77','次韻飛卿二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','赦黄新拜日邊書，畫舸行游雨外湖。',64,'全唐诗/poet.song.88000.json','["赦黄新拜日邊書，畫舸行游雨外湖。", "粗有微官如漫叟，苦無高論似王符。", "江邊孤壘應千里，天上神州夢九衢。", "物外故人今遠别，固應憐我不同塗。"]'),
('61364e78-e5e1-47fa-b266-38f0a64e3acc','次韻飛卿二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','聞道州閑可讀書，綠荷朱閣繞平湖。',64,'全唐诗/poet.song.88000.json','["聞道州閑可讀書，綠荷朱閣繞平湖。", "慚非萬里青雲器，未稱中興赤伏符。", "來暮不應歌叔度，久窮聊免哭唐衢。", "君當别我休辭醉，我亦匆匆恐問塗。"]'),
('f2549b3e-4660-43b2-94e3-52fc6e4f79c1','將赴興國别同社五君子','周紫芝','宋','宋诗','song-poetry','','[]','欲傾杯酒話平生，又觧孤舟作曉行。',64,'全唐诗/poet.song.88000.json','["欲傾杯酒話平生，又觧孤舟作曉行。", "有友五人那忍别，去家三歲若爲情。", "一時但恐無耆舊，四海誰言有弟兄。", "歸路若隨清夢到，江南雖遠不多程。"]'),
('0f9b7844-3083-4da9-999c-ad60c02934d1','宿能仁作','周紫芝','宋','宋诗','song-poetry','','[]','吳帆送我作東歸，雙玉重新見兩溪。',32,'全唐诗/poet.song.88000.json','["吳帆送我作東歸，雙玉重新見兩溪。", "脚踏故鄉猶未穩，仍携十品過江西。"]'),
('3bb9f24f-50c7-4e03-9630-6c172c16fc4a','僕將有江西之役證公老師自龍谿來訪僕於家已而遂至春谷送别二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','兩翁投老各華顛，往事重論亦黯然。',32,'全唐诗/poet.song.88000.json','["兩翁投老各華顛，往事重論亦黯然。", "只有高情無歲月，相看依舊似當年。"]'),
('2704ca23-2dea-4f36-b556-963b8200cab5','僕將有江西之役證公老師自龍谿來訪僕於家已而遂至春谷送别二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','羸驂相逐犯風埃，行盡千巖未肯回。',32,'全唐诗/poet.song.88000.json','["羸驂相逐犯風埃，行盡千巖未肯回。", "送我漳淮三百里，道人何止過谿來。"]'),
('e9cb8adb-ae38-47b4-bae2-cf899b39d1ad','過九華作','周紫芝','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','隔路仙凡欲問津，馬頭空厭没黄塵。',32,'全唐诗/poet.song.88000.json','["隔路仙凡欲問津，馬頭空厭没黄塵。", "傷心不到牛欄港，九子山應觧笑人。"]'),
('3c5eca3b-3997-4d85-81a1-2015ca3e9bbb','梅聖俞嘗爲建德尉僕過是邑詢之果然且言今有梅公堂在焉','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','百年遺像鎖寒廳，氣壓長江賈尉輕。',64,'全唐诗/poet.song.88000.json','["百年遺像鎖寒廳，氣壓長江賈尉輕。", "誰道都官能作讖，固應梅福自知名。", "人猶能說當時事，詩亦懸知早歲成。", "泉下玉山呼不起，可憐華屋漫峥嶸。"]'),
('5a645700-98a3-4c54-a877-f184986032c4','夜宿堯城寒甚明日山中有薄雪馬上賦二詩  其一','周紫芝','宋','宋诗','song-poetry','','[]','剪水飛花點翠巒，未教全放玉孱顔。',32,'全唐诗/poet.song.88000.json','["剪水飛花點翠巒，未教全放玉孱顔。", "分明六曲屏風樣，和雪新描著色山。"]'),
('9d2d943e-2a57-428b-a631-697525401747','夜宿堯城寒甚明日山中有薄雪馬上賦二詩  其二','周紫芝','宋','宋诗','song-poetry','','[]','雲意悠悠晚尚堅，玉塵猶未破清寒。',32,'全唐诗/poet.song.88000.json','["雲意悠悠晚尚堅，玉塵猶未破清寒。", "不知誰把千巖雪，付與詩翁馬上看。"]'),
('f360e568-f997-4b2a-b193-3e35aa275fde','梅山宗老惠近詩明日自山中來訪余堯城驛二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','梅山寄我近來詩，便恐諸郎氣盡低。',32,'全唐诗/poet.song.88000.json','["梅山寄我近來詩，便恐諸郎氣盡低。", "雙井派中真法嗣，莫將輕比順闍黎。"]'),
('af35317e-fdb8-41ca-bf2d-3619dedcfd2e','梅山宗老惠近詩明日自山中來訪余堯城驛二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','參得詩中句外禪，頗知經歲杜禪關。',32,'全唐诗/poet.song.88000.json','["參得詩中句外禪，頗知經歲杜禪關。", "要須覿面親分付，不免煩君一下山。"]'),
('2134f7ae-908e-4b8d-8d67-f4463ac526a0','過狄梁公墓','周紫芝','宋','宋诗','song-poetry','','[]','高后王諸吕，漢鼎幾半傾。',180,'全唐诗/poet.song.88000.json','["高后王諸吕，漢鼎幾半傾。", "絳侯入北軍，有意誅鯢鯨。", "兵纒未央殿，血濺長安城。", "祿輩僅誅滅，四海殊雷驚。", "唐家女主禍，未可方西京。", "艾猳剪宗枝，賊計殊未成。", "三思本么麽，白面不足黥。", "舉朝無直節，但畏羅織刑。", "梁公挾大計，赤手無寸兵。", "爲言不祔姑，禍止談笑平。", "功比漢諸人，優劣不用評。", "事苟以理勝，口舌亦可爭。", "師曲舉必敗，勢力未易憑。", "老婦雖至愚，理在見自明。", "不然此危邦，詎可一言興。"]'),
('cdde2da4-a6fe-4a5b-b414-b7d55c2d03ed','琵琶亭二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','舊事無人作短行，湓江空自繞湓城。',32,'全唐诗/poet.song.88000.json','["舊事無人作短行，湓江空自繞湓城。", "黄蘆苦竹依然在，猶替琵琶作怨聲。"]'),
('cf35e461-7268-4ecc-91f4-0d367dbf9c62','琵琶亭二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','捍撥難傳不盡情，琵聲裁盡繼琶聲。',32,'全唐诗/poet.song.88000.json','["捍撥難傳不盡情，琵聲裁盡繼琶聲。", "風流掃地無人說，只有空江舊月明。"]'),
('d1423e47-5675-43ae-86ae-8a88f4d7626f','陪李使君登庾樓是日雲霧不見淮山二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','跨江雲夢不勝寛，樓在江聲洶涌間。',32,'全唐诗/poet.song.88000.json','["跨江雲夢不勝寛，樓在江聲洶涌間。", "試看坐中尋得句，說君眼力盡時山。"]'),
('d6d4ebe8-7bc7-4231-9dba-ff7fa0219cfd','陪李使君登庾樓是日雲霧不見淮山二首  其二','周紫芝','宋','宋诗','song-poetry','','["\u8861\u5c71"]','樓前江水看鎔銀，江外淮山色未分。',32,'全唐诗/poet.song.88000.json','["樓前江水看鎔銀，江外淮山色未分。", "安得長驅鱷魚手，爲開南嶽嶺頭雲。"]'),
('f0bef210-9328-4885-b568-08a9c0ce6f08','九江趙倅新作環季亭','周紫芝','宋','宋诗','song-poetry','','[]','小攜樽酒作清游，尋得方壺最上頭。',64,'全唐诗/poet.song.88000.json','["小攜樽酒作清游，尋得方壺最上頭。", "山在斷霞明處碧，江從白鳥去邊流。", "苦無健句爭天巧，賴有新亭慰客愁。", "他日東南論勝地，未應只数庾公樓。"]'),
('c6110a24-0c89-4018-9279-57dd3ff6f73c','題東林香山像','周紫芝','宋','宋诗','song-poetry','','[]','大唐受歷三百年，文士輩出俱可傳。',144,'全唐诗/poet.song.88000.json','["大唐受歷三百年，文士輩出俱可傳。", "情雖嫵媚中骨鯁，當時只有香山賢。", "香山年少謫湓浦，臥聽琵琶心獨苦。", "想得回舟夜半時，半濕青衫淚如雨。", "别來江月幾番圓，黄蘆苦竹空淒然。", "風流掃地那復有，但見東風吹白髯。", "可憐畫手無前輩，欲倩虎頭呼不起。", "瓊枝玉樹了無蹤，鐵撥鵾絃何用爾。", "明朝一舸下潯陽，月明依舊空江水。"]'),
('bb0c0860-1052-4675-ae0d-1d998a740e46','借書','周紫芝','宋','宋诗','song-poetry','','[]','牢落偏州少士夫，一鴟求借是書無。',32,'全唐诗/poet.song.88000.json','["牢落偏州少士夫，一鴟求借是書無。", "道山堂外長廊下，黄卷如雲記石渠。"]'),
('0b236edb-2114-45da-bc5c-881004813d08','課吏抄書戲作','周紫芝','宋','宋诗','song-poetry','','[]','雪花飛上白髭鬚，繭紙猶抄細字書。',32,'全唐诗/poet.song.88000.json','["雪花飛上白髭鬚，繭紙猶抄細字書。", "莫笑老翁兒戲子，政緣長日要銷除。"]'),
('73bcfe35-888f-4b7c-9021-e94a3bb83da9','湖亭懷舊三絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','鈴索無聲訟牒空，妙香寮外水冥濛。',32,'全唐诗/poet.song.88000.json','["鈴索無聲訟牒空，妙香寮外水冥濛。", "長安故舊如相問，今在江西道院中。"]'),
('8ef9fb5b-f63c-4ecc-b4d6-c437392842e3','湖亭懷舊三絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','校書天祿想諸郎，應在蓬山語晝長。',32,'全唐诗/poet.song.88000.json','["校書天祿想諸郎，應在蓬山語晝長。", "記得去年秋七月，日斜香轉曝書廊。"]'),
('7954fd8b-12a7-4710-acc0-f589cd042b2f','湖亭懷舊三絕  其三','周紫芝','宋','宋诗','song-poetry','','[]','白頭武部最風流，便是汝南陳太邱。',32,'全唐诗/poet.song.88000.json','["白頭武部最風流，便是汝南陳太邱。", "折角烏巾人似畫，與誰同伴兩山游。"]'),
('03b24f95-095b-43a0-a2da-f29fea4f58f0','沈季卿出元具茨王相山詩卷相示兩翁雖存没異途而均爲不偶讀之良增慨歎爲題軸尾','周紫芝','宋','宋诗','song-poetry','','[]','沈郎带减不勝衣，瘦甚由來政坐詩。',64,'全唐诗/poet.song.88000.json','["沈郎带减不勝衣，瘦甚由來政坐詩。", "試數交游盡前輩，便知文采照當時。", "子猷何處尋脩竹，漫叟今誰弔舊祠。", "人似浮雲忽吹散，老夫雖健鬢成絲。"]'),
('f5ace03a-cd27-41fa-877a-ee7e5a88fa13','寄題陳醫安樂堂  其一','周紫芝','宋','宋诗','song-poetry','','[]','六塵欲要淨三摩，辛苦修行奈老何。',32,'全唐诗/poet.song.88000.json','["六塵欲要淨三摩，辛苦修行奈老何。", "只得四休安樂法，一身受用已爲多。"]'),
('74ce025d-6c75-4551-9b41-271e438d1760','寄題陳醫安樂堂  其二','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','自笑區區老倦游，廬山今是我莵裘。',32,'全唐诗/poet.song.88000.json','["自笑區區老倦游，廬山今是我莵裘。", "暮年欲覓安心法，他日敲門問四休。"]'),
('185f183e-fa21-47aa-9489-94f54f02fc10','送陳鄂州','周紫芝','宋','宋诗','song-poetry','','[]','舊識君家小仲容，步兵今復此相同。',64,'全唐诗/poet.song.88000.json','["舊識君家小仲容，步兵今復此相同。", "誰教楚楚青雲器，來照鬖鬖白雪翁。", "廬阜故山休入望，武昌官柳正搖風。", "只應黄霸歸朝日，已在天邊尺一中。"]'),
('56c98a83-9fa1-45c7-9895-9152368770ed','窗明','周紫芝','宋','宋诗','song-poetry','','[]','窗明有斜日，几靜無一塵。',24,'全唐诗/poet.song.88000.json','["窗明有斜日，几靜無一塵。", "向後有餘恨，亂鴉來聒人。"]'),
('b7e6639b-7647-4695-9bd1-d852ac3830c8','病起步至湖亭三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','雨從今日十分晴，病後春應一倍增。',32,'全唐诗/poet.song.88000.json','["雨從今日十分晴，病後春應一倍增。", "著地已無殘歲雪，掛簷猶有上元燈。"]'),
('b6265894-d349-4667-8888-db2f9167c4e5','病起步至湖亭三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','薄羅初欲換單衣，社肉裁分燕又歸。',32,'全唐诗/poet.song.88000.json','["薄羅初欲換單衣，社肉裁分燕又歸。", "喚得春來却催去，滿庭紅雨杏花飛。"]'),
('891d9df4-821b-4d20-9c03-bfb54178c35b','病起步至湖亭三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','病餘猶著杖藜扶，臨水依然一老夫。',32,'全唐诗/poet.song.88000.json','["病餘猶著杖藜扶，臨水依然一老夫。", "不用苦燒紅蠟燭，桃花解笑白髭鬚。"]'),
('f61dc48d-3528-4a6c-9443-493cae77b9c4','弔梅二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','飛盡江南泣雨枝，韻高猶共雨相宜。',32,'全唐诗/poet.song.88000.json','["飛盡江南泣雨枝，韻高猶共雨相宜。", "洗粧只有唇紅在，也勝桃花好面皮。"]'),
('9d1c3dfa-fcc5-451f-865a-fb9304cffe63','弔梅二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','傷心不見玉扶疏，丹杏縹桃亦甚都。',32,'全唐诗/poet.song.88000.json','["傷心不見玉扶疏，丹杏縹桃亦甚都。", "只恐此君零落後，餘芳要自不如渠。"]'),
('7036c310-c6b4-45f2-9f7c-9296dbf05d74','春日連雨湖水大至二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','楚地春三月，他鄉客二毛。',48,'全唐诗/poet.song.88000.json','["楚地春三月，他鄉客二毛。", "愁懷須著酒，寒力尚欺袍。", "細雨淹花濕，顛風拍浪高。", "昨朝紅藥柱，今日整漁舠。"]'),
('ae9becc5-51a3-4f2f-85f7-e0988e58154c','春日連雨湖水大至二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','白雨鳴珠琲，春江灌玉壺。',48,'全唐诗/poet.song.88000.json','["白雨鳴珠琲，春江灌玉壺。", "漫郎回小艇，摩詰畫新圖。", "山近醒愁眼，州閑養病軀。", "如何樽酒地，更與看南湖。"]'),
('3d61dd67-b6b2-4552-9ce1-7a8398ed8a23','秦少保生日詩三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','歲當作噩律始催，杓攜龍角星紀回。',168,'全唐诗/poet.song.88000.json','["歲當作噩律始催，杓攜龍角星紀回。", "祥雲下覆窮九垓，帝車御極雲旗排。", "夜色清潤明三台，昴精叱馭天上來。", "上帝欲遣清風埃，漢家雙闕高崔嵬。", "日趨龍尾朝蓬萊，父師有鼎調鹽梅。", "公贊廟畫衆允諧，龍顔一笑天歡咍。", "虎皮蒙甲卷不開，白玉彫爼尊有雷。", "五風十雨無煙霾，爟火夜上通天臺。", "禮成一代誰可偕，功高欲報帝所懷。", "大用永配德與才，壽廟祝之言可該，拍肩俱願齊洪崖。"]'),
('bec1d63b-e7fa-45e5-a114-94755c32829c','秦少保生日詩三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','跨鼇昔上環州山，恍如夢見非人間。',136,'全唐诗/poet.song.88000.json','["跨鼇昔上環州山，恍如夢見非人間。", "黄金作屋碧玉椽，靈芝仙草香流泉。", "琅函玉軸架插天，神龍守鑰秘不傳。", "天書錯落御墨鮮，泥金描鳯寶带纒。", "中有紫府遐齡仙，主張東壁宗衆賢。", "天風獵獵吹廣寒，霞漿酌客春晝暄。", "蘂珠琴心久精妍，靈根堅固玉鍊顔。", "三官四輔誰可遷，看公袞繡當帝前，拾塵算劫不計年。"]'),
('229aa4a7-b9d2-4679-acc7-14d1f9dd31c4','秦少保生日詩三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','右文天子朝明光，漢陛曉列千官行。',208,'全唐诗/poet.song.88000.json','["右文天子朝明光，漢陛曉列千官行。", "罷朝不歸按霓裳，黄門羣襲御殿香。", "翠蓋趣駕黄微張，日高宮樹遮回廊。", "侍臣進册儼在旁，香羅覆帕牙籖長。", "前規堯舜後三王，六維龜鑑策最良。", "聖心自約昔未堂，日有所就月有將。", "公書萬卷胸中藏，海涵地負誰可當。", "官粗住下百報忙，獨留真儒傳紫皇。", "茶甌拜賜近御床，天顔咫尺瞻龍章。", "金葉舊事不足方，人如禇馬才亦常。", "說定惟服寧可忘，設施行當見廟堂。", "可使風俗還軒黄，有時問道崆峒鄉。", "廣成之師壽百昌，千有三百歲未央。"]'),
('fb932d0a-5f54-4b6e-88ec-4545b12be7e3','二月二十三日遵奉聖詔出郊勸農謹賦詩一首示諸同寮','周紫芝','宋','宋诗','song-poetry','','[]','星言出郊坰，緩轡遵微塗。',180,'全唐诗/poet.song.88000.json','["星言出郊坰，緩轡遵微塗。", "陂池湛新綠，阡陌開上腴。", "春色嚮晼晚，農事日已趨。", "有司奉漢詔，訓辭宣帝謨。", "父老數十輩，龍鍾白髯鬚。", "扶杖前致詞，謂當極勤劬。", "曩也事格鬬，今當反田廬。", "農桑遂温飽，里胥絕征誅。", "兹焉不少力，是自貽瘠臞。", "椒漿酌大斗，起坐時歡呼。", "有如一日蜡，相期悅須臾。", "殷勤頗自愧，小信殊未孚。", "儻非獲三登，何以謝汝徒。", "同寮數君子，妙略懷永圖。", "願言規遲暮，共此豐歲娛。"]'),
('cf0d766d-b7d8-457f-a0f9-d41241cc64c9','次韻郭宰題妙香寮','周紫芝','宋','宋诗','song-poetry','','[]','香嚴參鼻觀，可受郢人斤。',156,'全唐诗/poet.song.88000.json','["香嚴參鼻觀，可受郢人斤。", "誰能論許事，且炷松爐薫。", "借此沈水力，侑我棐几文。", "小閣亦窈窕，青烟散敷紛。", "與人共婆娑，此意良殷勤。", "恨無博山賦，可寫蜀錦紋。", "老人住江東，來作江西雲。", "江湖渺歸思，先弟無餘芬。", "焚香此幽事，此外何所欣。", "如人嗜昌歜，豈復思羶葷。", "令君出新語，種學窺多聞。", "但恐燕寢句，頗慚韋使君。", "更當宿殘火，薄霧看氤氳。"]'),
('27d92a94-59f5-4c71-b40d-847a973175d1','劉德秀縣丞凢五和前篇僕亦五次其韻  其一','周紫芝','宋','宋诗','song-poetry','','[]','劉侯一諾重，勝獲金百斤。',156,'全唐诗/poet.song.88000.json','["劉侯一諾重，勝獲金百斤。", "秀句忽復出，華名愧微薫。", "但憐溝中斷，枉錯黄金文。", "君欲强推轂，誰當爲解紛。", "顧我絕世好，百念獨此勤。", "鵲尾得古製，鷓鴣玩斑紋。", "時從孤巒頂，看上秋空雲。", "遂作小方寮，調護留清芬。", "忘言聊復爾，念意亦可欣。", "了知法界中，清静無五葷。", "倘非此地勝，是妙數得聞。", "誰知几席間，中有造化恩。", "遂此草木性，一氣蒙氤氲。"]'),
('2918b3cb-0cf6-464b-84ec-fa484f0f600d','劉德秀縣丞凢五和前篇僕亦五次其韻  其二','周紫芝','宋','宋诗','song-poetry','','[]','楚澤是魚稻，不論斗與斤。',156,'全唐诗/poet.song.88000.json','["楚澤是魚稻，不論斗與斤。", "老守睡足處，飽飫聞餘薫。", "時歌郢人曲，細和湘纍文。", "天風一披拂，花砌飛繽紛。", "樂此盡日静，頗無終歲勤。", "劉侯過我數，坐久衣成紋。", "時驚燕梁句，有似春空雲。", "千年論往事，一炷同清芬。", "有客乃如此，我意豈不欣。", "人生如草木，鼻味殊薌葷。", "海天得彼趣，妙香吾所聞。", "庶希清浄化，上答明聖恩。", "從今世外樂，可比洪崖氲。"]'),
('cd51dedd-01ee-4fe3-b2a8-f9c93b9ac39d','劉德秀縣丞凢五和前篇僕亦五次其韻  其三','周紫芝','宋','宋诗','song-poetry','','[]','蔚宗草香傳，水沈貴盈斤。',156,'全唐诗/poet.song.88000.json','["蔚宗草香傳，水沈貴盈斤。", "標置何必高，有德當自薫。", "士成稍藴藉，往往嗔斯文。", "人生顧安用，浪爲此紛紛。", "我静偶獲趣，君意良復勤。", "摩娑辨款識，共玩古曹紋。", "青烟既司寒，小孤方插雲。", "詩應神所授，句與爐争芬。", "懸知我輩事，俗子未必欣。", "不容芝蘭室，雜以蒿艾葷。", "政恐千年後，餘臭尚有聞。", "惟愛青雲士，亟拜黄屋恩。", "未知誰氏子，肯對香氤氲。"]'),
('b171a75d-8424-4ebf-81e0-c5623bf21135','劉德秀縣丞凢五和前篇僕亦五次其韻  其四','周紫芝','宋','宋诗','song-poetry','','[]','念昔居上國，春薺賣作斤。',144,'全唐诗/poet.song.88000.json','["念昔居上國，春薺賣作斤。", "那得千金嚢，可買百濯薫。", "一爲道院主，坐空朱墨文。", "清笳咽悲壯，濃篆横披紛。", "幽意可略喜，老倦復小勤。", "詩如水得風，自然偶成紋。", "香亦旋變滅，頗類無心雲。", "丞哉兩松篇，時出水麝芬。", "鏤冰納蔬腸，争洗三韭葷。", "敏手不可敵，勝妙昔未聞。", "豈不勝兒女，呢呢相怨恩。", "人生如此少，爐烟且氤氲。"]'),
('1fd4fcea-ff10-43f3-9a5b-863adf15a80e','劉德秀縣丞凢五和前篇僕亦五次其韻  其五','周紫芝','宋','宋诗','song-poetry','','[]','隱之刺五羊，歸嚢香一斤。',156,'全唐诗/poet.song.88000.json','["隱之刺五羊，歸嚢香一斤。", "恕投湖亭水，內子無飯薫。", "欲草廉吏傳，恨無班馬文。", "此風一凋落，披靡如絲紛。", "前身是香嚴，宿習今尚勤。", "爐烟凝室炷，印篆緘雕紋。", "嗜香猶有癖，於世已如雲。", "况今花木妍，香風度微芬。", "節物豈不佳，老況難強欣。", "太常齋日多，十飯九不葷。", "唯有鼻孔香，時於静中聞。", "未知劉季和，何如荀令君。", "且當置是事，一笑同氤氲。"]'),
('d5d6bffa-a64c-49a3-ac56-718df3128ab1','蘇內相在黄岡嘗從桃花寺僧覓茶栽移種雪堂下余始至此會歲且暮明年春得新芽試之色香味俱絕不減湖越二品宜其見賞於此老人也人言雪堂今已鞠爲館驛茶蓋可知矣','周紫芝','宋','宋诗','song-poetry','','[]','梅雪既掃地，桃花露微紅。',180,'全唐诗/poet.song.88000.json','["梅雪既掃地，桃花露微紅。", "風從北苑來，吹入茶塢中。", "真香不可說，玉色誰與同。", "不知耐幾湯，成此三味功。", "顧渚與日注，名高各雌雄。", "四海一大地，所至皆春風。", "物固有不幸，乃爾殊窮通。", "此品不見稱，白雲空蒙茸。", "移栽雪堂下，賴有黄岡翁。", "來禽青李帖，絕世無此工。", "遂使桃花名，遍滿江西東。", "此老久下世，真賞殊未逢。", "只今調粥手，乳花爲誰濃。", "堂今在館驛，樹亦知何蹤。", "樹固不足惜，館驛行當空。"]'),
('7797eda2-225f-4d62-9758-c8ad86eb8c33','筠陽竹根枕','周紫芝','宋','宋诗','song-poetry','','[]','高安老竹三尺圍，斷爲釡甑中可炊。',160,'全唐诗/poet.song.88000.json','["高安老竹三尺圍，斷爲釡甑中可炊。", "蘄州開笛不足數，嶰谷截筒空自奇。", "何如猫頭未成竹，化爲霜根白如玉。", "峥嶸勁節不得施，歷碌黑斑空滿目。", "白頭老吏飽官倉，雲夢南州睡初足。", "筠陽别乘一幅書，寄我中刳兩枵腹。", "飄飄逸韻青衣郎，夢中相見筠山陽。", "一笑摩挲撫君背，定教從此毋相忘。", "我欲問舍無何鄉，爲我往使華胥王。", "人生草草兩鬢霜，要知日月壺中長。"]'),
('24d6a9ca-74ec-4f5a-8d73-08ef138969d6','四月五日早晴二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','老病猶朝朔，華顛尚著冠。',48,'全唐诗/poet.song.88000.json','["老病猶朝朔，華顛尚著冠。", "馬頭收雨去，湖面拍堤寒。", "鳥作鄉關語，花如夢寐看。", "晚來還倚杖，看日下欄干。"]'),
('2cc36934-fa65-4839-ab6b-251a6805579a','四月五日早晴二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','憶作西來夢，猶堪細數程。',48,'全唐诗/poet.song.88000.json','["憶作西來夢，猶堪細數程。", "隨雲千里到，看月五番生。", "上箔蠶宜暖，瀕湖麥要晴。", "天應憐病守，有意在秋成。"]'),
('37d68b5b-9082-4e34-a324-06d2626428b0','四月八日燕客湖亭風雨忽來頗有波瀾意欣然悅之  其一','周紫芝','宋','宋诗','song-poetry','','[]','水平真欲見秋毫，碧海無人掣巨鼇。',32,'全唐诗/poet.song.88000.json','["水平真欲見秋毫，碧海無人掣巨鼇。", "多謝西風卷烟雨，肯來湖面作波濤。"]'),
('44514a06-949e-4b63-8fed-5ab0852df709','四月八日燕客湖亭風雨忽來頗有波瀾意欣然悅之  其二','周紫芝','宋','宋诗','song-poetry','','[]','孤山十載飲湖光，更入江西鷗鷺行。',32,'全唐诗/poet.song.88000.json','["孤山十載飲湖光，更入江西鷗鷺行。", "官舍一生常近水，前身應是水仙王。"]'),
('68c84149-1bd3-4fb8-97ff-daad197ba61e','四月八日燕客湖亭風雨忽來頗有波瀾意欣然悅之  其三','周紫芝','宋','宋诗','song-poetry','','[]','白雨跳珠水上鳴，雪花吹浪酒邊行。',32,'全唐诗/poet.song.88000.json','["白雨跳珠水上鳴，雪花吹浪酒邊行。", "不嗔燕子飛將去，最愛鸕鷀睡不驚。"]'),
('a5d9c369-3d3a-4a83-a646-a0460d548e82','千葉石榴盛開爲賦一詩','周紫芝','宋','宋诗','song-poetry','','[]','江東五月榴花紅，江西三月滿花叢。',128,'全唐诗/poet.song.88000.json','["江東五月榴花紅，江西三月滿花叢。", "東花窘束少態度，西花重疊紅蒙茸。", "誰翦燕支山下草，乞與殷紅照林杪。", "移栽我欲過江東，銜子鴻鵠今成空。", "紅巾半蹙爲誰苦，芳心何止千重重。", "試遺紅粧歌一曲，此花此曲何由逢。", "春光都無十日事，不成夜雨還朝風。", "紅芳莫遣忽飛去，斷腸烟雨空溟濛。"]'),
('12a25b64-3ff3-4784-9e2d-c84392613be6','十六日對雨是日聞得濓溪地','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','大麥結穗牛尾長，小麥滿地秋雲黄。',128,'全唐诗/poet.song.88000.json','["大麥結穗牛尾長，小麥滿地秋雲黄。", "清漣堂前今日雨，中有廬山湯餅香。", "故人喚我廬山住，欲買茅椽近廬阜。", "得田於我復何求，只就天公覓甘澍。", "天隨農父與陰晴，雲共東風作朝暮。", "山南山北水長流，下田高壠禾無數。", "秫堪醸酒醉不醒，飯可充饑飽摩肚。", "先生不管醉尉呵，柱杖尋遊遶山去。"]'),
('c299c497-a55a-47ef-95f7-f9422dbc8662','鼓鼕鼕行','周紫芝','宋','宋诗','song-poetry','','[]','煙雨凄凄芳草渡，隔岸鼕鼕賽神鼓。',64,'全唐诗/poet.song.88000.json','["煙雨凄凄芳草渡，隔岸鼕鼕賽神鼓。", "男巫唱歌女巫舞，蠶宜青桑麥宜土。", "天下無兵三百州，不如賣劍買汝牛。", "千倉萬廩汝莫愛，富民今歲新封侯。"]'),
('73431658-6cf1-4e20-9620-0a78d6319348','午睡聽流鶯作歌  其一','周紫芝','宋','宋诗','song-poetry','','[]','擬倩花枝當綺羅，更煩鶯作緩聲歌。',32,'全唐诗/poet.song.88000.json','["擬倩花枝當綺羅，更煩鶯作緩聲歌。", "未殘春色猶堪惜，已老周郎奈若何。"]'),
('58875b70-7760-4ac0-baa5-4a989b2b0ece','午睡聽流鶯作歌  其二','周紫芝','宋','宋诗','song-poetry','','[]','樹裏金衣不露身，欲尋啼處了無因。',32,'全唐诗/poet.song.88000.json','["樹裏金衣不露身，欲尋啼處了無因。", "綠陰長得成何事，遮却黄鸝最惱人。"]'),
('10c3b3ab-ade3-4a60-a787-8c782f40ed44','午睡聽流鶯作歌  其三','周紫芝','宋','宋诗','song-poetry','','[]','江南草長亂啼鶯，睡足南州得細聽。',32,'全唐诗/poet.song.88000.json','["江南草長亂啼鶯，睡足南州得細聽。", "最愛欲歌還欲住，伴人如夢亦如醒。"]'),
('43db3787-5d2a-455f-a6c8-f9afcfe3f752','寄黄超然監丞求山谷像','周紫芝','宋','宋诗','song-poetry','','[]','昔人生不恨，幸識元魯山。',180,'全唐诗/poet.song.88000.json','["昔人生不恨，幸識元魯山。", "平生黄叔度，常在夢想間。", "時於絹素中，得見冰雪顔。", "晚乃客京洛，髯孫始追攀。", "眉目真似之，典刑今未刊。", "昔我在武林，歲月不得閑。", "甚欲貌公像，歸嚢竟空還。", "邇從同寮家，小軸得細看。", "芒鞵方釋杖，野服不著冠。", "尚恐或非真，蠧蟲亦少殘。", "謂言君家本，可借不作難。", "願君呼畫史，摹寫來江干。", "孫郎傾蓋交，臭味同芝蘭。", "能事亦須趣，勿作水石慳。", "君不相我請，幽興恐易闌。"]'),
('59f69c37-4cfc-4f97-a157-65647f0501e1','次韻沈季鄉題醉山堂','周紫芝','宋','宋诗','song-poetry','','[]','看盡吳頭楚尾山，不嫌心似鳥知還。',64,'全唐诗/poet.song.88000.json','["看盡吳頭楚尾山，不嫌心似鳥知還。", "可憐樽爼登臨處，正在烟雲杳靄間。", "地勝豈無神物護，天教付與老翁閑。", "憑欄欲喚君來語，家住寒溪第幾灣。"]'),
('35e8068b-5654-49ac-9af2-b852dee55b3e','送呼延韓仲','周紫芝','宋','宋诗','song-poetry','','[]','人生何苦著儒冠，心與功名了不干。',64,'全唐诗/poet.song.88000.json','["人生何苦著儒冠，心與功名了不干。", "早歲氣吞雲夢澤，暮年身作灞陵官。", "欲尋故國今安在，漫醉醨樽不當歡。", "老别相逢知幾日，花鬚句在好重看。"]'),
('2393d7aa-1e6e-4d15-8f60-d6d0cb0d2a6d','晚思','周紫芝','宋','宋诗','song-poetry','','[]','落日下平蕪，回照東湖尾。',48,'全唐诗/poet.song.88000.json','["落日下平蕪，回照東湖尾。", "牛從何處歸，相隨渡湖水。", "幽人倚欄意，得月猶未已。", "白鷺知何爲，欲下還復起。"]'),
('f346ad68-24af-4052-aad6-30f0f41ac62f','送劉德秀赴官貴池','周紫芝','宋','宋诗','song-poetry','','[]','劉郎人物照當時，未上青雲莫慢遲。',64,'全唐诗/poet.song.88000.json','["劉郎人物照當時，未上青雲莫慢遲。", "秋浦江山應似舊，藍田雁鶩不妨詩。", "銷魂怕作文通别，問字誰如伯始知。", "此去醉山梅欲動，憶君同看雪前枝。"]'),
('9f651349-349a-4c0e-8909-56bf0167ec83','季卿惠詩頗寓窮愁之意作是詩勉之','周紫芝','宋','宋诗','song-poetry','','[]','君有篇章配國風，技兼鼯鼠固應窮。',64,'全唐诗/poet.song.88000.json','["君有篇章配國風，技兼鼯鼠固應窮。", "但令人似千金璧，莫恨門生一丈蓬。", "北阮有生寧免俗，蒙荘雖放亦求通。", "會看黄鵠摩霄去，未可輕投燕雀叢。"]'),
('6273cd04-5568-4d96-bd97-270ff2ac7787','秋意','周紫芝','宋','宋诗','song-poetry','','[]','江城木落又秋高，歸夢難成客鬢凋。',32,'全唐诗/poet.song.88000.json','["江城木落又秋高，歸夢難成客鬢凋。", "擬倩西風吹雨去，莫來窗下打芭蕉。"]'),
('f2f961a3-c16f-4cf1-8417-d6863483cad7','十月晦日郡席見鵝梨','周紫芝','宋','宋诗','song-poetry','','[]','雪後新嘗濺齒泉，樽前風味固依然。',64,'全唐诗/poet.song.88000.json','["雪後新嘗濺齒泉，樽前風味固依然。", "自從北郡無人到，不見鵝梨今幾年。", "魯酒謾傾猶病渇，并刀未下已流涎。", "從今莫覓張公種，飣坐雖多不當賢。"]'),
('b2358060-8640-41e6-9dc1-2816f89c918b','題向司户薌林圖','周紫芝','宋','宋诗','song-poetry','','[]','宸奎猶作麝烟浮，便艤歸航結小樓。',64,'全唐诗/poet.song.88000.json','["宸奎猶作麝烟浮，便艤歸航結小樓。", "何處訪求三島路，徑須圖畫百花洲。", "黄金殿裏鵷鸞夢，白鷺江頭草樹秋。", "天上歸來輞川住，世間那有此風流。"]'),
('2bbad000-852d-478f-9f43-ef4bb363055f','臘月二十三日郡廳禱雪宿齋房趙尉燈下送蠟梅','周紫芝','宋','宋诗','song-poetry','','[]','半昏燈火宿齋房，驚見梅梢破蠟黄。',32,'全唐诗/poet.song.88000.json','["半昏燈火宿齋房，驚見梅梢破蠟黄。", "夜静月斜簾不卷，步虚聲裏得花香。"]'),
('b2d1a7b5-52c1-46c8-a975-e47c810250df','正月十四日夜病在告雨中不寐示劉德秀','周紫芝','宋','宋诗','song-poetry','','[]','雨意涔涔客夢慳，病來無意近歌檀。',64,'全唐诗/poet.song.88000.json','["雨意涔涔客夢慳，病來無意近歌檀。", "看他紅袖傾春酒，分我青燈照夜寒。", "老子要非年少伴，醉鄉空願故時歡。", "懸知鄴下劉公幹，猶擁書檠午夜看。"]'),
('9863f024-6e8f-4937-804a-983489441f13','題李伯時畫歸去來圖','周紫芝','宋','宋诗','song-poetry','','[]','淵明詩成無色畫，龍眠畫出無聲詩。',192,'全唐诗/poet.song.88000.json','["淵明詩成無色畫，龍眠畫出無聲詩。", "兩公恐是前後身，二妙略殊今昔時。", "我頃誦詩不知處，今乃按圖俱得之。", "當時想見歸意好，扁舟颺水風吹衣。", "壺觴未飲入室酒，玉色先見迎門兒。", "豈無故老說情話，尚有殘菊依東籬。", "雲歸鳥倦自有意，欲辯已忘誰復知。", "龍眠得之心應手，筆所到處心相隨。", "僮奴似有傲世色，草木亦带烟霞姿。", "癡兒方辦公家事，此老自挾南畝犁。", "人生異趣豈不遠，心如鐡石終難移。", "我今此意不自事，老去見畫空慚非。"]'),
('a76a8348-45c0-4e19-a704-76b1214b7ae7','次韻范提幹二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','繡袞華貂侍禁宸，忠宣遺烈在絲綸。',64,'全唐诗/poet.song.88000.json','["繡袞華貂侍禁宸，忠宣遺烈在絲綸。", "傳家父子俱仁孝，蓋世功名孰比倫。", "閥閲固知流派遠，衣冠今見典型新。", "如公自是青雲器，不作劉郎問大鈞。"]'),
('7879d2c5-7c43-4a09-81ee-2860aaec8013','次韻范提幹二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','白頭於世亦何能，欲賦歸來計未成。',64,'全唐诗/poet.song.88000.json','["白頭於世亦何能，欲賦歸來計未成。", "孟博聲名追往昔，蔚宗文字慰平生。", "風流易散嗟人事，臭味相求豈世情。", "欲唱清歌送行客，不知誰是米嘉榮。"]'),
('22315e7a-69f2-4bd0-9a28-bf1cbc18116e','客夢','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','客夢長千里，官居已歲餘。',48,'全唐诗/poet.song.88000.json','["客夢長千里，官居已歲餘。", "却愁花蘂動，轉益鬢毛疏。", "山氣朝朝雨，江苞月月魚。", "匡廬早歸去，稚子可籃輿。"]'),
('d96243f6-2d06-43e7-9e09-3519d940e5fe','次韻强使君見寄','周紫芝','宋','宋诗','song-poetry','','[]','夢澤南州聽曉雞，老饕於此寄朱麾。',64,'全唐诗/poet.song.88000.json','["夢澤南州聽曉雞，老饕於此寄朱麾。", "春湖魚上先分玉，暗谷茶生看展旗。", "酒甲江西聊可醉，山横楚尾恨無詩。", "年豐訟少知何事，時有光陰到楚詞。"]'),
('63822e3c-c86b-4814-9185-3b6c78171553','次韻黄叔魚見寄','周紫芝','宋','宋诗','song-poetry','','[]','江邊熟睡不聞雞，高臥何功尚擁麾。',64,'全唐诗/poet.song.88000.json','["江邊熟睡不聞雞，高臥何功尚擁麾。", "千里西風飽魚蟹，十年驚魄夢旌旗。", "名慚公瑾終焉用，人似黄香更好詩。", "欲作報章無妙語，楚歌唯有竹枝詞。"]'),
('a0a12e5a-7ad8-4429-9857-6f5813760231','湖亭之勝大似江上但無蘆葦二月二十日移植數十本','周紫芝','宋','宋诗','song-poetry','','[]','大年著色山前雨，摩詰無聲句裏秋。',32,'全唐诗/poet.song.88000.json','["大年著色山前雨，摩詰無聲句裏秋。", "已是湖山無限好，更栽蘆葉伴輕鷗。"]'),
('58c101c8-a6b9-4c9e-a7d0-eb1dca7b44f0','杜鵑三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','甘王祠下杜鵑啼，句句聲聲是說歸。',32,'全唐诗/poet.song.88000.json','["甘王祠下杜鵑啼，句句聲聲是說歸。", "安得一家三十口，似君兩翼解高飛。"]'),
('203e0a38-6247-4578-867e-c55ec9009fb5','杜鵑三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','千秋但有一淵明，肯脫青衫事耦耕。',32,'全唐诗/poet.song.88000.json','["千秋但有一淵明，肯脫青衫事耦耕。", "政使漢朝俱此老，都門誰祖二疏行。"]'),
('b43d5ef3-ee29-4b7e-bdfe-f0e63cea515b','杜鵑三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','窮甚亦須缾有粟，天寒可遣婦無褌。',32,'全唐诗/poet.song.88000.json','["窮甚亦須缾有粟，天寒可遣婦無褌。", "杜鵑不大知人意，歸計應須與細論。"]'),
('9bccb1ee-5dfb-4dcd-b437-2d39f54237a4','聞真如牡丹盛開偶憶去歲看花之會二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','記得東風隔水村，偶逢幽艶薦芳樽。',32,'全唐诗/poet.song.88000.json','["記得東風隔水村，偶逢幽艶薦芳樽。", "今年多病無行樂，更怕春寒不出門。"]'),
('df96c998-90c4-48cc-bf5b-e5127e6fefa4','聞真如牡丹盛開偶憶去歲看花之會二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','春來花草盡關愁，風雨妨人懶出游。',32,'全唐诗/poet.song.88000.json','["春來花草盡關愁，風雨妨人懶出游。", "不見鞓紅去年面，可憐孤負玉風流。"]'),
('4828ab97-2d3b-40d3-a1d0-92505c96400d','謝王侍郎寄東倉祖送圖二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','都門供帳記當年，十里旌旗暗畫船。',64,'全唐诗/poet.song.88000.json','["都門供帳記當年，十里旌旗暗畫船。", "文石班中天上客，水晶宮裏地行仙。", "鈴齋妙畫人間見，相府珍篇海內傳。", "錦軸牙籖渾未識，忽隨雙鯉到家邊。"]'),
('258c1ff4-0615-40b1-a360-783d9c835815','謝王侍郎寄東倉祖送圖二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','抗章聞說動前旒，分得東吳第一州。',64,'全唐诗/poet.song.88000.json','["抗章聞說動前旒，分得東吳第一州。", "久與衣冠爲盛事，更尋雲水作遨頭。", "當時鵷鷺應須記，此去湖山莫謾留。", "却笑杜郎生羽翼，但知歡喜下汀州。"]'),
('fe0d5e5f-748b-46b3-8c52-b6d10bd9e7b7','次韻李安州贈别','周紫芝','宋','宋诗','song-poetry','','[]','老來著處便爲家，行盡江西是水涯。',64,'全唐诗/poet.song.88000.json','["老來著處便爲家，行盡江西是水涯。", "詩到說歸無限意，山非吾土未應嘉。", "我思故國方成恨，君到東湖尚有花。", "更欲少留聽句法，公詩已似玉無瑕。"]'),
('b3885303-be27-461f-8260-dfd1795e3d01','次韻李安州紀贈二十韻','周紫芝','宋','宋诗','song-poetry','','[]','衣冠數人物，伯仲高人間。',240,'全唐诗/poet.song.88000.json','["衣冠數人物，伯仲高人間。", "我於鴻雁行，疇昔奉往還。", "掛名華萼集，遂爾不復刊。", "暮齒慨晼晚，得州近荆蠻。", "恨公識面遲，又復容追攀。", "高風薄雲漢，秀句横筆端。", "乃知同氣中，文采真斑斑。", "誰將鄖城水，換取蓬萊山。", "要公撫凋氓，天意豈等閑。", "玉階有餘地，行歸鳴佩環。", "上最不待久，唾手未苦難。", "念我老已熟，無鬢堪成班。", "江頭忽三月，坐見春物殘。", "相逢喜傾蓋，往事論險艱。", "一飲未徹席，扁舟渡驚湍。", "情鍾惜易别，易别成永歎。", "可憐堂下水，故作聲潺湲。", "風流倏雲散，人生豈長歡。", "願公寄尺書，細行勿輕刪。", "仍煩巧匠手，著意鐫堅頑。"]'),
('5231d120-2a5e-4174-9cdc-30bef848d335','北湖暮春十首  其一','周紫芝','宋','宋诗','song-poetry','','[]','東君無意惜花殘，留得青山隔雨看。',32,'全唐诗/poet.song.88000.json','["東君無意惜花殘，留得青山隔雨看。", "可怪天公不憐客，綠陰成後却春寒。"]'),
('825b9ca8-5a15-476d-bfe8-cf4a2c37706c','北湖暮春十首  其二','周紫芝','宋','宋诗','song-poetry','','[]','北湖看雨兩春餘，忘却漁村笠澤居。',32,'全唐诗/poet.song.88000.json','["北湖看雨兩春餘，忘却漁村笠澤居。", "去歲鶯花猶是主，今年鬚鬢不勝疏。"]'),
('c6765f77-caec-4998-b77f-b5545c558c4d','北湖暮春十首  其三','周紫芝','宋','宋诗','song-poetry','','[]','花到酴醿欲盡時，一春已是燕游稀。',32,'全唐诗/poet.song.88000.json','["花到酴醿欲盡時，一春已是燕游稀。", "舊來持酒聽歌處，乞與東風燕子飛。"]'),
('6b6dfa12-709a-4c7a-9e35-3808c6354f6b','北湖暮春十首  其四','周紫芝','宋','宋诗','song-poetry','','[]','長安市裏人如海，靜寄庵中日似年。',32,'全唐诗/poet.song.88000.json','["長安市裏人如海，靜寄庵中日似年。", "夢斷午窗花影轉，小爐猶有睡時煙。"]'),
('4ad1e7e1-fe5b-43ec-bfc4-999194eacca6','北湖暮春十首  其五','周紫芝','宋','宋诗','song-poetry','','[]','幾日春風自在顛，誰家相喚上鞦韆。',32,'全唐诗/poet.song.88000.json','["幾日春風自在顛，誰家相喚上鞦韆。", "難留花住那堪雨，不奈天寒更禁烟。"]'),
('a09ea980-e8af-4f11-964c-e865d2f0600c','北湖暮春十首  其六','周紫芝','宋','宋诗','song-poetry','','[]','洛紅聞說爛如霞，應著青油密護遮。',32,'全唐诗/poet.song.88000.json','["洛紅聞說爛如霞，應著青油密護遮。", "莫剪姚黄供老眼，使君頭白懶看花。"]'),
('2d317894-1159-4af0-86b1-e628d895cae4','北湖暮春十首  其七','周紫芝','宋','宋诗','song-poetry','','[]','韋郎詩淡少人傳，貪看仙書不愛眠。',32,'全唐诗/poet.song.88000.json','["韋郎詩淡少人傳，貪看仙書不愛眠。", "閑磨小團新樣月，撥灰重試古龍涎。"]'),
('33ac2cff-71e5-425c-bffb-2894108f8608','北湖暮春十首  其八','周紫芝','宋','宋诗','song-poetry','','[]','西施乳白魚供箸，樊素唇紅果薦新。',32,'全唐诗/poet.song.88000.json','["西施乳白魚供箸，樊素唇紅果薦新。", "不恨江干春晼晚，旅庖猶是慰愁人。"]'),
('6d06ca43-c140-45aa-be08-62627693a282','北湖暮春十首  其九','周紫芝','宋','宋诗','song-poetry','','[]','落絮天慵草漸勻，最遲紅藥又成塵。',32,'全唐诗/poet.song.88000.json','["落絮天慵草漸勻，最遲紅藥又成塵。", "苦無黄鳥能歌舞，連日春陰悶殺人。"]'),
('1317e071-d6f3-4150-a004-f7fd907cc5f9','北湖暮春十首  其一○','周紫芝','宋','宋诗','song-poetry','','[]','燕梁夫婦幾時歸，養得新雛總解飛。',32,'全唐诗/poet.song.88000.json','["燕梁夫婦幾時歸，養得新雛總解飛。", "投老卜巢猶未定，可憐人不似烏衣。"]'),
('b35fdddc-bbbe-449e-9a8b-9e80844c24ae','次韻元相題到花亭','周紫芝','宋','宋诗','song-poetry','','[]','從他白髪三千丈，莫管人生七十稀。',32,'全唐诗/poet.song.88000.json','["從他白髪三千丈，莫管人生七十稀。", "滿載月明歌一曲，到花亭裏醉中歸。"]'),
('f9b4b463-6a17-49b0-9599-b84bd2a0af25','送李瑞昌','周紫芝','宋','宋诗','song-poetry','','[]','廬阜老人心古錐，頗學子長多愛奇。',160,'全唐诗/poet.song.88000.json','["廬阜老人心古錐，頗學子長多愛奇。", "晚生恨不見前輩，一談往事神先馳。", "龍眠人品似摩詰，不比老閻呼畫師。", "往時袖手閲神駿，三馬就斃何由追。", "都人一日傳萬口，後生聞此心懷疑。", "諸孫今喜典型在，此事頗從君得之。", "吾皇仁聖重賢士，子孫必錄初無遺。", "但令苛政不如虎，會有善事令天知。", "碧油擁被報政急，桁楊臥壁催科遲。", "他年父老歌遺愛，爲君摩石題蒼碑。"]'),
('92b3107d-33d2-4ba0-bfec-38024367391e','余手植木芙蕖數十本山亭之下比聞頗爲群羊踐履','周紫芝','宋','宋诗','song-poetry','','[]','春去無花伴白顛，旋栽紅艶照霜前。',32,'全唐诗/poet.song.88000.json','["春去無花伴白顛，旋栽紅艶照霜前。", "髯郎莫剪柔柯去，留作秋風一醉眠。"]'),
('8023e61d-215f-490c-9ba1-650fb6ef255d','送高仲思提幹','周紫芝','宋','宋诗','song-poetry','','[]','獮猴莫厭土牛遲，天馬能行老更奇。',64,'全唐诗/poet.song.88000.json','["獮猴莫厭土牛遲，天馬能行老更奇。", "論事頗遭官長怒，潔身惟恐世人知。", "簿書奔走聊應爾，臺閣飛騰自有時。", "雲落斷鴻誰是伴，尺書何日慰相思。"]'),
('880be645-5b11-47d4-b199-ff52bdedc506','送瑩老住灌谿  其一','周紫芝','宋','宋诗','song-poetry','','[]','一年身寄水南村，誰把禪床一席分。',32,'全唐诗/poet.song.88000.json','["一年身寄水南村，誰把禪床一席分。", "去住隨緣本無意，道人蹤跡似孤雲。"]'),
('7fa456d9-9c1a-448b-a1af-85e960363ac5','送瑩老住灌谿  其二','周紫芝','宋','宋诗','song-poetry','','[]','竹坡無物可關懷，只有青山眼爲開。',32,'全唐诗/poet.song.88000.json','["竹坡無物可關懷，只有青山眼爲開。", "未識灌溪真面目，煩君著句畫將來。"]'),
('3c77ef6e-48ba-4739-8e62-239fbb46947e','送楊師醇之臨安兼呈師古','周紫芝','宋','宋诗','song-poetry','','[]','家在湓城五老山，與君相望各江干。',64,'全唐诗/poet.song.88000.json','["家在湓城五老山，與君相望各江干。", "如何肯撥艅艎棹，便欲來同苜蓿盤。", "傾蓋盡知今日意，買鄰仍結舊時歡。", "菊觴澆酒無離恨，淡榜書名看二難。"]'),
('9025744f-8880-4ab1-9268-3c5e4bc1cda3','擬省題桂林一枝詩','周紫芝','宋','宋诗','song-poetry','','[]','晉祚傳千載，賢科重一時。',72,'全唐诗/poet.song.88000.json','["晉祚傳千載，賢科重一時。", "擬横金殿棟，先剪桂林枝。", "月窟根盤壯，烟巖雨露滋。", "孤芳寧有種，凡木自多姿。", "臃腫樗空大，風流柳漫垂。", "惟應太邱令，功德季方知。"]'),
('174d70cf-b2d3-4ec4-9baf-99aab5a3569b','秋來久不作詩書所感','周紫芝','宋','宋诗','song-poetry','','[]','雨蹙江濤壯，天含暮靄低。',48,'全唐诗/poet.song.88000.json','["雨蹙江濤壯，天含暮靄低。", "年華添老色，風物似年時。", "富貴渾無念，情懷不到詩。", "度秋無一語，已是俗人爲。"]'),
('f08326c1-b24b-4fe3-874d-ac5bdeab03e4','寄李安州未得别後書二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','未得安州信，空添楚水秋。',48,'全唐诗/poet.song.88000.json','["未得安州信，空添楚水秋。", "雁寒飛不到，江遠望難休。", "去國雙紅旆，攜家兩白頭。", "可能無一字，分慰老人愁。"]'),
('eac8289d-2e5a-4763-a8a6-258f703726c9','寄李安州未得别後書二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','鄂渚他時縣，江南盡處州。',48,'全唐诗/poet.song.88000.json','["鄂渚他時縣，江南盡處州。", "平生求識面，此地忽同遊。", "湖外公開府，江邊我上樓。", "尺書何日到，能寄近詩不。"]'),
('a8eb9e5e-a14b-4bcc-9a2b-e618a0660b15','送富川秋舉五君子','周紫芝','宋','宋诗','song-poetry','','[]','雲衢欲上馬蹄輕，莫問長安路幾程。',64,'全唐诗/poet.song.88000.json','["雲衢欲上馬蹄輕，莫問長安路幾程。", "雙劍竟須騰巨澤，夜光元自當連城。", "偶因勸駕江邊日，猶記臚傳玉陛聲。", "澹墨榜知何日出，擬開春瓮爲君傾。"]'),
('5fec3ca7-0c30-4fa2-9aed-c2c5ae9a5f1f','收小兒栞書二詩因趣其歸  其一','周紫芝','宋','宋诗','song-poetry','','[]','黄梅雨熟汝辭家，數得秋風到藕花。',32,'全唐诗/poet.song.88000.json','["黄梅雨熟汝辭家，數得秋風到藕花。", "書裏懸知有歸日，醉中不復問年華。"]'),
('e09c428b-5f1a-4c1c-ac9c-0a31e818f508','收小兒栞書二詩因趣其歸  其二','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','廬峰今已卜菟裘，心共長江日月流。',32,'全唐诗/poet.song.88000.json','["廬峰今已卜菟裘，心共長江日月流。", "莫待西風彫綠草，速來隨我上歸舟。"]'),
('e131514c-51fd-4d67-8da7-5a85e9848543','次韻强幼安中大以僕築室濂溪見寄','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','歸去來兮復幾時，臨流屢欲喚篙師。',64,'全唐诗/poet.song.88000.json','["歸去來兮復幾時，臨流屢欲喚篙師。", "種秔有地供饑腹，佩犢無人作去思。", "偶著衣冠真是夢，倦尋丘壑已嫌遲。", "如今真在廬山裏，二妙堂成更乞詩。"]'),
('e468b48c-b8da-4656-84f6-04661977a735','强幼安中大示樂聞過齋記以詩爲謝','周紫芝','宋','宋诗','song-poetry','','[]','白璧摩挲未有疵，榜齋銘座尚防微。',64,'全唐诗/poet.song.88000.json','["白璧摩挲未有疵，榜齋銘座尚防微。", "欲從今日求聞過，故說當年是昨非。", "言行固知無裏襮，吏民何處不恩威。", "欲參函丈師全德，此去應須便拂衣。"]'),
('a4218727-72b3-425d-b483-543e2f2ee2e3','題趙倅家獐猿圖','周紫芝','宋','宋诗','song-poetry','','[]','易生畫手妙，幻出猿與獐。',138,'全唐诗/poet.song.88000.json','["易生畫手妙，幻出猿與獐。", "雙猿掛樹枝，二獐回目光。", "烏衣白面兩臂長，雌雄相逐争跳梁。", "秋山果熟腹自飽，雲蹬路絕人誰傷。", "下臨長嘯頗自得，那愁解舞緋衣郎。", "二獐驚怪久眦睨，深羨兩猿高據烟林藏。", "猿狙喜怒不足說，獐鹿町畦寧無場。", "枝高地卑能有幾，蚿蛇自可俱相忘。", "富貴貧賤各有適，也恐萬事誰能量。"]'),
('a6523372-6630-47b1-ac28-4545383d8c76','雪中同上醉山','周紫芝','宋','宋诗','song-poetry','','[]','駕言陟前岡，勝賞追良辰。',144,'全唐诗/poet.song.88000.json','["駕言陟前岡，勝賞追良辰。", "蒼黄慘暮色，浩蕩飛瑤塵。", "冰花似有意，娛我坐上賓。", "但恐白糢糊，偶失青嶙峋。", "造物有奇事，變滅無逡巡。", "斜陽忽到眼，萬疊羅蒼岷。", "戲從壺中天，漏此色界痕。", "况乃文字飲，盡屬我輩人。", "老守頗自愧，繆許參冠巾。", "念我千里行，維舟在江濱。", "雪既不可留，跡亦恐遂陳。", "置之勿復道，且飲樽中醇。"]'),
('509ebe72-74fb-4a4f-95c1-2af5485ddb0f','送章使君守竟陵','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江盡此是吾州，君去長江更盡頭。',64,'全唐诗/poet.song.88000.json','["長江盡此是吾州，君去長江更盡頭。", "短棹只添行客恨，清樽肯爲故人留。", "飽聽夢澤洲前雨，却望蒼龍闕角樓。", "試問尺書何日到，會須紅蓼白蘋洲。"]'),
('a1c9307b-0f2f-49c4-87f7-c3fdbf6b8bd6','金山貫道人跨水作亭余爲名以枕流亭成而僕欲去作二詩因以留别  其一','周紫芝','宋','宋诗','song-poetry','','[]','聞說朱欄照眼新，一溪清淺共誰分。',32,'全唐诗/poet.song.88000.json','["聞說朱欄照眼新，一溪清淺共誰分。", "可憐橋下無情水，不遣龜魚識使君。"]'),
('70220641-3525-4f46-9f74-48ee9288792a','金山貫道人跨水作亭余爲名以枕流亭成而僕欲去作二詩因以留别  其二','周紫芝','宋','宋诗','song-poetry','','[]','與師同是一山雲，吹落江西却再分。',32,'全唐诗/poet.song.88000.json','["與師同是一山雲，吹落江西却再分。", "聚散人生俱似夢，虎溪重過不煩君。"]'),
('51998c07-d5e4-4152-b962-9f1b6995af74','食橄欖記客語','周紫芝','宋','宋诗','song-poetry','','[]','朔風吹元雲，欲雪愁江天。',144,'全唐诗/poet.song.88000.json','["朔風吹元雲，欲雪愁江天。", "煙颿駕海舶，橄欖來閩川。", "客言似有理，得失亦小偏。", "紅鹽落青子，嚼玉宜芳鮮。", "色香苦未發，遂雜春客煎。", "清香雖覆椀，翠潤殊嫣然。", "香味元自若，人生浪求全。", "方言田家翁，好惡能兩捐。", "一食輒苦口，棄擲古道邊。", "回甘入齒頰，拾遺止流涎。", "樸質固可笑，任真亦良賢。", "向來紛紛者，妄論誠可憐。"]'),
('4bc9da09-4a72-41d8-8a13-8db59ec182a2','次韻桂嘉任郎中贈别二十四韻','周紫芝','宋','宋诗','song-poetry','','[]','是身本蘧廬，誤得兩朱轓。',276,'全唐诗/poet.song.88000.json','["是身本蘧廬，誤得兩朱轓。", "朅來臥江樓，白鷗看飛翻。", "驚鴻卷西風，吹落雲水間。", "江山相表裏，宇宙殊恢寛。", "但苦千種愁，不供萬疊山。", "幸兹洪崖君，仙馭超人寰。", "一身聊復爾，萬事不可干。", "富貴倘無求，藜藿亦自安。", "不須金鼎爐，養此玉棟顔。", "紛紛一回睇，往往俱冥頑。", "有如盗跖手，可鱠朝飯肝。", "居之彼不疑，念念我心寒。", "公今梨棗成，心地無險艱。", "横湖僅一葦，經月無寒暄。", "昔爲吏曹郎，今带儒生酸。", "繆從周旋間，獲奉澹泊歡。", "公已聞大道，我猶縳枯禪。", "誰知數日惡，忽有千里歎。", "古道催行輈，滿山霜葉丹。", "仙凡自此隔，無復相追攀。", "餘生幾何時，白日飛驚湍。", "願公追松喬，駕鶴驂翔鸞。", "我亦上五老，舉首雲間看。"]'),
('23f96177-b8c7-4398-9e92-d696a3c2c905','題卷雪樓','周紫芝','宋','宋诗','song-poetry','','[]','三國英雄氣似雲，江南只數故將軍。',64,'全唐诗/poet.song.88000.json','["三國英雄氣似雲，江南只數故將軍。", "借令馬上身猶健，應笑中原鼎尚分。", "謚册屢沾新雨露，斷碑空說舊功勳。", "斜陽萬里明如雪，獨倚欄干酒半醺。"]'),
('f8522455-1796-4803-8ff8-812f33f82067','大冶山中有東方寺世傳東方曼倩嘗讀書於此寺後有聖泉凡邑人之乞子於此者隨願輒得僧慧滿住持十載無日不醉癸酉冬十二月之吉趺坐示寂九日而色不變人皆攜酒來酌師至暮必頳頰泚顙状如醉人然其事甚怪金山貫道人將赴東方之請於其行也戲作三詩送之因紀其事使刻之山中以傳好事者  其一','周紫芝','宋','宋诗','song-poetry','','[]','先生自以滑稽雄，何事偷身入漢宮。',32,'全唐诗/poet.song.88000.json','["先生自以滑稽雄，何事偷身入漢宮。", "跨鶴乘鸞本無定，安知不到此山中。"]'),
('93bed6bd-2e77-453b-b97c-40c97b6d5fe5','大冶山中有東方寺世傳東方曼倩嘗讀書於此寺後有聖泉凡邑人之乞子於此者隨願輒得僧慧滿住持十載無日不醉癸酉冬十二月之吉趺坐示寂九日而色不變人皆攜酒來酌師至暮必頳頰泚顙状如醉人然其事甚怪金山貫道人將赴東方之請於其行也戲作三詩送之因紀其事使刻之山中以傳好事者  其二','周紫芝','宋','宋诗','song-poetry','','[]','平生著酒滿葫蘆，醉上禪床不用扶。',32,'全唐诗/poet.song.88000.json','["平生著酒滿葫蘆，醉上禪床不用扶。", "更把酡顔驚世俗，方知肉眼是凡夫。"]'),
('291fce76-5477-4805-b76e-5c77577ecdee','大冶山中有東方寺世傳東方曼倩嘗讀書於此寺後有聖泉凡邑人之乞子於此者隨願輒得僧慧滿住持十載無日不醉癸酉冬十二月之吉趺坐示寂九日而色不變人皆攜酒來酌師至暮必頳頰泚顙状如醉人然其事甚怪金山貫道人將赴東方之請於其行也戲作三詩送之因紀其事使刻之山中以傳好事者  其三','周紫芝','宋','宋诗','song-poetry','','[]','誰謂靈泉易感通，解令少婦却愁容。',32,'全唐诗/poet.song.88000.json','["誰謂靈泉易感通，解令少婦却愁容。", "道人應爲衆生說，此事如何著得儂。"]'),
('79d4455c-be66-4267-9631-934a6dadf615','游香巖一小室甚温潔坐客皆言雅宜聽雪各賦一首','周紫芝','宋','宋诗','song-poetry','','[]','鵲尾烟横不卷簾，莫嫌好客坐無氈。',32,'全唐诗/poet.song.88000.json','["鵲尾烟横不卷簾，莫嫌好客坐無氈。", "道人此室知何用，留與衰翁聽雪眠。"]'),
('36f16865-2bd2-4e8a-a66b-9c43c9083f7a','曉發永城','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','跨鞍不作永城留，馬上烟銷霽色浮。',32,'全唐诗/poet.song.88000.json','["跨鞍不作永城留，馬上烟銷霽色浮。", "便恐匡廬來入望，此行今日是江洲。"]'),
('bc954964-618f-41d0-845c-17cd81d0881d','瑞昌道中梅','周紫芝','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我昔西來野梅發，今歲梅花似前臘。',64,'全唐诗/poet.song.88000.json','["我昔西來野梅發，今歲梅花似前臘。", "流年别我誰肯留，衰鬢羞花不成折。", "昔非今是未必然，尺短寸長何足說。", "到家浄洗客衣塵，猶有匡廬半山雪。"]'),
('fe145427-b8fe-4616-914b-f2f95ed345d7','時宰生日樂章七首 樂賢臣章第一','周紫芝','宋','宋诗','song-poetry','','[]','亳后出，莘野興。',88,'全唐诗/poet.song.88000.json','["亳后出，莘野興。", "一德懋，三台明。", "歲在午，月嘉平。", "鼓坎坎，玉簫鳴。", "醉厭厭，椒醑馨。", "閲萬古，所未聞。", "肖說像，傳堯文。", "盤誥出，德爵尊。", "依日月，慶風雲。", "等箕翼，奉羲軒。", "願公壽兮錫公齡。"]'),
('5bcf6fb3-895f-4929-b51f-f65534da38a3','時宰生日樂章七首 忠貫日章第二','周紫芝','宋','宋诗','song-poetry','','[]','六親和，孝慈不出。',106,'全唐诗/poet.song.88000.json','["六親和，孝慈不出。", "國道昌，忠臣不立。", "韙公節，秋霜栗。", "繄公忠，貫白日。", "河洛腥，黄霧塞。", "梟獍鳴，羣姦集。", "靡它而從中不沐，忠臣飲氣義士戢，主左與左公不屈。", "茫茫沙漠萬里天，渺渺歸船海中檝。", "公之歸，天爲悅。", "願壽公兮報公節。"]'),
('466f8734-79eb-4db7-952d-133290fad546','時宰生日樂章七首 回瀾章第三','周紫芝','宋','宋诗','song-poetry','','[]','歲在昔，時否屯。',88,'全唐诗/poet.song.88000.json','["歲在昔，時否屯。", "河陽狩，滄海渾。", "將惰驕，霸棘分。", "盜連行，兵蜂屯。", "公決策，摭霧雰。", "豐豕封，群羊奔。", "佩槖鞬，朝帝閽。", "姦氣讋，聖道尊。", "三階明，萬室歡。", "帝籍功，永不刊。", "願壽公兮公永安。"]'),
('7cba4b00-f5aa-46e2-b6b7-9d6061602d40','時宰生日樂章七首 單于朝章第四','周紫芝','宋','宋诗','song-poetry','','[]','單于朝，流沙暨。',80,'全唐诗/poet.song.88000.json','["單于朝，流沙暨。", "天降康，神樂只。", "坐法宮，聖天子。", "稽唐虞，制六藝。", "屬大儒，明古義。", "金支張，玉帛制。", "告太平，備昭事。", "天馬徠，渥洼至。", "朱鳥徠，翔九陛。", "願壽公兮報公治。"]'),
('94e90733-4318-4e41-a50e-e01a5483a3d0','時宰生日樂章七首 歌泰和章第五','周紫芝','宋','宋诗','song-poetry','','[]','馬牛歸，文軌同。',64,'全唐诗/poet.song.88000.json','["馬牛歸，文軌同。", "洛邑宅，神邱蒙。", "神光流，爟火通。", "君車駕，款郊宮。", "君車回，霈澤豐。", "神既娯，景沖融。", "俗阜康，君樂雍。", "願壽公兮報公功。"]'),
('026b52cd-8f32-4d4d-aa26-6c8f511617cc','時宰生日樂章七首 泰一徠章第六','周紫芝','宋','宋诗','song-poetry','','[]','排天門，羅萬戟。',80,'全唐诗/poet.song.88000.json','["排天門，羅萬戟。", "升三陔，祠泰一。", "旗幡幡，鼓吸吸。", "降赤霄，下瑤席。", "泰一徠，景貺集。", "歲三登，連八極。", "五臣相，宇宙一。", "神降臨，罔不吉。", "神言歸，恍兮惚。", "願壽公兮報公德。"]'),
('0aa3df46-6326-4f13-8d11-a024ea37ec60','時宰生日樂章七首 榆中章第七','周紫芝','宋','宋诗','song-poetry','','[]','榆關以北，一騎不馳。',95,'全唐诗/poet.song.88000.json','["榆關以北，一騎不馳。", "孰窺漢月，燧息烽夷。", "塞草春榮，夷氓負犁。", "九州萬井，風恬俗怡。", "血屬相保，母父子妻。", "既續厥嗣，亦活黄萊，幾億萬年。", "維德所施，礽雲來睇。", "天之報之，壽之福之。", "劫塵可數，此報何期。"]'),
('bd2e476a-b135-41c6-8ba2-df25d3763a1d','登元次山新祠','周紫芝','宋','宋诗','song-poetry','','[]','人物推前輩，風流自一時。',48,'全唐诗/poet.song.88000.json','["人物推前輩，風流自一時。", "空憐瀼溪水，還繞漫郎祠。", "君已新華屋，吾猶續斷碑。", "誰當知此意，只有少陵詩。"]'),
('131b86d0-f580-4a9b-b937-8c5423dd3779','過劉道士庵壁間見梁竑父蘇季文詩因用其韻','周紫芝','宋','宋诗','song-poetry','','[]','高臥何由雨墊巾，關門聊此寄閑身。',64,'全唐诗/poet.song.88000.json','["高臥何由雨墊巾，關門聊此寄閑身。", "長生自是君家事，白髮應憐我輩人。", "多釀醉鄉千日酒，豈知浮世十朱輪。", "重來却踐山中約，猶有桃花一半春。"]'),
('ad47c898-82f5-4db9-8034-6070461543cb','遷居二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','久作懷鄉夢，今年拚不歸。',48,'全唐诗/poet.song.88000.json','["久作懷鄉夢，今年拚不歸。", "奉親猶得粟，見客已忘衣。", "憑几看帆過，開門任燕飛。", "皇天憐老病，留此著柴扉。"]'),
('8ad0f38b-54cb-460c-8814-eab93cd29aa9','遷居二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','扶病翻書卷，移家枕斷城。',48,'全唐诗/poet.song.88000.json','["扶病翻書卷，移家枕斷城。", "雲空千嶂曉，門静一江横。", "葉密催春事，花飛惱客情。", "暮霞將霽色，招我作山行。"]'),
('0b650ee0-af4b-4792-9c26-934dc1ecb24e','傷春二首擬近體  其一','周紫芝','宋','宋诗','song-poetry','','[]','越羅初欲替茸裘，二月輕寒比麥秋。',64,'全唐诗/poet.song.88000.json','["越羅初欲替茸裘，二月輕寒比麥秋。", "潘老凋疏空惜鬢，庾郎憔悴不禁愁。", "催歸燕子春何限，落盡桃花雨未休。", "誰遣少年隨夢去，不教人似柳風流。"]'),
('f3c79e55-b2b1-462f-9f5b-a89d7ecfa89f','傷春二首擬近體  其二','周紫芝','宋','宋诗','song-poetry','','[]','一幅輕紗老秃翁，半簾疏雨著東風。',64,'全唐诗/poet.song.88000.json','["一幅輕紗老秃翁，半簾疏雨著東風。", "長條柳伴短條舞，深色桃欺淺色紅。", "愁思但知嫌酒薄，客情終不似春濃。", "盡將黑海無名障，付與邯鄲一夢中。"]'),
('6eec9a0e-f1d3-41c8-8721-6cf1de3c26e6','再賦傷春二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','豈料餘生兩鬢皤，廬峰猶得共婆娑。',64,'全唐诗/poet.song.88000.json','["豈料餘生兩鬢皤，廬峰猶得共婆娑。", "昔年自作南柯夢，此去心如古井波。", "官冷故人書不到，日長齋閣睡還多。", "文園曾病猶堪酒，傳語風光奈我何。"]'),
('46caad37-01c1-4e4e-a8dd-300901872128','再賦傷春二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','潯陽江上聽琵琶，買得江天且寄家。',64,'全唐诗/poet.song.88000.json','["潯陽江上聽琵琶，買得江天且寄家。", "带雨衝泥看燕子，隨風著地數飛花。", "人來裹飯何妨病，客去張羅亦自嘉。", "還了世間無限債，却修香火足生涯。"]'),
('ae319216-4531-48eb-b822-c4d262c676dd','客自富川來言湖水已到萬坡','周紫芝','宋','宋诗','song-poetry','','[]','昔年喚客飲湖邊，猶記湖天五月寒。',64,'全唐诗/poet.song.88000.json','["昔年喚客飲湖邊，猶記湖天五月寒。", "白鷺翻空歸杳靄，驚濤卷雪到杯盤。", "鯤鵬水擊三千里，雲夢胸吞八九寛。", "想得拍堤春漲滿，又吹飛雨濕闌干。"]'),
('d56b9048-40ff-4628-a485-41aa8a7ce696','寄章復州','周紫芝','宋','宋诗','song-poetry','','[]','春來未得復州書，流落他鄉我獨居。',64,'全唐诗/poet.song.88000.json','["春來未得復州書，流落他鄉我獨居。", "今日離羣天際雁，昔年同隊水中魚。", "遙知賣劒方成俗，想得追鋒便賜車。", "擬約琵琶亭下月，伴君一醉復何如。"]'),
('eb70a20d-f707-472c-8c05-88fd9204cf6e','南窗植竹數百竿後數日蔚然俱青客問種竹法作四言以告之','周紫芝','宋','宋诗','song-poetry','','[]','平生寡友，形影相弔。',240,'全唐诗/poet.song.88000.json','["平生寡友，形影相弔。", "與君結交，相視一笑。", "四方萬里，動静險夷。", "我惟子求，子必我随。", "聿來湓江，屋廬既正。", "相子攸居，我室乃定。", "得子之宮，於窗之南。", "風莖雨葉，蔚其鬖鬖。", "人言死貓，可引活竹。", "貓死地虛，根行竹綠。", "又言無法，移必行迷。", "仍標其根，以識東西。", "區區百設，何乃多事。", "事在眉睫，初無妙理。", "穴地成坎，碎土加篩。", "沃以斗水，和之成泥。", "置竹其中，實之以土。", "土燥潤久，可月不雨。", "逮其雨來，竹既已成。", "熱不受暑，寒不變青。", "嗟哉此君，以節自負。", "如遇君子，理宜調護。", "君欲何法，無法可傳。", "併以告子，俾知竹賢。"]'),
('5942d9c3-bd27-4165-b455-db0e2d24c6d1','九江初識水仙二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','七十詩翁鬢已華，平生未識水仙花。',32,'全唐诗/poet.song.88000.json','["七十詩翁鬢已華，平生未識水仙花。", "如今始信黄香錯，剛道山礬是一家。"]'),
('778b8e45-3718-4a45-884e-079d79af6aab','九江初識水仙二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','天香不染麝煤烟，家近龍宮寶藏邊。',32,'全唐诗/poet.song.88000.json','["天香不染麝煤烟，家近龍宮寶藏邊。", "世上鉛華無一點，分明真是水中仙。"]'),
('dc94981e-aacd-4bb6-8e64-12dffd770a31','新作布裘二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','青裘短袂瘦軀長，拄杖横擔古錦嚢。',32,'全唐诗/poet.song.88000.json','["青裘短袂瘦軀長，拄杖横擔古錦嚢。", "變盡形容人不識，家僮應怪賀知章。"]'),
('92bf7b69-65e4-4a96-a70a-19ffafd6b491','新作布裘二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','少日無心佩紫嚢，一生裘葛是衣裳。',32,'全唐诗/poet.song.88000.json','["少日無心佩紫嚢，一生裘葛是衣裳。", "但知野服尋山便，不學唐裝又晉裝。"]'),
('c13b8fbd-0293-432e-8f4d-4735aa4d8cff','吳傳朋郎中自出新意作游絲書妙絕一時士大夫皆賦詩爲作數語書軸尾','周紫芝','宋','宋诗','song-poetry','','[]','公孫舞渾脱，長史妙心畫。',156,'全唐诗/poet.song.88000.json','["公孫舞渾脱，長史妙心畫。", "老兵塗箒堊，中郎出飛帛。", "得法自所見，豈用規疇昔。", "隨人作書奴，終與古人隔。", "游絲最無事，何止但百尺。", "飛來若有態，吹去忽無跡。", "使君看青天，意外得新格。", "映空疑有無，著紙互絡繹。", "神機殆天授，至技非人積。", "遂令一絲輕，可掛千金石。", "聊將畫沙錐，幻出蟲網壁。", "我雖不解書，好書乃成癖。", "公如儻有意，能事不敢迫。"]'),
('680c5414-ee2a-4fae-b0f0-9d6aefb266d9','傳朋爲作游絲小軸報以長句','周紫芝','宋','宋诗','song-poetry','','[]','竟陵老守尚書郎，平生墨妙窺鍾王。',128,'全唐诗/poet.song.88000.json','["竟陵老守尚書郎，平生墨妙窺鍾王。", "會令夜鬼助奇崛，更與游絲争短長。", "游絲忽從天際落，洗眼熟視無毫芒。", "癡兒著意吹不起，春風無力難飛揚。", "草雖號聖亦可到，此品入神誰復强。", "使君憐我頗知好，五十六珠投夜光。", "溪藤搗紙滑勝玉，古錦縫嚢牢祕藏。", "要遣張顛與醉素，不敢與公分雁行。"]'),
('17d5d225-5ce5-4de7-b835-e8d5940ccadf','讀司馬長卿傳','周紫芝','宋','宋诗','song-poetry','','[]','揚雄新著草元書，却笑相如賦子虛。',32,'全唐诗/poet.song.88000.json','["揚雄新著草元書，却笑相如賦子虛。", "借使曲終方奏雅，比君符命復何如。"]'),
('11288a6c-2c42-4c9a-a9e4-5754c7ce661e','病起節物可驚效柳子厚','周紫芝','宋','宋诗','song-poetry','','[]','病起忽數日，杖策周吾廬。',156,'全唐诗/poet.song.88000.json','["病起忽數日，杖策周吾廬。", "桃花手新栽，小紅今欲舒。", "萱草未出土，苗葉將扶疏。", "物變乃如此，光景難踟蹰。", "退自觀我生，今形復何如。", "夢前黑垂髫，夢後霜入鬚。", "安得萬丈繩，縳此窗間駒。", "先生可笑人，爲生本田。", "晚汙琳館粟，俾代南山鋤。", "皇恩浩如海，臣報終難虛。", "老力雖不足，閑日幸有餘。", "願炷金鼎鑪，日誦琅函書。", "跪祝望天門，聖壽如居諸。"]'),
('54398e22-e2bd-42e9-a98e-d38dea77b09a','紙帳二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','雪帳垂空萬事休，醉來高枕竹猫頭。',32,'全唐诗/poet.song.88000.json','["雪帳垂空萬事休，醉來高枕竹猫頭。", "不知金谷園中障，輸與儂家幾百籌。"]'),
('b3534a7a-cb00-4101-9bc0-3cb19a1fa03d','紙帳二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','荆王翠羽衾中夢，太尉銷金帳裏歌。',32,'全唐诗/poet.song.88000.json','["荆王翠羽衾中夢，太尉銷金帳裏歌。", "若以道人銀色界，雖無歡笑亦無魔。"]'),
('b9890ff8-cda2-4c0e-8609-6945b1d6c311','秦觀文生日詩三十韻','周紫芝','宋','宋诗','song-poetry','','[]','寶祚開蒼籙，炎精表赤符。',288,'全唐诗/poet.song.88000.json','["寶祚開蒼籙，炎精表赤符。", "乾坤歸聖統，廊廟得真儒。", "事借帷籌定，顛從漏刻扶。", "兵銷九節度，儀肅五單于。", "意與神明會，功知傳記無。", "公師隆化道，嗣相恊神謨。", "世業垂餘慶，天心究永圖。", "貂冠親日月，玉座接都俞。", "自可均調鼎，猶謙謝秉樞。", "槐庭何日見，繡袞幾時紆。", "大府連甍棟，翔鸞踵步趨。", "侏離將入賀，象寄盡交孚。", "光耀三台宿，喧騰百雉都。", "傳呼鳯尾諾，導從火城驅。", "隔坐恩由占，同朝禮固殊。", "位雖仍亞保，望久在中區。", "藝籍明經殿，文星照石渠。", "諸生咨典故，列辟奉規摹。", "往歲方平難，斯民稍避胡。", "大臣俱宿德，四海盡夷塗。", "効已知無敵，天應信不誣。", "他年各安堵，此日記垂弧。", "雲篆祈千載，霞漿賜百壺。", "中人傳詔旨，東閣擁金朱。"]'),
('cbdbd6a2-0a07-437b-8325-76c31ba15836','題陳大卿三徑堂','周紫芝','宋','宋诗','song-poetry','','[]','一身和影共婆娑，看盡人間兩鬢皤。',32,'全唐诗/poet.song.88000.json','["一身和影共婆娑，看盡人間兩鬢皤。", "要好只銷長閉戸，便開三徑已爲多。"]'),
('3c899f49-7e95-4992-a1bf-9e040de0e555','曉晴','周紫芝','宋','宋诗','song-poetry','','[]','曈曨曉色上簾旌，吹盡江頭滴雨聲。',64,'全唐诗/poet.song.88000.json','["曈曨曉色上簾旌，吹盡江頭滴雨聲。", "百歲一生常苦惱，三春幾日好晴明。", "從他落絮隨人去，但趁青山放脚行。", "尚有詩腸新鼓吹，滿攜樽酒聽黄鶯。"]'),
('84f3d5ed-723a-48c8-825b-416450e52c7c','楊得臣見和曉晴長句用韻奉酬  其一','周紫芝','宋','宋诗','song-poetry','','[]','西風獵獵轉紅旌，吹盡春霖點滴聲。',64,'全唐诗/poet.song.88000.json','["西風獵獵轉紅旌，吹盡春霖點滴聲。", "曉送楚雲歸隴去，夜看淮燒隔江明。", "舞狂恨我無長袖，句好從君得短行。", "擬爲新晴歌一曲，誰將此調付鶯鶯。"]'),
('59b3bb6d-b6a0-465e-a61e-a3df405e25b4','楊得臣見和曉晴長句用韻奉酬  其二','周紫芝','宋','宋诗','song-poetry','','[]','詩翁老去得雙旌，慣聽清漣夜雨聲。',64,'全唐诗/poet.song.88000.json','["詩翁老去得雙旌，慣聽清漣夜雨聲。", "水到潯陽心獨喜，雲開廬阜眼先明。", "落花已是春三月，飛蓋猶堪酒數行。", "寄語草元窗下客，忍令辜負曉啼鶯。"]'),
('a1c8fe61-5033-47dd-b81f-db11873e3aa6','楊得臣見和曉晴長句用韻奉酬  其三','周紫芝','宋','宋诗','song-poetry','','[]','歸心何事等搖旌，叔起能詩近有聲。',64,'全唐诗/poet.song.88000.json','["歸心何事等搖旌，叔起能詩近有聲。", "豈料從遊如夢寐，不知風雨過清明。", "拍浮我自堪娯老，矍鑠誰應更請行。", "此去定交君見許，爲歌伐木賦鳴鶯。"]'),
('142f2de6-d1c6-4ff8-9b53-ce137568872a','楊得臣見和曉晴長句用韻奉酬  其四','周紫芝','宋','宋诗','song-poetry','','[]','上最初無善可旌，歸來和雨聽江聲。',64,'全唐诗/poet.song.88000.json','["上最初無善可旌，歸來和雨聽江聲。", "自憐老眼昏花甚，乞得晴窗夕照明。", "蓮葉繫舟驚水滿，魚須拄頬看雲行。", "君能著屐時相過，猶有殘春一雨鶯。"]'),
('9fd9df28-d063-4d90-ab7d-efce6a2feebb','楊得臣見和曉晴長句用韻奉酬  其五','周紫芝','宋','宋诗','song-poetry','','[]','何處籠街引旆旌，老翁高臥聽雞聲。',64,'全唐诗/poet.song.88000.json','["何處籠街引旆旌，老翁高臥聽雞聲。", "看花强起尋韋曲，謁帝空思入大明。", "有興時彈流水調，無情懶賦麗人行。", "青春别我誰爲伴，只有能歌綠樹鶯。"]'),
('c28be682-c95d-41b9-aa15-ed60e5f6aa91','楊得臣見和曉晴長句用韻奉酬  其六','周紫芝','宋','宋诗','song-poetry','','[]','隨緣南北似風旌，飽聽波濤處處聲。',64,'全唐诗/poet.song.88000.json','["隨緣南北似風旌，飽聽波濤處處聲。", "今日園花風裏盡，到時江月雪中明。", "雖無格磔鈎輈語，尚有媻姗勃窣行。", "誰餞東君沸歌管，琵琶絃上囀春鶯。"]'),
('fde33076-3792-481d-b100-9494406b3868','奉酬晁强伯見和曉晴長句','周紫芝','宋','宋诗','song-poetry','','[]','元祐文華掲綵旌，金沙别乘有家聲。',64,'全唐诗/poet.song.88000.json','["元祐文華掲綵旌，金沙别乘有家聲。", "天教雲彩歸何處，詩共晴光欲鬬明。", "已閣山前山後雨，尚堪水北水南行。", "不應文石班中客，肯伴韋郎賦曉鶯。"]'),
('4e2290ac-1f8a-4c2a-982f-e8f8843f5059','奉酬晁元采三和前韻','周紫芝','宋','宋诗','song-poetry','','[]','見賢殊未駐干旌，叩戸先聞剝啄聲。',64,'全唐诗/poet.song.88000.json','["見賢殊未駐干旌，叩戸先聞剝啄聲。", "春去鳥啼千樹暗，雨餘花落一窗明。", "新詩已得前人法，病足惟追逸驥行。", "何日長安君得意，著鞭閑聽上林鶯。"]'),
('ae5a67e2-102c-43af-bf71-c98f615737b9','曹度堅待制罷帥成都歸江南以川中唐人六十家詩見遺作長句爲謝','周紫芝','宋','宋诗','song-poetry','','[]','三月瞿塘峻江水，萬里歸來蜀都帥。',176,'全唐诗/poet.song.88000.json','["三月瞿塘峻江水，萬里歸來蜀都帥。", "盡收五十四州書，畫舸連檣當歌吹。", "有唐文士幾千人，文不逮漢詩則異。", "開元天寶光熖長，長慶元和殿唐季。", "化入寶奩脂澤中，亦有風滿有能事。", "六十餘家三百年，天遣遺風未全墜。", "青衫昔日同舍郎，老傍人間百無意。", "將焚筆硯技輒癢，未說風騷心復醉。", "公堂許我能篇章，遺以斯文慰憔悴。", "徒令後學羞捧心，誰與前賢共聯轡。", "爲公隱几抱殘編，聊伴青奴問朝霽。"]'),
('8e84b0eb-e3d0-4570-bca8-f7f1ebd1f8d2','雨中讀韓致光詩偶池上鹿葱盛開因效其體  其一','周紫芝','宋','宋诗','song-poetry','','[]','曲欄干外水平階，池上朱扉繞翠苔。',32,'全唐诗/poet.song.88000.json','["曲欄干外水平階，池上朱扉繞翠苔。", "燕子飛來人不到，鹿葱花在雨中開。"]'),
('4709e2d4-0c36-4e5e-a3bd-3b5fbcb8a7ea','雨中讀韓致光詩偶池上鹿葱盛開因效其體  其二','周紫芝','宋','宋诗','song-poetry','','[]','雕盡朱顔白盡頭，種花本爲欲忘憂。',32,'全唐诗/poet.song.88000.json','["雕盡朱顔白盡頭，種花本爲欲忘憂。", "誰知花上風和雨，添得周郎一段愁。"]'),
('cc400077-20c3-4d09-94ea-08a142bc55ab','天申節日謁告不赴贊祝擬王仲初  其一','周紫芝','宋','宋诗','song-poetry','','[]','小臣拜祝奉千秋，敕賜宮花憶滿頭。',32,'全唐诗/poet.song.88000.json','["小臣拜祝奉千秋，敕賜宮花憶滿頭。", "今日江邊揩病眼，五雲常望帝王州。"]'),
('09b66fd0-f346-40d2-a48e-59e0838e2e52','天申節日謁告不赴贊祝擬王仲初  其二','周紫芝','宋','宋诗','song-poetry','','[]','吾皇一出萬方春，自合傾心祝至尊。',32,'全唐诗/poet.song.88000.json','["吾皇一出萬方春，自合傾心祝至尊。", "乞得養痾閑地祿，此生尺寸是君恩。"]'),
('95c3deef-427a-4817-b73c-aa626b2f45e6','題畫蛺蝶小扇','周紫芝','宋','宋诗','song-poetry','','[]','花裏飛來粉翅疏，香羅扇上得形模。',32,'全唐诗/poet.song.88000.json','["花裏飛來粉翅疏，香羅扇上得形模。", "只緣容易無人愛，但說滕王蛺蝶圖。"]'),
('84734164-15f9-47cf-b7b4-6f1cec0dbf4b','題小扇','周紫芝','宋','宋诗','song-poetry','','[]','小扇題詩墨色新，碧紗囊剪藕絲勻。',32,'全唐诗/poet.song.88000.json','["小扇題詩墨色新，碧紗囊剪藕絲勻。", "月團常在纖纖手，不用流蘇拂暗塵。"]'),
('68692296-aa18-4033-abe5-7b8ea2bf42cc','池蓮初著數花','周紫芝','宋','宋诗','song-poetry','','[]','數枝臨水見纖娥，新採紅藍染襪羅。',32,'全唐诗/poet.song.88000.json','["數枝臨水見纖娥，新採紅藍染襪羅。", "傳語薫風莫吹去，且容留眼看微波。"]'),
('85a420bd-6285-4b7a-90a7-76eb0b547daa','富水軍治有巨澤往歲荷花滿湖郡守歲取荷葉可貿百千一日曝之湖濱大風吹卷飛數十里頃刻俱盡又採葉者頗以爲苦瀝膏油以毒之逮僕至閱兩歲無一花今年結茅於此穴小池植數十根而花已可觀因感前事遂書之','周紫芝','宋','宋诗','song-poetry','','[]','湖邊老守湖是家，湖光十里蒙寒沙。',64,'全唐诗/poet.song.88000.json','["湖邊老守湖是家，湖光十里蒙寒沙。", "我來不見花如錦，但聞荷葉飛天涯。", "小池今無十許步，晚雨亦開三數花。", "人生樂事無多少，可意應須隨分了。"]'),
('54e952de-3fb9-4ace-b724-893e3779254d','題吕伸友寓安堂','周紫芝','宋','宋诗','song-poetry','','[]','事非昨夢本來空，正在黄粱一熟中。',64,'全唐诗/poet.song.88000.json','["事非昨夢本來空，正在黄粱一熟中。", "到處隨緣是安樂，人生何地有窮通。", "飛衣不對東風舞，霜葉空憐醉面紅。", "只恐他年終未免，傳家重說小申公。"]'),
('a5a710e1-2623-44f4-8044-d031a84da8df','剪松毛小栅以詩落成','周紫芝','宋','宋诗','song-poetry','','[]','東堂坐甑遭炊蒸，西簷烈日方騰騰。',144,'全唐诗/poet.song.88000.json','["東堂坐甑遭炊蒸，西簷烈日方騰騰。", "炎官張傘火漸熾，烏豕渡河雲不興。", "五官大夫有遺種，十八公自分雲仍。", "羲和揮戈不可却，郢匠剪毛歸作棚。", "南風颯瑟出餘韻，怒龍奮迅蒼髯昇。", "香來鼻觀過一雨，便恐冰麝終難勝。", "天公割此一席地，付與老翁來曲肱。", "何時快著短齒屐，信手自把南山藤。", "臥聽松風滿山雨，去作水邊巖下僧。"]'),
('410fda62-cae6-4a0e-890e-b418ed8167da','五月二十四日晚雨忽晴浴罷獨臥池亭雲峰奇峭既夕方散','周紫芝','宋','宋诗','song-poetry','','[]','長虹截天雨初斷，孤日翻光上銀漢。',160,'全唐诗/poet.song.88000.json','["長虹截天雨初斷，孤日翻光上銀漢。", "忽從海底出三山，就中蓬萊正奇觀。", "黄金塗闕射日光，白玉飛欄入天半。", "青童舞女各媻姗，手執雲幢影凌亂。", "想得神清洞府君，應榜春皇侍香案。", "群飛白鶴徒爾爲，化作蒼狗何勞看。", "神仙出沒不久長，碧落天宮豈容玩。", "荆王曉夢只須臾，神女乘鸞逐雲散。", "人間幻化無不爾，空復欷歔一長嘆。", "老人假寐忽舉頭，但見明星光有爛。"]'),
('ea1e670b-f43d-4c2e-b787-90f627e52ee4','五月憫雨頗聞饑民弄兵於嚴衢兩州間三十韻','周紫芝','宋','宋诗','song-poetry','','[]','長天望油雲，槁黍待甘霔。',288,'全唐诗/poet.song.88000.json','["長天望油雲，槁黍待甘霔。", "一雨有豐凶，死生分旦暮。", "頗聞兩州民，巖谷多嘯聚。", "有司幸眼前，白對急追捕。", "斯民如嬰兒，慈母仰調護。", "豈容使之饑，而反貽以怒。", "救饑當未然，爲食須早具。", "不雨三月餘，開口久待哺。", "岳牧事遨游，傲聣曾莫顧。", "遂令出偏師，往往勤遠慮。", "人亦甚畏死，階亂豈無故。", "漢有大司農，爲國最知務。", "誰知部使者，出納反堅固。", "輸金買朝糧，僅得鳥一嗉。", "尚爾吝弗予，民隱獨何愬。", "幾何不爲盜，悔過苦無路。", "富兒家多金，封財亦良裕。", "積金謀子錢，切骨被疽蠧。", "閉糶不肯售，叩門如蟻附。", "忿氣生一時，萬死有不懼。", "政坐守宰癡，申令苦不素。", "有時出萬斛，官爲復常賦。", "大或旌義閭，小或賜朝酺。", "民情非木石，豈不遵勸諭。"]'),
('6443a97d-7836-4c26-be9a-2a8475f7d61d','祁居之見過僕出未歸明日作二詩爲謝  其一','周紫芝','宋','宋诗','song-poetry','','[]','家近平湖草樹青，幾年於此寄高情。',32,'全唐诗/poet.song.88000.json','["家近平湖草樹青，幾年於此寄高情。", "有時亦爲衰翁出，誰道龐公不入城。"]'),
('54a09d02-a54d-4796-8116-ce282954bdc1','祁居之見過僕出未歸明日作二詩爲謝  其二','周紫芝','宋','宋诗','song-poetry','','[]','不見前賢畏後生，一聞君語爲心傾。',32,'全唐诗/poet.song.88000.json','["不見前賢畏後生，一聞君語爲心傾。", "何時却約高軒過，重聽門人說老成。"]'),
('ce830e85-c16d-4547-91be-04bba3716823','雨後極涼簡竹坡四君子','周紫芝','宋','宋诗','song-poetry','','[]','江城夏六月，大旱草木黄。',180,'全唐诗/poet.song.88000.json','["江城夏六月，大旱草木黄。", "稽首文殊師，駕言天池陽。", "爲乞一斗水，普救千里傷。", "微雲生寶髻，法雨遍大荒。", "霈爲一尺霖，化作三日涼。", "老人不耐暑，內熱煎中腸。", "吹以碧落風，灌以丹露漿。", "我有方丈室，彩榜名妙香。", "呼我四君子，聊與之徜徉。", "朝憑共烏几，夜宿同方床。", "永結無情歡，此樂殊未央。", "榮瘁不改觀，死生知有常。", "豈不賢俗子，與世隨低昂。", "翻手覆手間，此道寧久長。", "願我四玉友，永言不相忘。"]'),
('4c9f08c7-0a34-4641-827b-b90db8722afb','七夕','周紫芝','宋','宋诗','song-poetry','','[]','七夕相逢說牛女，晉魏以來傳樂府。',176,'全唐诗/poet.song.88000.json','["七夕相逢說牛女，晉魏以來傳樂府。", "金冠玉帔照靈河，不見此身聞此語。", "何如當日兩神仙，空中一别五千年。", "五龍駕車各異色，萬里乘雲來九天。", "麻姑女子十八九，青絲作髻爪爲手。", "擗麟薦酒進行厨，撒米成沙只回肘。", "爲言東海將揚塵，蓬萊水淺無升斗。", "蔡經得道心尚凡，背痒自速方平鞭。", "上界真仙足官府，牛女之說真茫然。", "綵樓對月誰家倩，更就天孫乞針線。", "何不苦學麻姑仙，養取紅顔如玉爛。"]'),
('6ddf0ef8-13e6-425d-a042-391bca4e7c5e','僕所居蓋濓溪先生之故基也有井清甘而寒先生嘗以比谷簾今爲路人所汲余嘗爲作亭號濂溪泉而爲之銘今未暇也','周紫芝','宋','宋诗','song-poetry','','[]','山下清泉古甃寒，百年誰爲發幽潛。',32,'全唐诗/poet.song.88000.json','["山下清泉古甃寒，百年誰爲發幽潛。", "可憐昔日供茶鼎，曾與先生當谷簾。"]'),
('da06b342-355d-4b98-bd05-12783eea257c','夢行西湖梅花下  其一','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久把西湖作故鄉，至今清夢到湖傍。',32,'全唐诗/poet.song.88000.json','["久把西湖作故鄉，至今清夢到湖傍。", "分明昨夜經行處，一色梅花十里香。"]'),
('fc7b4269-0bb1-49d3-806a-905cdc4b91da','夢行西湖梅花下  其二','周紫芝','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春雲收盡忽斜陽，夢裏梅花带雨香。',32,'全唐诗/poet.song.88000.json','["春雲收盡忽斜陽，夢裏梅花带雨香。", "却上小舟誰是伴，回頭只有櫂船郎。"]'),
('4f791d47-de21-4239-9cca-7d2fbc9991b2','食芡有感二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','雞頭子熟客新嘗，流落空嗟各異鄉。',32,'全唐诗/poet.song.88000.json','["雞頭子熟客新嘗，流落空嗟各異鄉。", "紅線綠荷香裏夢，十年燈火記錢塘。"]'),
('b4291d0a-9b0d-4b3b-9db0-520a80dbca2b','食芡有感二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','翻香引睡一胡床，剝芡尋詩度日長。',32,'全唐诗/poet.song.88000.json','["翻香引睡一胡床，剝芡尋詩度日長。", "若得長閑了無事，人生如此亦何妨。"]'),
('f14ac549-af62-43ff-a6d5-6b1409be6395','書祁居之家小閣','周紫芝','宋','宋诗','song-poetry','','[]','李渤築長堤，三千五百尺。',144,'全唐诗/poet.song.88000.json','["李渤築長堤，三千五百尺。", "爲我絕平湖，遂識柴桑宅。", "高人淡無營，小室自生白。", "倚壁横兩床，並坐可四客。", "時聞蒼蠅館，不厭蝸牛馘。", "誰知湖尾山，抱負縈水石。", "繁陰庇芳姿，收拾在几席。", "天地本高明，胸次有寛窄。", "固應世外境，頗與俗眼隔。", "我欲爲君留，雨意良霂霢。", "對眠分小窗，夜語要劇會。", "須臾攜被来，更待風雨夕。"]'),
('a5bd97da-941d-4081-8500-1e34abc85dfb','次韻都倅題趙菘老竹澗聽雨亭','周紫芝','宋','宋诗','song-poetry','','[]','西來倦客厭飄零，一見宗枝眼爲青。',64,'全唐诗/poet.song.88000.json','["西來倦客厭飄零，一見宗枝眼爲青。", "世事絕知塵外少，雨聲更在竹間聽。", "鏗如曲奏江邊瑟，清伴風鳴塔上鈴。", "想得荆州都别駕，詩成幽夢曉初醒。"]'),
('75d2a8c0-617c-4ae7-961c-0d814900136a','曉雨用都倅韻','周紫芝','宋','宋诗','song-poetry','','[]','亂敲簷瓦曉初零，聲入孤燈影半青。',64,'全唐诗/poet.song.88000.json','["亂敲簷瓦曉初零，聲入孤燈影半青。", "枕上有詩因雨得，窗間無客對床聽。", "翠光洗出山千疊，金色添成菊萬鈴。", "收取新涼歸酒盞，莫將雙眼爲愁醒。"]'),
('cc2a7436-b308-4f51-8c78-b0e273c160cf','夜雨再用都倅韻','周紫芝','宋','宋诗','song-poetry','','[]','半世常愁夜雨零，斷腸無復鬢絲青。',64,'全唐诗/poet.song.88000.json','["半世常愁夜雨零，斷腸無復鬢絲青。", "又將船艦舟中夢，移入梧桐葉上聽。", "涼吹漸欣歸枕簟，好詩那更似鸞鈴。", "欲知多少江湖興，病眼無眠徹曉醒。"]'),
('9129ab3d-d363-4cb4-85d1-fe3bbf812e47','夜聞驟雨枕上二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','星斗闌干雲翳銷，黄昏猶未有微飈。',32,'全唐诗/poet.song.88000.json','["星斗闌干雲翳銷，黄昏猶未有微飈。", "誰將枕上三更雨，捲作錢塘八月潮。"]'),
('cdbcbdb9-0e88-4f69-bfee-32313f9d3841','夜聞驟雨枕上二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','山南未作小徘徊，坐想奔流萬壑雷。',32,'全唐诗/poet.song.88000.json','["山南未作小徘徊，坐想奔流萬壑雷。", "三峽橋邊風雨樣，先將此讖入詩來。"]'),
('0955b541-54b2-479e-ac18-b899de78e26a','季夏極暑正晝草木俱萎獨吾坡上數君子玉立蒼然傲睨自得豈杜少陵所謂脩竹不受暑者乎','周紫芝','宋','宋诗','song-poetry','','[]','烈日當正晝，長天無一雲。',144,'全唐诗/poet.song.88000.json','["烈日當正晝，長天無一雲。", "草木失顔色，葳蕤困燒焚。", "陽春始用事，庶類争芳芬。", "小草最無名，羅生費鋤耘。", "凡花頗矜持，隨風弄餘薰。", "一朝值炎酷，爾輩徒紛紛。", "蒼蒼不改操，惟我坡上君。", "脩莖粲碧玉，茂植歌屯雲。", "有如獨醒人，不受麴蘖醺。", "如彼至人者，自與世俗分。", "入火且不熱，况乃逢朝昕。", "小人柔弱姿，難與君子群。"]'),
('74f7ea89-5612-490d-8be3-4b7c090fab9f','送吳甥歸秣陵','周紫芝','宋','宋诗','song-poetry','','[]','人生良苦不自知，三折肱乃成良醫。',240,'全唐诗/poet.song.88000.json','["人生良苦不自知，三折肱乃成良醫。", "老夫年少不知此，請爲甥也今言之。", "平時頗喜詩有味，晚乃竟坐寒無衣。", "人言詩成本無用，小技止可持自怡。", "一聞斯言寢不寐，盡欲棄去無孑遺。", "人皆見之唾不顧，汝乃掇拾歸何爲。", "前年行都子訪我，值我偶得南州麾。", "汝之老母我伯姊，何爲棄養行相隨。", "極知饑寒子良苦，况乃窀穸歸無期。", "翁今兒孫漸滿屋，子六八女肩相差。", "歸嚢羞澁止有此，世事乃爾真成癡。", "渭陽老將如病驥，肉瘦到骨那能肥。", "枯萁成豆不足較，甥也幸有驊騮姿。", "丈夫豈合長貧賤，慎勿瑣細含酸悲。", "天寒霜勁路如掌，矯首一望秋風嘶。"]'),
('50c476bc-75cd-4bfb-8f1a-d1ee51890414','小兒栞歸自宛陵喜甚成詩三十韻','周紫芝','宋','宋诗','song-poetry','','[]','吾家自曾高，善積豈一日。',288,'全唐诗/poet.song.88000.json','["吾家自曾高，善積豈一日。", "爾祖工辭章，論議抱經術。", "我亦學弓冶，少小弄文筆。", "汝兄今有兒，束髮行授室。", "義方稍加訓，書種恐未失。", "汝亦千里駒，似有趻踔質。", "頃爲國子弟，兩戰一敗黜。", "猶復勝端舒，不識六與七。", "胡爲久别離，嘉月六換律。", "去時春氣温，飛燕如點漆。", "只今秋風高，露草鳴蟋蟀。", "老眼望千里，懷抱難盡述。", "有時坐如癡，經月髮不櫛。", "酒酸或忘飲，客至亦懶出。", "汝書江南來，歸計似可必。", "翁也望汝懷，疑有后皇橘。", "奴婢喜欲顛，精糳治黍秫。", "辛勤釀斗酒，待汝解憂慄。", "訪舊說鄉閭，呼兒共梨栗。", "念汝童稚時，頃刻不去膝。", "况今待汝來，時序恐凛凓。", "竹輿聽咿啞，雲嶺走崒嵂。", "吾無千金産，遺汝使汝逸。", "惟有骩骳文，待汝成卷帙。"]'),
('b24e9f27-f982-49ce-a9c4-c072a8b6d650','次韻郭元壽泊舟琵琶亭下夜聞吹簫','周紫芝','宋','宋诗','song-poetry','','[]','舟在琵琶舊日亭，玉簫更弄月微明。',32,'全唐诗/poet.song.88000.json','["舟在琵琶舊日亭，玉簫更弄月微明。", "湓江故事新歌曲，便是香山此夜情。"]'),
('4e45cf40-c469-4474-97da-590e3408e9e6','次韻元壽見贈','周紫芝','宋','宋诗','song-poetry','','[]','畫簷横著小闌干，看盡西來最好山。',64,'全唐诗/poet.song.88000.json','["畫簷横著小闌干，看盡西來最好山。", "带雨楚江依約處，隔烟淮樹有無間。", "已煩造物分幽趣，合就餘年了燕閑。", "借使眼前無此妙，可能不似鳥知還。"]'),
('cc7c8086-0131-4624-9d98-6f46d423803b','送元壽歸華亭','周紫芝','宋','宋诗','song-poetry','','[]','念昔得左魚，相逢各萍梗。',240,'全唐诗/poet.song.88000.json','["念昔得左魚，相逢各萍梗。", "我方事米鹽，君亦厭簿領。", "豈曰吾無徒，其實但弔影。", "殷勤共杯酌，邂逅得俄頃。", "坐中老於菟，神色甚凶獷。", "一軀垂豕腹，兩眼張牛猛。", "酒行殊未闌，幽事頗遭梗。", "人生聚散多，快意復難逞。", "只今幾何時，我居已深屏。", "君亦乘歸舟，久别勞問省。", "長言出新詩，小酌共晝永。", "平生發硎刃，妙割無肯綮。", "豈容金九傍，臥著函牛鼎。", "廟堂重汲引，盡取無短綆。", "會當從隗始，豈復雜噲等。", "願君飛尺書，早發慰晚景。", "功名要激昂，人事勿暖冷。", "爲我謝黄郎，無路勤造請。", "熟醉倘有味，高臥不須醒。", "仍煩織筠笯，丹砂寄圓頂。"]'),
('1594a18e-dc88-4389-be15-1f5551eed662','都倅壽詩二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','讀盡人間未見書，幾曾回眼到園蔬。',64,'全唐诗/poet.song.88000.json','["讀盡人間未見書，幾曾回眼到園蔬。", "文章筆下飛雲錦，今古胸中著石渠。", "萬事要詢胡伯始，九重應問馬相如。", "明年我欲爲公壽，想得追鋒已賜車。"]'),
('ef0a5aa6-d833-40cf-bec7-ad07f7088ad9','都倅壽詩二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','文石班中侍從聯，如公真合在甘泉。',64,'全唐诗/poet.song.88000.json','["文石班中侍從聯，如公真合在甘泉。", "何由魏闕催歸詔，未到荆州去路邊。", "分外寡求應是福，静中有壽不須仙。", "滿斟玉色長生酒，爛醉廬峰五老前。"]'),
('d9f87c80-a7ef-400f-83f9-fe4a942e78ab','晚眺','周紫芝','宋','宋诗','song-poetry','','[]','望極應千里，人家自一村。',48,'全唐诗/poet.song.88000.json','["望極應千里，人家自一村。", "客帆何處落，鄰碓隔煙聞。", "山自秋來瘦，江從雨後渾。", "平生幽獨意，爲客却銷魂。"]'),
('9b3b8b0b-51f5-43ef-a11a-b79417ca917c','九江木犀甚富而香亦奇絕江東所無也','周紫芝','宋','宋诗','song-poetry','','[]','自從春去憶疏梅，直到秋來數木犀。',64,'全唐诗/poet.song.88000.json','["自從春去憶疏梅，直到秋來數木犀。", "不隔幽香微雨細，偏宜小樹夕陽低。", "無詩可說難言態，有酒應須著意攜。", "家在東江苦無此，莫嫌爲客在江西。"]'),
('d11f7f68-47bc-4846-8fc0-d366539980a8','再賦木犀','周紫芝','宋','宋诗','song-poetry','','[]','新詩幾欲賦幽姿，才淺真慚禿角犀。',64,'全唐诗/poet.song.88000.json','["新詩幾欲賦幽姿，才淺真慚禿角犀。", "未可便教金粟盡，直須看到玉蟾低。", "風吹香去天誰管，花趁人來我自攜。", "不對此郎時一醉，空令墓上掲征西。"]'),
('a2c3738a-54b6-48ed-a85a-15ff0b5bd1b2','再賦木犀','周紫芝','宋','宋诗','song-poetry','','[]','尋香剪得耐寒枝，不羨腰圍寶带犀。',64,'全唐诗/poet.song.88000.json','["尋香剪得耐寒枝，不羨腰圍寶带犀。", "塘桂自應同臭味，巖花未可較高低。", "秋風易老空成恨，佳客無人莫漫攜。", "挽取芳條供燕坐，絕勝騎馬號安西。"]'),
('bb1ce604-1e9e-41f7-a5c7-e8f567468221','謝祁居之惠桃竹杖','周紫芝','宋','宋诗','song-poetry','','[]','老翁年少白如玉，初學裹頭雙鬢綠。',176,'全唐诗/poet.song.88000.json','["老翁年少白如玉，初學裹頭雙鬢綠。", "一心走覓梨與栗，兩脚登山健如鹿。", "中年脚力驚早衰，騰踔安得如兒時。", "挾弓持滿走避賊，尚與箭鋒争疾遲。", "如今老矣那忍說，七十上身頭似雪。", "年來脚力何所似，鈍如罷牛跛如鼈。", "先生强欲相扶持，贈我江心桃竹枝。", "竹夫人癡不解語，木上座肯行相隨。", "况乃柴焰如削鐡，四十九層排玉節。", "天公與我山作堂，木落霜空秋九月。", "與君共看南山雲，安可一日無此君。"]'),
('ca50745f-0990-46c3-a3bd-ec0cee09b41f','十月十七日大風約客登虎渡亭觀浪人言今日下水風不可往也戲作此篇','周紫芝','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江水自光搖空，陽侯欲與風争雄。',128,'全唐诗/poet.song.88000.json','["長江水自光搖空，陽侯欲與風争雄。", "濤頭不受水犀弩，鯨波欲卷馮夷宮。", "徑須便入虎溪口，净洗平吞雲夢胸。", "人言上水得風浪，下水得風終少功。", "平生萬事盡難偶，政要東風渠不東。", "江邊一嘆良細事，而亦齟齬煩天公。", "兒時望事到白首，事不如意十八九。", "不如快飲風流泉，夜看青山銜北斗。"]'),
('77fd84e2-6736-4660-ad2d-57aeffb87477','送楊師醇赴竟陵法官','周紫芝','宋','宋诗','song-poetry','','[]','平昔交遊未易論，世間誰復似君真。',64,'全唐诗/poet.song.88000.json','["平昔交遊未易論，世間誰復似君真。", "五花判事元無意，三尺從官政爲貧。", "酒賤頗宜呼客飲，詩成莫忘寄書頻。", "使君若向新堂老，今是開山第一人。"]'),
('131bb08d-07ae-4dae-a55d-c1dc1758a360','次韻楊師古留别','周紫芝','宋','宋诗','song-poetry','','[]','寄食客鄉遠，誰人肯見過。',48,'全唐诗/poet.song.88000.json','["寄食客鄉遠，誰人肯見過。", "江山來往數，蘭玉弟兄多。", "可恨澆愁酒，能摧轉棹波。", "幾時書到眼，此别意如何。"]'),
('6ef91d8a-ee43-40dd-84ef-6298dc060910','晚思','周紫芝','宋','宋诗','song-poetry','','[]','灘沙露尾江水乾，江洪束峽江流湍。',64,'全唐诗/poet.song.88000.json','["灘沙露尾江水乾，江洪束峽江流湍。", "千山落木風轉急，萬里飛鴻天更寒。", "暮雲政擁蒼玉玦，落日忽下丹砂盤。", "他鄉久客去未得，悠然東望心悲酸。"]'),
('b424c848-8e12-494b-9246-20874fe714ec','二妙堂望九十九峰雪','周紫芝','宋','宋诗','song-poetry','','[]','北風卷地天漫漫，長空下舞十翔鸞。',144,'全唐诗/poet.song.88000.json','["北風卷地天漫漫，長空下舞十翔鸞。", "天公吹絮作飛雪，大匠琢玉成群山。", "群山南來西北折，走如連環斷如玦。", "接天朝同一色雲，映水夜伴中宵月。", "誰知三千大千界，有此九十九峰雪。", "人間未見固難名，天上有之那可說。", "老夫才盡晚益繆，筆力應無此雄傑。", "徐煕著色豈可畫，大年小景不足悅。", "誰當貌此一段奇，留與高堂洗炎熱。"]'),
('b4ebfcfe-59a0-4e9c-9d32-253eb0617590','雪後步至江亭','周紫芝','宋','宋诗','song-poetry','','[]','老人攜家無窟穴，晚得一邱藏曲折。',144,'全唐诗/poet.song.88000.json','["老人攜家無窟穴，晚得一邱藏曲折。", "今朝日出天色佳，拄杖來看山頂雪。", "青山疊疊幾十峰，桃竹班班三百節。", "山晴顔色看轉好，老健脚力殊未竭。", "出門暮色尚餘霞，步到江亭已生月。", "歸來附火却關門，茶熟詩成意良悅。", "客有勸我勿作詩，奈此江山兩奇絕。", "捫鬚仰面看屋梁，心自知之口無說。", "天將此段付詩人，世間那有閑風月。"]'),
('43c220ee-eac5-44ac-9a98-2a45e7c9e093','時宰生日詩五首  其一','周紫芝','宋','宋诗','song-poetry','','[]','皇天産萬彚，瑣碎不足名。',120,'全唐诗/poet.song.88000.json','["皇天産萬彚，瑣碎不足名。", "青黄百草中，幻作芝九莖。", "惡鳥不敢語，紫鳯丹霄鳴。", "尤物倘或出，四海稱隆平。", "太史上圖牒，后夔奏韺䪫。", "豈知人中瑞，千載乃一生。", "神高下蒼籙，昴宿扶漢氓。", "天亦甚愛惜，殷勤遺黎煢。", "聖主答天意，一酌尊老成。", "願公於斯年，擁佩朝玉京。"]'),
('23189463-3cac-4d3b-96c5-18bf48804c51','時宰生日詩五首  其二','周紫芝','宋','宋诗','song-poetry','','[]','歷世由羲軒，百相標簡牘。',120,'全唐诗/poet.song.88000.json','["歷世由羲軒，百相標簡牘。", "操術難具論，大抵一言足。", "所尚必仁恩，所禁在殺戮。", "臯陶期無刑，四海自肅穆。", "敷德益所贊，坐使有苖服。", "西都郅支功，蕭相不肯錄。", "有唐未開邊，宋璟乃當軸。", "向來多謬悠，紛紛空食肉。", "一言俞玉音，萬竈休野宿。", "不戰乃爲功，休兵豈無福。"]'),
('99c51b75-dcf3-4036-8dec-bd5221fe4940','時宰生日詩五首  其三','周紫芝','宋','宋诗','song-poetry','','[]','維國有六職，論道先三公。',120,'全唐诗/poet.song.88000.json','["維國有六職，論道先三公。", "巍峨獨姬旦，焜燿傳無窮。", "子房號賢傑，妙算無遺蹤。", "謂可爲帝師，授書圯上翁。", "周公迓太平，道與時適隆。", "張侯策雖奇，未解銷兵戎。", "太師回狂瀾，僅在談笑中。", "德業與智謀，誰能與公同。", "疇人亦何知，但說前無功。", "誰知公一德，自與天潛通。"]'),
('0f466fb0-d5da-4369-a40f-e7d8c84fcb4d','時宰生日詩五首  其四','周紫芝','宋','宋诗','song-poetry','','[]','種木當培根，疏流必深源。',120,'全唐诗/poet.song.88000.json','["種木當培根，疏流必深源。", "嘗聞活萬夫，報在子與孫。", "只今父子懿，同拱羲皇尊。", "文方班馬富，業與臯夔倫。", "奕奕兩貂蟬，煌煌一朱門。", "聖道家所傳，蘭樹俱有聞。", "韋氏守一經，事業不足論。", "金張誇富貴，盛德無遺芬。", "父師固難量，有功在元元。", "爲公祝遐壽，千載同風雲。"]'),
('4fd1e216-5d34-436f-997e-84a579d29d6b','時宰生日詩五首  其五','周紫芝','宋','宋诗','song-poetry','','[]','魯人用真儒，齊田歸鄆讙。',120,'全唐诗/poet.song.88000.json','["魯人用真儒，齊田歸鄆讙。", "當時號聖相，晏語甚眧煥。", "往者遭承平，燕安嗟久玩。", "三綱既已解，四海兵幾半。", "天戈不忍揮，胡騎忽雲散。", "功高陋古今，事易止朝旦。", "方知今相聖，難復與魯辨。", "世罕班馬流，無言可稱贊。", "願公守成勳，寶歷慶千萬。", "蕪詞不足錄，至意良可獻。"]'),
('85c0a5ff-6f9e-4c92-b430-f3357f8bf2bc','客有以僕託病謝客者甲戌除夜作','周紫芝','宋','宋诗','song-poetry','','[]','夢中七十四番春，謝客明年懶見人。',64,'全唐诗/poet.song.88000.json','["夢中七十四番春，謝客明年懶見人。", "已是天公憐我老，苦無官長怕誰嗔。", "臘隨殘漏聲俱盡，鬢共疏梅色鬬新。", "招取雲山來一笑，竹坡猶有此閑身。"]'),
('cd9f782d-622b-4028-b176-b1db87c30dbe','祁居之作亭山間名之以宜謂四時之皆宜也其後寓安有亭未名居之使榜以似宜寓安雖從之而其詩乃有未必輸公之語氣似未平也寓安欲余賦詩因爲解紛且以見二公相忘之意','周紫芝','宋','宋诗','song-poetry','','[]','先生有亭宜四時，乃使寓安名似宜。',128,'全唐诗/poet.song.88000.json','["先生有亭宜四時，乃使寓安名似宜。", "寓安口諾心未肯，更欲老翁聊決疑。", "老翁百事盡稱好，一生和羅常作椎。", "况是宜亭頗静秀，聞說似宜尤復奇。", "兩山相望俱不惡，二老較勝知何爲。", "會當扶病躡雙屐，攜酒君家爲君醉。", "不知春事已過眼，但見此亭俱可意。", "且對青山食蛤蜊，一笑誰能知許事。"]'),
('509d5d54-0aba-4775-842f-59e2ad1d1213','晚霽效韋蘇州','周紫芝','宋','宋诗','song-poetry','','[]','重霧翳曉日，相持決陰晴。',132,'全唐诗/poet.song.88000.json','["重霧翳曉日，相持決陰晴。", "須臾忽戰勝，日杲中天明。", "積雪壓竹腰，欲舉如垂旌。", "冰凌既融液，意氣還峥嶸。", "花木手新植，未可分死生。", "庶幾僵仆根，可與微陽争。", "况乃田畝間，春事亦漸營。", "新綠染麰麥，餘甘歸竹萌。", "飽食遂可料，聊助春山行。", "一晴亦細可，繫我憂喜情。", "我詩不浪作，有詩君勿輕。"]'),
('032a3942-2027-4488-94a9-923bd7d3d10d','寄題章漢直中虚堂','周紫芝','宋','宋诗','song-poetry','','[]','谷以虚而應，樂以虚而出。',144,'全唐诗/poet.song.88000.json','["谷以虚而應，樂以虚而出。", "婦姑時勃蹊，作室坐自窒。", "天地猶槖籥，用固不能屈。", "學而不見道，方寸等暗室。", "誰知道集虛，通一萬事畢。", "推此以遊世，於道乃其一。", "異哉子章子，妙悟造理窟。", "何止學美身，虛静了不汩。", "願君師心齋，守此能勿失。", "室以虛生白，水以止鑑物。", "此意似太漫，未免遭罵詘。", "我亦取斯言，聊用自湔拂。"]'),
('1027c98f-02b8-4c0b-b1ab-655e2b410052','徽宗皇帝挽詞二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','治格興王日，功垂定鼎年。',48,'全唐诗/poet.song.88000.json','["治格興王日，功垂定鼎年。", "重新周制度，盡有漢山川。", "寶墨星辰爛，皇猷典誥傳。", "小臣回老眼，垂泣望雲天。"]'),
('a2c48935-d783-43a9-9eb8-d584cc7bfecf','徽宗皇帝挽詞二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','主器歸儲嗣，神堯意獨高。',48,'全唐诗/poet.song.88000.json','["主器歸儲嗣，神堯意獨高。", "帝方遊赤水，人已抱烏號。", "萬國瞻雙闕，三山戴巨鼇。", "思陵風雨夜，松柏漫蕭騷。"]'),
('e646920a-2102-4a09-a956-bc9ee564a1ea','吳師魯挽詞','周紫芝','宋','宋诗','song-poetry','','[]','少日詞華豹一斑，暮年白髮老青山。',64,'全唐诗/poet.song.88000.json','["少日詞華豹一斑，暮年白髮老青山。", "誰知筆下三都賦，不及人間五兩綸。", "麟閣未輸前日恨，鹿門長享百年安。", "他時隱逸書佳傳，名在宗元季孟間。"]'),
('0ccef1db-ec0c-48cc-a361-c051d2b3b4d8','王夫人挽詞','周紫芝','宋','宋诗','song-poetry','','[]','藁砧高義赫窮閻，內子宜家恊鳯占。',64,'全唐诗/poet.song.88000.json','["藁砧高義赫窮閻，內子宜家恊鳯占。", "茶乳未容收浄供，蛛絲早已上香奩。", "坐中有客思分髻，林下無人解擬鹽。", "他日諸郎盡臺閣，會刊佳傳賁幽潛。"]'),
('cf2a2cd0-515e-4958-9037-d65bbfe6a8cf','徐夫人挽詞','周紫芝','宋','宋诗','song-poetry','','[]','蚤歲孀居婦職修，凛然霜檜與争秋。',64,'全唐诗/poet.song.88000.json','["蚤歲孀居婦職修，凛然霜檜與争秋。", "木蘭女解聽金柝，共伯妻能賦柏舟。", "鸞誥一封身未享，木奴千樹子先侯。", "可憐黄壤埋瓊玉，十里虞歌滿路愁。"]'),
('8d382838-47fc-4a3c-9ace-3ae353235884','郝至之挽詞','周紫芝','宋','宋诗','song-poetry','','[]','不見平生郝骩山，滿襟青淚只澘然。',64,'全唐诗/poet.song.88000.json','["不見平生郝骩山，滿襟青淚只澘然。", "少時插架空千軸，老去看嚢止一錢。", "挈榼暗思攜酒處，跨驢誰畫作詩肩。", "當時刻鵠終成鶩，唾面應須使自亁。"]'),
('a1709f97-461b-4c0f-9b29-dcdbf3562cb6','哭劉元素  其一','周紫芝','宋','宋诗','song-poetry','','[]','前度劉郎跡已塵，交親零落倍傷神。',32,'全唐诗/poet.song.88000.json','["前度劉郎跡已塵，交親零落倍傷神。", "桃花句好人何在，忍看風搖燕麥春。"]'),
('f2ddc6d0-2d20-48ff-9ca6-dd2e1df1babf','哭劉元素  其二','周紫芝','宋','宋诗','song-poetry','','[]','日飲無何自醉醒，平生種種是真誠。',32,'全唐诗/poet.song.88000.json','["日飲無何自醉醒，平生種種是真誠。", "不須私作門人謚，君亦從來苦畏名。"]'),
('4bf35ffe-832d-4282-956e-1180fa03aebc','哭劉元素  其三','周紫芝','宋','宋诗','song-poetry','','[]','中郎已老元無子，靈運爲僧只在家。',32,'全唐诗/poet.song.88000.json','["中郎已老元無子，靈運爲僧只在家。", "斗酒隻雞吾欲哭，不知誰爲作侯芭。"]'),
('56f67a12-f134-4768-bd52-c19e0569712e','劉元亢挽詞','周紫芝','宋','宋诗','song-poetry','','[]','交遊半作白頭新，不見劉郎誰與親。',64,'全唐诗/poet.song.88000.json','["交遊半作白頭新，不見劉郎誰與親。", "東野命窮官止尉，少陵才健筆如神。", "皇天可是無公道，舉世何由有若人。", "醉裏廣文渠不識，可憐官長錯相嗔。"]'),
('0631ee69-55df-4da0-bb3e-59b0e589aba3','悼友篇','周紫芝','宋','宋诗','song-poetry','','[]','建炎三年冬，胡騎方南驅。',288,'全唐诗/poet.song.88000.json','["建炎三年冬，胡騎方南驅。", "王師一敗績，列戍如驚烏。", "賊將招叛亡，操戈横道隅。", "坐令江鄉地，化作盜賊區。", "平生金蘭友，之子真吾徒。", "避地出三物，夷險兩不渝。", "豈謂倉惶間，遂有生死殊。", "始時群盜來，未識安所趨。", "但聞戞金革，門外争喧呼。", "捫蘿得微徑，密雪方紛敷。", "子時索我急，出門衝賊塗。", "遲子久不至，得報日已晡。", "夫婦俱見執，擔簦入軍俘。", "纍纍五兒女，飲泣聲呱呱。", "小雛從物故，踉蹌走大雛。", "長女留軍中，繼釋二小姝。", "藉草已信宿，脱死許可圖。", "賊意欲解縳，小試聊躊躇。", "時方羽書至，招諭陳嘉謨。", "渠姦立授辭，抗論苦未俞。", "命子使草檄，操筆徒嗟吁。", "謂言不事賊，高目捫髯鬚。", "丈夫賤苟活，請就斧鉞誅。", "袒裼蒙殊死，肥白驚瓠壺。"]'),
('45823c04-f84b-4da1-a5fb-edfc4886ba82','詹伯尹挽詞二首  其一','周紫芝','宋','宋诗','song-poetry','','[]','詹郎胸次有奇兵，幾爲樓蘭欲請纓。',64,'全唐诗/poet.song.88000.json','["詹郎胸次有奇兵，幾爲樓蘭欲請纓。", "四海眼高空燕雀，百年身老困鯢鯨。", "跕鳶不用傷遺恨，蒼狗何嘗有定名。", "勳業轉頭渾似夢，却將五字作長城。"]'),
('4a602125-dc22-4f90-bc50-ff9b03b376c7','詹伯尹挽詞二首  其二','周紫芝','宋','宋诗','song-poetry','','[]','平生危論劇傾河，應合飛騰上諫坡。',64,'全唐诗/poet.song.88000.json','["平生危論劇傾河，應合飛騰上諫坡。", "富貴腥羶真夢耳，死生名節奈君何。", "欲求佳傳無千斛，但把青魂付九歌。", "斗酒淋漓澆宿草，西風老淚不勝多。"]'),
('19fbbb10-c7c7-4544-9876-1648794624f5','吳夫人挽詞  其一','周紫芝','宋','宋诗','song-poetry','','[]','懿德閨房重，高名遠近稱。',48,'全唐诗/poet.song.88000.json','["懿德閨房重，高名遠近稱。", "流年忽成夢，素節尚如冰。", "法悟無生忍，襌參最上乘。", "應憐女博士，空近讀書燈。"]'),
('47177b0b-13e7-4550-ac8d-ed204b1bbb01','吳夫人挽詞  其二','周紫芝','宋','宋诗','song-poetry','','[]','素幔秋風急，烟峰曉日殘。',48,'全唐诗/poet.song.88000.json','["素幔秋風急，烟峰曉日殘。", "香沈金獸在，鏡掩玉臺寒。", "恩已霑封誥，人空委珮蘭。", "他年作佳傳，誰爲考幽刊。"]'),
('9a008357-0806-4531-a5b1-f05a33fa7b39','李卿挽詞','周紫芝','宋','宋诗','song-poetry','','[]','東漢埋輪手，開元御府卿。',48,'全唐诗/poet.song.88000.json','["東漢埋輪手，開元御府卿。", "名因射策早，恩許故家榮。", "竟失鵷行舊，空乘馬鬛旌。", "他時雙驥子，萬里是歸程。"]'),
('0438719a-e5ff-42e0-bb1e-49d4f3aaec82','桐川太守母夫人挽詞','周紫芝','宋','宋诗','song-poetry','','[]','夫人無復擁魚軒，旅櫬歸來倍黯然。',64,'全唐诗/poet.song.88000.json','["夫人無復擁魚軒，旅櫬歸來倍黯然。", "皂蓋朱轓今有子，布裙椎髻舊推賢。", "餘哀盡入虞殯曲，盛事當隨列女篇。", "忽掩幽墟可無恨，誥封生享更高年。"]'),
('35307eb9-e8e2-452e-94db-5fdbecd08f7b','哭吳與行二絕  其一','周紫芝','宋','宋诗','song-poetry','','[]','李廣平生竟不侯，功名看得鬢霜秋。',32,'全唐诗/poet.song.88000.json','["李廣平生竟不侯，功名看得鬢霜秋。", "學無西洛時難偶，人似南金價未酬。"]'),
('46c7fcd8-6360-4b32-bd52-6caa5538ac6e','哭吳與行二絕  其二','周紫芝','宋','宋诗','song-poetry','','[]','投筆文場日未西，春蠶食飽速於飛。',32,'全唐诗/poet.song.88000.json','["投筆文場日未西，春蠶食飽速於飛。", "充庭不是無前列，從此元江九肋稀。"]'),
('1861067b-f547-47f4-b849-1f8d2c4a560e','聞侯元進死  其一','周紫芝','宋','宋诗','song-poetry','','[]','薄宦時難得，餘生老易分。',48,'全唐诗/poet.song.88000.json','["薄宦時難得，餘生老易分。", "人言侯叔起，詩學鮑參軍。", "未補胸中線，空修地下文。", "欲尋高密語，應怕虎狼羣。"]'),
('58d481ca-7f2c-487f-9232-ca3bfd86c356','聞侯元進死  其二','周紫芝','宋','宋诗','song-poetry','','[]','君在漳溪病，相逢特地歡。',48,'全唐诗/poet.song.88000.json','["君在漳溪病，相逢特地歡。", "句新詩屢出，談劇酒頻寒。", "夢作三春别，人成隔世看。", "無由弔塵几，只有涕闌干。"]'),
('6b5af29f-3356-4e32-a57f-2caf3a381551','悼舒永豐','周紫芝','宋','宋诗','song-poetry','','[]','舒侯九秋鷹，未奮老拳翼。',228,'全唐诗/poet.song.88000.json','["舒侯九秋鷹，未奮老拳翼。", "平生流輩中，肯數程不識。", "庾公開幕府，少作九江客。", "風簷掛虛樓，夜月浮大白。", "飲氣吞江流，高談傾坐席。", "一朝胡塵暗，孤壘困劇賊。", "艨艟浮江下，雲霧蔽天赤。", "坐中嘬炙兒，相視無人色。", "手持白羽扇，奮身追危壁。", "坐解兩家難，稍稍無勍敵。", "身幾落虎口，名不掛賞籍。", "鳥去良弓藏，論功止投石。", "歲晚猶折腰，得邑亦甚僻。", "似聞山中人，盡飽太邱德。", "官謗殊未眀，此責詎可塞。", "乃復令斯人，含恨入窀穸。", "風亭分客袂，僅作秋夏隔。", "奪我玉面郎，江湖坐愁寂。", "撫棺欲三號，何由反鄉國。"]'),
('9cd257ba-de5c-40be-adb8-8edf37982fc9','元具茨不起道州之疾哭之以詩','周紫芝','宋','宋诗','song-poetry','','[]','一别魯山三歲餘，西來消息未全疏。',64,'全唐诗/poet.song.88000.json','["一别魯山三歲餘，西來消息未全疏。", "白頭忍雪舂陵涕，醉墨纔乾廬阜書。", "晚路得州真似斗，平生彈鋏竟無魚。", "漫郎猶有新書在，千古風流不負渠。"]'),
('605bd927-bf33-44d4-aa60-2d53b59ac00c','沈貴池挽詞','周紫芝','宋','宋诗','song-poetry','','[]','澤宮當日喜逢君，雞鶩初驚鶴在羣。',64,'全唐诗/poet.song.88000.json','["澤宮當日喜逢君，雞鶩初驚鶴在羣。", "果見亷平清似水，不嫌名宦薄於雲。", "一區未買江邊宅，三尺誰澆隴上墳。", "自古達人俱泯滅，固應知有沈休文。"]'),
('fefded4d-02c0-479a-84f8-9611cf41a959','李使君挽詞三首  其一','周紫芝','宋','宋诗','song-poetry','','[]','治劇知公老更優，何嘗箕斂急征求。',64,'全唐诗/poet.song.88000.json','["治劇知公老更優，何嘗箕斂急征求。", "誰言粟自關中漕，但見錢從地上流。", "已報南來三日政，爲寛北顧一時憂。", "皇天自古無公道，不遣劉郎到白頭。"]'),
('4e48ea50-f58d-4411-87cd-af76e764738d','李使君挽詞三首  其二','周紫芝','宋','宋诗','song-poetry','','[]','溪頭萬杵響春雷，談笑争看雉堞開。',64,'全唐诗/poet.song.88000.json','["溪頭萬杵響春雷，談笑争看雉堞開。", "鼛鼓不須催晝急，麗譙疑復自天來。", "一樽誰酹風前酒，萬柳空垂雪後栽。", "魯史書城三十六，不殫民力獨公才。"]'),
('96bf8eea-2969-418d-9216-3c0c81deb495','李使君挽詞三首  其三','周紫芝','宋','宋诗','song-poetry','','[]','使君投老益精明，三換魚符寄一城。',64,'全唐诗/poet.song.88000.json','["使君投老益精明，三換魚符寄一城。", "漢相未曾除郡守，蜀祠空復拜諸生。", "他年宿草人誰弔，當日清泉我作銘。", "萬里巴江消息斷，不堪斜日上寒旌。"]'),
('9106cc97-3cd1-47c3-b0c6-039f5ca4eb40','蔡氏夫人挽詞','周紫芝','宋','宋诗','song-poetry','','[]','中郎文采照當年，婦德尤稱女弟賢。',64,'全唐诗/poet.song.88000.json','["中郎文采照當年，婦德尤稱女弟賢。", "長夜忽成三尺壠，異恩來自九重天。", "名留仙籍誰能見，事載銘詩世謾傳。", "想得伯鸞懷舊恨，摩挲歸櫬一澘然。"]'),
('29543576-1150-4e31-a601-02a54663e5f8','方桐川挽詞','周紫芝','宋','宋诗','song-poetry','','[]','善人淪沒意如何，細說平生恨轉多。',64,'全唐诗/poet.song.88000.json','["善人淪沒意如何，細說平生恨轉多。", "此日飛騰只蘭省，當時準擬上鑾坡。", "十年猶記燕姬舞，一曲今悲鬼伯歌。", "欲問哭君多少淚，未能注海亦傾河。"]'),
('d682ae93-eac7-4570-8b07-2da98a6856dd','周脩武挽詞','周紫芝','宋','宋诗','song-poetry','','[]','懶隨車馬著冠裳，便築華堂作醉鄉。',64,'全唐诗/poet.song.88000.json','["懶隨車馬著冠裳，便築華堂作醉鄉。", "遮眼不知山幾疊，供閑自有木千章。", "平生陰德應無數，他日高門未可量。", "我亦元無諛墓手，斯文聊付起家郎。"]'),
('bfb66af6-16a0-4040-94db-b171c21fbeb9','弔孫雲老','周紫芝','宋','宋诗','song-poetry','','[]','孫郎涉世似虛舟，一醉從前萬事休。',64,'全唐诗/poet.song.88000.json','["孫郎涉世似虛舟，一醉從前萬事休。", "千佛經中無姓字，八仙歌裏見風流。", "清詩便與重泉隔，客淚空添晚歲愁。", "隴上只今多宿草，爲君何地築糟邱。"]'),
('9ea9d15f-92a4-4e23-b1d8-701575f4ee00','哭二羅','周紫芝','宋','宋诗','song-poetry','','[]','平生交友懷三益，晚歲悲酸弔二羅。',64,'全唐诗/poet.song.88000.json','["平生交友懷三益，晚歲悲酸弔二羅。", "地下忽埋雙白璧，人間真是一南柯。", "篇章零落知誰管，人物風流竟若何。", "未有隻雞澆斗酒，空令老淚作傾河。"]'),
('eda6726d-4069-4350-95c6-a8096d2dfcf9','弔陳相之侍郎','周紫芝','宋','宋诗','song-poetry','','[]','疇昔相逢十載餘，已驚白雪鬢疏疏。',64,'全唐诗/poet.song.88000.json','["疇昔相逢十載餘，已驚白雪鬢疏疏。", "長鳴本是空群馬，入社猶爲漏網魚。", "醉到湖邊誰共酒，别來江上苦無書。", "風流文采今何在，只有傾河淚滿裾。"]'),
('c0e299f9-51d8-4968-92c7-ae25cef923f9','九道江中弔趙温叔','周紫芝','宋','宋诗','song-poetry','','[]','昔飲江南酒，劉郎鬢未華。',48,'全唐诗/poet.song.88000.json','["昔飲江南酒，劉郎鬢未華。", "無依憐晚歲，死賊痛全家。", "夢隔泉臺久，魂歸故國賖。", "與誰山下路，同折凍梅花。"]'),
('0fb5259c-547c-4a75-b8af-fa27cc54da14','大宋中興頌','周紫芝','宋','宋诗','song-poetry','','[]','緬維聖宋，昔在中葉。',240,'全唐诗/poet.song.88000.json','["緬維聖宋，昔在中葉。", "四方多虞，萬里喋血。", "大臣持謀，興師肆伐。", "將臣持兵，日獻戎捷。", "皇帝曰吁，黷武無烈。", "糜我赤子，膏我斧鉞。", "孰與休師，一戟不折。", "因壘而降，舞干而悅。", "閉我玉關，歸師解甲。", "犂我春田，銷兵鑄鐡。", "使命交通，相望不絕。", "愛惜兩朝，前師聖說。", "昭陵之仁，嘉祐之業。", "念昔興師，堂陛卼臲。", "發言盈庭，更訿元薎。", "佩劍彼此，孰予孰決。", "廟謀一定，群議沮折。", "袖手何言，瞠目巻舌。", "草木蒼蒼，始有芽蘖。", "盡育恢胎，咸歸坱圠。", "灞上棘門，環衛拱列。", "罔敢擅師，始制君節。", "萬夫屬鞬，拜舞君闕。", "乃命叔孫，諏日綿蕝。"]'),
('739540ca-342f-43b7-b388-f32db65e4fe0','天申節樂語口號','周紫芝','宋','宋诗','song-poetry','','[]','建章宫殿擁祥烟，遙望需雲錫御筵。',64,'全唐诗/poet.song.88000.json','["建章宫殿擁祥烟，遙望需雲錫御筵。", "上帝自應知舜孝，萬方宜共祝堯年。", "蒼龍闕轉曈曨日，瑞獸香聞咫尺天。", "湛露恩深何以報，願將虎拜答周宣。"]'),
('144af57f-9f66-4d89-b2e8-7bc63cd3f346','周朝議宣新第致語口號','周紫芝','宋','宋诗','song-poetry','','[]','風光渾占一溪中，青谷新開甲第雄。',64,'全唐诗/poet.song.88000.json','["風光渾占一溪中，青谷新開甲第雄。", "凉榭切雲先得月，朱樓凌水欲横空。", "連甍萬瓦琉璃碧，照坐千鍾琥珀紅。", "要看仍雲乘駟馬，使君眉壽似喬松。"]'),
('4eaa0d70-0b08-4c27-8146-8c4580bbb692','上元燕賓客致語口號','周紫芝','宋','宋诗','song-poetry','','[]','使君才氣本無雙，暫擁州麾殿大邦。',64,'全唐诗/poet.song.88000.json','["使君才氣本無雙，暫擁州麾殿大邦。", "千騎出城聞畫角，萬燈銜壁看銀釭。", "夜天星滿光浮漢，秋水花紅錦照江。", "莫向華堂辭一醉，君正懷舊憶竒龎。"]'),
('a6c9928b-ca13-46b8-b156-746c2e271e6f','燕太守汪內相致語口號','周紫芝','宋','宋诗','song-poetry','','[]','誰持尺一下明光，新易泉南舊印章。',64,'全唐诗/poet.song.88000.json','["誰持尺一下明光，新易泉南舊印章。", "禁殿何時出頗牧，人間又喜見龔黄。", "攀轅父老今猶在，騎竹兒童喜欲狂。", "只恐政成歸更速，便紆華衮望清光。"]'),
('7b95cadb-7ce0-4d62-99ac-7dc833901b7f','燕吳奉使致語口號','周紫芝','宋','宋诗','song-poetry','','[]','清詔名髙下紫宸，異方初喜見王人。',64,'全唐诗/poet.song.88000.json','["清詔名髙下紫宸，異方初喜見王人。", "二年輦轂辭家逺，萬里岷峨入眼新。", "使者登車爭攬轡，君王問俗頗憂民。", "翰林勸酒非無意，知向明光作侍臣。"]'),
('913aecc5-5a17-41d8-bcb9-24c8e71b6b56','二妙堂落成家集致語口號','周紫芝','宋','宋诗','song-poetry','','[]','居士歸來已白頭，數椽聊喜枕江流。',64,'全唐诗/poet.song.88000.json','["居士歸來已白頭，數椽聊喜枕江流。", "百年夢幻何時了，二妙江山一日收。", "鼓吹自從詩裏得，光陰都在醉中休。", "蟹螯霜後偏宜酒，蘇幕歌成可共謳。"]'),
('9a031e26-2a38-44ec-af20-3bd47dd79d0b','松林道人施繡觀音','周紫芝','宋','宋诗','song-poetry','','[]','菩薩變化如虚空，云何得此虚空相。',272,'全唐诗/poet.song.88000.json','["菩薩變化如虚空，云何得此虚空相。", "我觀無礙大慈悲，無刹不現如水月。", "八萬四千母陁臂，能援世間一切衆。", "八萬四千清淨眼，能照五濁諸有情。", "是故神通不思議，而欲妄以色相求。", "譬如狂人逐四方，四方無盡力無竭。", "况以丹青繪繒綵，更復刺繡爲儀形。", "絲毫縑素相假合，妙技巧借金十奴。", "若人捐棄釙與絲，亦無五色可資藉。", "瞑目黙相不可得，畢竟無有是菩薩。", "吾願世人捨色相，當時未有釙絲時。", "蓬萊觀妙本無心，以粗即妙作是念。", "松林無心受此施，以施居士作禮言。", "我當還亦以此施，此施有盡法無窮。", "普願世間諸佛子，凡瞻此相悉歡喜。", "若見菩薩非菩薩，即知是我非是妄。", "妄見除滅無復然，吾與佛子等無二。"]'),
('9e8b4c5a-f916-4b00-9643-1bb57b1192c7','夢禮僧伽大士','周紫芝','宋','宋诗','song-poetry','','[]','我觀諸佛子，皆以妄自冥。',288,'全唐诗/poet.song.88000.json','["我觀諸佛子，皆以妄自冥。", "不知有無想，一切俱是妄。", "認有以爲實，夫豈識無有。", "如人具諸欲，耳目與鼻舌。", "百體俱動作，動作皆有相。", "耳欲以聽聲，有耳言可聞。", "絃匏與笙簫，皆具諸宫羽。", "雖然始一奏，有耳悉皆聞。", "衆生於是時，知聲不知耳。", "衆音始一闋，寂靜無有聲。", "傾耳而聽之，無一可聞者。", "衆生於是時，知耳不知聲。", "至於目視色，亦復如耳根。", "知色爲有形，乃以色爲有。", "寧知本無色，何况於目睫。", "乃至鼻聞臭，口舌所啖食。", "百體諸毛髮，意有所爲者。", "行步與坐臥，喘息及呼吸。", "方其有爲時，無一不爲有。", "諸爲悉皆空，了無有一存。", "心惟昨所爲，恍惚如夢事。", "我昔禮菩薩，是爲真見者。", "譬如聞衆聲，認聲爲有響。", "比其不及禮，菩薩那得見。"]'),
('fa5e7fdc-8f10-4f8e-9b98-6f56ed067245','宗演師金書妙法蓮經','周紫芝','宋','宋诗','song-poetry','','[]','稽首無上尊，爲世大慈父。',276,'全唐诗/poet.song.88000.json','["稽首無上尊，爲世大慈父。", "爲憫一切衆，流浪諸苦海。", "滋無碍辨才，廣爲衆生說。", "譬如大火宅，隨念得清凉。", "又令諸窮子，獲此大寶珠。", "是真秘密藏，故名妙法華。", "非思量分别，而以得解悟。", "雖諸大菩薩，有所不能知。", "况於聲聞衆，豈復聞妙義。", "如來廣開示，一一令悟入。", "衆生悉皆曉，而况於聲聞。", "我佛出現世，了此一大緣。", "當如佛所說，是最爲第一。", "今此大比邱，舍所甚愛者。", "百煉真黄金，銷鑠爲書寫。", "具諸大寶貝，更以爲莊嚴。", "偷兒甚魁儈，如飛天藥叉。", "諸所經過處，悉爲尸陁林。", "大火所藏滅，毫髮無遺餘。", "龍天諸善神，悉力來加護。", "究竟不得壞，我今同讚歎。", "普告諸佛子，凡所見聞者。", "信心自堅固，各各普授持。"]'),
('3b342e51-1f53-45e3-929a-3ed5956368c2','金剛般若波羅密經','周紫芝','宋','宋诗','song-poetry','','[]','佛以甚深微妙法，廣爲一切衆生說。',280,'全唐诗/poet.song.88000.json','["佛以甚深微妙法，廣爲一切衆生說。", "有能悉發菩提心，究竟得成無上道。", "彼有受持讀誦者，其福不可更稱量。", "七寶滿爾河沙數，以用布施得福徳。", "而比福徳猶爲多，况吾大慈大願師，常憫衆生墮惡道。", "假此持經功徳海，能免世間一切苦。", "有大長者號宰官，書寫讀誦不少懈。", "旃檀香及薝蔔花，供養恭敬常作禮。", "忽遇黑風吹船舫，將隨那刹諸鬼國。", "倉惶取是受持經，投諸江流沒巨浪。", "須臾風定夜色霽，達旦悉得大快樂。", "平明篙師有婦妻，忽言汲水得巨軸。", "金書貝葉與巾繡，無一毫毛有壞相。", "有如金剛不壞身，經大水聚性不滅。", "拾塵數刼有時盡，而是功徳終無窮。", "衆生信心不堅固，未甞聞此殊勝事。", "用是稽首無上尊，願我諸佛常加護。"]'),
('de0b66c5-87bf-427b-961c-feeae7980aea','戲作小詩用少陵事','周紫芝','宋','宋诗','song-poetry','','[]','百尺寒松老幹枯，韋郎筆妙古今無。',32,'全唐诗/poet.song.88000.json','["百尺寒松老幹枯，韋郎筆妙古今無。", "何如莫掃鵝溪絹，留取天吳紫鳳圖。"]'),
('91fe57bb-9d3c-47fe-b97f-a4dc223cf0e1','湖州','周紫芝','宋','宋诗','song-poetry','','[]','霅溪景物見歌詩，只有當年杜紫微。',48,'全唐诗/poet.song.88000.json','["霅溪景物見歌詩，只有當年杜紫微。", "沽酒店穿斜巷出，採蓮船傍後門歸。", "翠沾城郭山千點，清蘸樓臺水一圍。"]'),
('c55a0d28-84f1-40b2-89d3-7b776d957f66','句  其一','周紫芝','宋','宋诗','song-poetry','','[]','枕簟綠陰花謝後，軒窗清景月明時。',16,'全唐诗/poet.song.88000.json','["枕簟綠陰花謝後，軒窗清景月明時。"]'),
('ada3d2e8-37f3-49bc-a48b-7a1d32cd2ff3','句  其二','周紫芝','宋','宋诗','song-poetry','','[]','浪花叢裏看蟂磯。',8,'全唐诗/poet.song.88000.json','["浪花叢裏看蟂磯。"]'),
('7fb35b2b-f922-4d93-b1c3-c55e8c5a3fe3','句  其三','周紫芝','宋','宋诗','song-poetry','','[]','秋聲歸草木，寒色到衣裘。',12,'全唐诗/poet.song.88000.json','["秋聲歸草木，寒色到衣裘。"]'),
('4b08e857-df05-4f08-8099-800465f32754','句  其四','周紫芝','宋','宋诗','song-poetry','','[]','江南樹樹黄垂蜜。',8,'全唐诗/poet.song.88000.json','["江南樹樹黄垂蜜。"]'),
('2ce32863-d993-4fc9-971c-cf983b9d42c3','附錄 元祐元年己巳正月三十日同太史薄達夫來遊概作六詠又作長篇以廣其意景爾','周紫芝','宋','宋诗','song-poetry','','[]','靈巖勝概魁寧川，欲往還心幾踰年。',224,'全唐诗/poet.song.88000.json','["靈巖勝概魁寧川，欲往還心幾踰年。", "今朝乘興得清賞，須知亦是同夤緣。", "驅車初抵石門路，恍疑共到蓬萊天。", "旁連高延立玉壁，下廣迤邐鋪瓊田。", "俄從一徑造佛剎，樓閣深聳凌雲煙。", "山僧指我遍幽歷，嶮巇不憚躋山顛。", "明心深邃光通穿，朝陽晴暉火欲然。", "漣漪澄澈渚寒泉，碧雲紫霧爭華鮮。", "夕陽林麓禽啾喧，嘗聞昔有瞿硎仙。", "我今不見心懸懸，廣寒宮闕名空傳。", "日暮欲去還留連，嗟予事奪須回旋。", "不得共宿高談禪，郵亭耿耿夜不眠。", "擁衾操筆成長篇，封題遠寄風騷賢。", "辭語蕪陋不足道，爝火妄記星光躔。"]'),
('4ddddfdd-2083-4dc6-974c-44e71160d7c9','元忠作胡人下程圖','周紫芝','宋','宋诗','song-poetry','','[]','單于獵罷臥錦紅，解鞍休騎荒磧中。',160,'全唐诗/poet.song.88000.json','["單于獵罷臥錦紅，解鞍休騎荒磧中。", "蒼駒騧駱六十匹，隱谷映坡分尾騣。", "九駝五牛羊頗倍，沙草晚牧生寒風。", "貴賤小大只五百，執作意態皆不同。", "二鷹在臂二鷹架，駿犬當對能爭功。", "氈廬鼎列帳幕擁，鼔角未吹驚塞鴻。", "上山髙髙置烽燧，毛嚢貯獲閑刀弓。", "水泉在側挹其上，長河杳杳流無窮。", "素紈六幅筆何巧，胡環盡妙誰能通。", "今日都城有别識，别識共許劉元忠。"]'),
('b89b253f-b9ea-4704-8ed5-9a5ffb6fe43c','和菊花','朱勝非','宋','宋诗','song-poetry','','[]','紛紛桃李春，過眼成枯萎。',24,'全唐诗/poet.song.88000.json','["紛紛桃李春，過眼成枯萎。", "晚榮方耐久，造物豈吾欺。"]'),
('5a0b4a09-caa0-477f-8118-c6ad9678890e','和同省秋省宿','朱勝非','宋','宋诗','song-poetry','','[]','老火未甘退，稚金方力征。',24,'全唐诗/poet.song.88000.json','["老火未甘退，稚金方力征。", "炎涼分勝負，頃刻變陰晴。"]'),
('b6e6ce25-2fd9-44f8-bc5f-234c4a7b7438','浦溪','朱勝非','宋','宋诗','song-poetry','','[]','郴嶺最高處，桐軒臨水開。',24,'全唐诗/poet.song.88000.json','["郴嶺最高處，桐軒臨水開。", "晚晴東北望，直見鬰孤台。"]'),
('198949e9-2afd-4714-86d2-30608c4c3578','天聖寺古檜','朱勝非','宋','宋诗','song-poetry','','[]','雷霆起蟄虬，夭矯勢欲上。',84,'全唐诗/poet.song.88000.json','["雷霆起蟄虬，夭矯勢欲上。", "忽然化此木，尚作拏雲狀。", "婆娑枝幹垂，生澀紐結壯。", "圖經不能記，父老那可訪。", "晉杉定儕類，蜀柏豈輩行。", "櫟夢何足神，槐語固已妄。", "自無斧斤憂，未始疑大匠。"]'),
('075eef16-ffa1-44fe-b779-41a7c994615b','瀘渡','朱勝非','宋','宋诗','song-poetry','','[]','曾到瀘溪渡，山青石壁粗。',48,'全唐诗/poet.song.88000.json','["曾到瀘溪渡，山青石壁粗。", "雲藏天寶塔，水遶率巖湖。", "日暖魚增價，風和酒易沽。", "魚船交過往，商旅及成都。"]'),
('ca96044f-9f44-4257-a9f3-54770768823f','石通洞  其一','朱勝非','宋','宋诗','song-poetry','','[]','涪翁詩名存宇宙，李杜摧鋒君殿後。',48,'全唐诗/poet.song.88000.json','["涪翁詩名存宇宙，李杜摧鋒君殿後。", "山川草木經品題，千古佳名長不朽。", "中年微累黔中□，石通曾運羲□□。"]'),
('a6d96c71-f668-45e7-b12e-fe86905838c8','石通洞  其二','朱勝非','宋','宋诗','song-poetry','','[]','咫尺天湖號堵坪，先賢曾此勸農耕。',32,'全唐诗/poet.song.88000.json','["咫尺天湖號堵坪，先賢曾此勸農耕。", "若教一日歸豪右，敢向黄公廟下行。"]'),
('f9eb0abe-911d-4f7e-a9d2-b9de677157da','句  其一','朱勝非','宋','宋诗','song-poetry','','[]','始意鍾陵參馬祖，卻尋橘井訪蘇仙。',16,'全唐诗/poet.song.88000.json','["始意鍾陵參馬祖，卻尋橘井訪蘇仙。"]'),
('2265c7fe-d30a-442d-b87b-072a7bcd3648','句  其二','朱勝非','宋','宋诗','song-poetry','','[]','地藏堂中坐，天鵝嶺下行。',12,'全唐诗/poet.song.88000.json','["地藏堂中坐，天鵝嶺下行。"]'),
('b6e5405a-ecfb-4043-8e93-637f4f6918b7','游北巖','王庶','宋','宋诗','song-poetry','','[]','衰病飄零心久灰，扁舟艤棹北巖隈。',64,'全唐诗/poet.song.88000.json','["衰病飄零心久灰，扁舟艤棹北巖隈。", "江連白帝浮空下，山背青城出劍來。", "三戶亡秦期可必，八公助順勢將回。", "老臣願獻中興頌，漢武周宣何遠□。"]'),
('73d1af63-db06-4c7a-9708-68b48a7b0a56','山中見桃花李花','吳激','宋','宋诗','song-poetry','','[]','錦里春風徧海棠，別時無計奈紅芳。',32,'全唐诗/poet.song.88000.json','["錦里春風徧海棠，別時無計奈紅芳。", "山中桃李渾疑晚，猶有殘紅斷客腸。"]'),
('257ce4b8-deb0-41d4-ab3f-e7156aacbaff','長安懷古','吳激','宋','宋诗','song-poetry','','[]','佳氣猶能想欝葱，雲間雙灣峙蒼龍。',64,'全唐诗/poet.song.88000.json','["佳氣猶能想欝葱，雲間雙灣峙蒼龍。", "春風十里灞陵樹，曉月一聲長樂鐘。", "小苑花開紅漠漠，曲江波漲碧溶溶。", "眼前疊嶂青如畫，借問南山共幾峰。"]'),
('26b39536-4fb3-4121-86fa-cd2997aa19cf','宿湖城簿廳','吳激','宋','宋诗','song-poetry','','[]','日遲風暖燕飛飛，古柳高槐面翠微。',32,'全唐诗/poet.song.88000.json','["日遲風暖燕飛飛，古柳高槐面翠微。", "卷上疏簾無一事，滿池春水照薔薇。"]'),
('1fb43ceb-7a37-4f72-b169-0dba659bc867','窮巷','吳激','宋','宋诗','song-poetry','','[]','窮巷無來轍，貧家有舊醅。',48,'全唐诗/poet.song.88000.json','["窮巷無來轍，貧家有舊醅。", "窗明憐雪在，睡美覺春回。", "菜甲方齊拆，梅花亦半開。", "茅簷鳴好鳥，節物莫相催。"]'),
('4d9c5bb2-dcff-456e-8fc2-0c46a08260d4','偶成二首  其一','吳激','宋','宋诗','song-poetry','','[]','一番瘦筍羽林槍，松架陰陰盡日涼。',32,'全唐诗/poet.song.88000.json','["一番瘦筍羽林槍，松架陰陰盡日涼。", "繞屋雲烟無定態，連山草木有真香。"]'),
('09b81f9a-a45b-435d-a929-035a3abd4c79','偶成二首  其二','吳激','宋','宋诗','song-poetry','','[]','蟹湯兔盞鬭旗槍，風雨山中枕簟涼。',32,'全唐诗/poet.song.88000.json','["蟹湯兔盞鬭旗槍，風雨山中枕簟涼。", "學道窮年何所得，只工掃地與焚香。"]'),
('b9d6ea63-2692-432c-a0e0-1aabd4bb4605','病後寄開甫','吳激','宋','宋诗','song-poetry','','[]','暗蛩咽幽響，隙月漏微光。',72,'全唐诗/poet.song.88000.json','["暗蛩咽幽響，隙月漏微光。", "溪上風雨過，翛然有餘凉。", "病瘦鶴骨立，低垂不能翔。", "懷我中山兄，開經焚道香。", "猿嘯耿清夜，鐘鳴悠夕陽。", "商秋早晚至，夢寐松楸蒼。"]'),
('f36010a5-3ca3-40e4-8970-c41a2e55ec01','過南湖偶成','吳激','宋','宋诗','song-poetry','','[]','杏山松檜紫坡陀，湖面無風亦自波。',64,'全唐诗/poet.song.88000.json','["杏山松檜紫坡陀，湖面無風亦自波。", "綠鬢朱顔嗟老矣，落花啼鳥奈春何。", "詩人未必皆憔悴，世事從來有折磨。", "列坐流觴能幾日，知誰對酒愛新鵝。"]'),
('16a564f1-e6b0-47df-8883-ebb56683352a','夜汎渦河龍潭','吳激','宋','宋诗','song-poetry','','[]','輕舟弄素月，静夜横清渦。',120,'全唐诗/poet.song.88000.json','["輕舟弄素月，静夜横清渦。", "天風毛髮亂，疏星燦明河。", "圖經記父老，冥寞年歲多。", "淵沈三千丈，湛碧寒無波。", "微流带文藻，絕岸無柔莎。", "炯如帝鴻鏡，可鑒不可磨。", "中蟠至神物，役使羣蛟鼉。", "蜿蜿頭角古，勁鬛誰敢劘。", "深宮照珠貝，頗費蚌與螺。", "何時葛陂竹，化作陶公梭。"]'),
('3a3e9004-e9c3-4349-a9b7-b723e6fb9fb4','秋興','吳激','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','後園雜樹入雲高，萬里長風夜怒號。',32,'全唐诗/poet.song.88000.json','["後園雜樹入雲高，萬里長風夜怒號。", "憶向錢塘江上寺，松窗竹閣瞰秋濤。"]'),
('8f4a003d-ca60-48a4-80d8-a4cc9b5f2fe0','晚春言懷寄燕中知舊','吳激','宋','宋诗','song-poetry','','[]','閑雲洩洩日暉暉，林斧谿舂響翠微。',64,'全唐诗/poet.song.88000.json','["閑雲洩洩日暉暉，林斧谿舂響翠微。", "天氣乍晴花滿樹，人家久住燕雙飛。", "鄰村社後容借酒，客舍新來未綻衣。", "遙憶東郊亭畔柳，歸時相見亦依依。"]'),
('abd9bdf4-670b-4530-b325-9529933f9e6e','歲莫江南四憶  其一','吳激','宋','宋诗','song-poetry','','[]','瘦梅如玉人，一笑江南春。',48,'全唐诗/poet.song.88000.json','["瘦梅如玉人，一笑江南春。", "照水影如許，怕寒粧未勻。", "花中有仙骨，物外見天真。", "驛使無消息，憶君清涙頻。"]'),
('a0ec5926-8356-424b-8e65-da3f655aae54','歲莫江南四憶  其二','吳激','宋','宋诗','song-poetry','','[]','天南家萬里，江上橘千頭。',48,'全唐诗/poet.song.88000.json','["天南家萬里，江上橘千頭。", "夢繞閶門迥，霜飛震澤秋。", "秋深宜映屋，香遠解隨舟。", "懷袖何時獻，庭闈底處愁。"]'),
('0986a5aa-d9e8-4f8a-9c76-b9a305681422','歲莫江南四憶  其三','吳激','宋','宋诗','song-poetry','','[]','吳淞潮水平，月上小舟横。',48,'全唐诗/poet.song.88000.json','["吳淞潮水平，月上小舟横。", "旋斫四腮鱠，未輸千里羮。", "擣虀香不厭，照箸雪無聲。", "幾見秋風起，空悲白髪生。"]'),
('262600c1-7307-4607-ab5f-f9aad81320f3','歲莫江南四憶  其四','吳激','宋','宋诗','song-poetry','','[]','平生把螯手，遮日負垂竿。',48,'全唐诗/poet.song.88000.json','["平生把螯手，遮日負垂竿。", "浩渺渚田熟，青熒漁火寒。", "憶看霜菊艶，不放酒杯乾。", "比老垂涎處，糟臍箇箇團。"]'),
('88a4ca54-8df6-46e3-9774-b04dc6a31f34','述懷','吳激','宋','宋诗','song-poetry','','[]','旅食空彈鋏，歸休合挂冠。',48,'全唐诗/poet.song.88000.json','["旅食空彈鋏，歸休合挂冠。", "烟塵榆塞遠，風雨麥秋寒。", "巢燕長如客，鳴蛙不屬官。", "柴門江漲到，落日下漁竿。"]'),
('ab1f1cf3-922f-4346-9df6-a7abcf92afbd','喜晴和張魯瞻','吳激','宋','宋诗','song-poetry','','[]','原野怳新沐，豐隆寧世情。',48,'全唐诗/poet.song.88000.json','["原野怳新沐，豐隆寧世情。", "鳥歸林靄暝，樓射澗虹明。", "春草牛羊遠，人家機杼鳴。", "慘舒長有命，誰復問陰晴。"]'),
('b2963d84-86d5-43e1-a943-bd202204d8a7','國公女生日席上命賦','吳激','宋','宋诗','song-poetry','','[]','雪射瑤階月，春回玉女扉。',48,'全唐诗/poet.song.88000.json','["雪射瑤階月，春回玉女扉。", "雲中三秀草，石上六銖衣。", "酒熟鵝兒色，身輕燕子飛。", "客槎還汎斗，誰解卜搘機。"]'),
('eba61dc3-60a0-4f33-8856-a3f6a5024c20','秋夜','吳激','宋','宋诗','song-poetry','','[]','豈有涓埃補盛明，強扶衰病厠豪英。',64,'全唐诗/poet.song.88000.json','["豈有涓埃補盛明，強扶衰病厠豪英。", "夜窗燈火青相對，曉鏡髭鬚白幾莖。", "年去年來還似夢，江南江北若爲情。", "石田茅舍君家近，借與林泉送此生。"]'),
('28c95fae-a7be-43f0-bb32-82c853f51000','招趙資深拾遺','吳激','宋','宋诗','song-poetry','','[]','別久貌逾壯，道同心更親。',48,'全唐诗/poet.song.88000.json','["別久貌逾壯，道同心更親。", "移居近韋杜，相對邈參辰。", "雪少似饒客，鳥喧知得春。", "歸期淹幾日，莫厭馬蹄頻。"]'),
('22e27978-63db-465a-9ad2-f6113039f6a3','同兒曹賦蘆花','吳激','宋','宋诗','song-poetry','','[]','天接蒼蒼渚，江涵裊裊花。',48,'全唐诗/poet.song.88000.json','["天接蒼蒼渚，江涵裊裊花。", "秋聲風似雨，夜色月如沙。", "澤國幾千里，漁村三兩家。", "翻思杏園路，鞭裊帽簷斜。"]'),
('24bc7bc8-4ef2-4d23-a284-4cd3972afb61','張戡北騎','吳激','宋','宋诗','song-poetry','','[]','張生鞍馬客幽都，却笑靈光筆法粗。',32,'全唐诗/poet.song.88000.json','["張生鞍馬客幽都，却笑靈光筆法粗。", "祗今白首風沙裏，憶向江南見畫圖。"]'),
('6eaaddf7-793d-47a9-9bab-29a890bc6408','早春','吳激','宋','宋诗','song-poetry','','[]','寂寂重寂寂，出門春草齊。',48,'全唐诗/poet.song.88000.json','["寂寂重寂寂，出門春草齊。", "晚芳猶著樹，江漲欲平溪。", "山暝有時雨，村深何處雞。", "遠山緣底恨，故作傍人低。"]'),
('52f3746f-a9d3-4811-b96e-a9c160c78a37','雞林書事','吳激','宋','宋诗','song-poetry','','[]','箕子朝鮮僻，蓬丘弱水寛。',192,'全唐诗/poet.song.88000.json','["箕子朝鮮僻，蓬丘弱水寛。", "儒風通百粤，舊史記三韓。", "邑聚從衡接，民居質朴安。", "猶存古籩豆，兼用漢衣冠。", "兔穎家工縛，鮭腥俗嗜餐。", "騎兵腰玉具，府衛挾金丸。", "長袖鳶窺肉，都場狖掛竿。", "琴中蔡氏弄，指下祝家彈。", "主禮分庭抗，賓筵百拜難。", "漬橙粇釀旨，滋桂鹿脩乾。", "潑墨松如櫛，隤牆石似丹。", "地偏先日出，天迫衆山攢。", "鵬翼雲帆遠，羊腸石磴盤。", "由來異文軌，休訝變暄寒。", "事可資談柄，誰能記筆端。", "聊將詩貌取，歸作畫圖看。"]'),
('05c0536f-a3a2-4581-a07a-a7423eefa861','題宗之家初序瀟湘圖','吳激','宋','宋诗','song-poetry','','[]','江南春水碧於酒，客子往來船是家。',32,'全唐诗/poet.song.88000.json','["江南春水碧於酒，客子往來船是家。", "忽見畫圖疑是夢，而今鞍馬老風沙。"]'),
('bd649360-b288-4918-b1f8-e448858a87f0','句  其一','吳激','宋','宋诗','song-poetry','','[]','春風蜀棧青山盡，曉日秦川綠樹平。',16,'全唐诗/poet.song.88000.json','["春風蜀棧青山盡，曉日秦川綠樹平。"]'),
('e5a85e35-0d64-4a38-9e01-cff43e5b4857','句  其二','吳激','宋','宋诗','song-poetry','','[]','煙拂柳梢留淡白，雲蒸山腹出深青。',16,'全唐诗/poet.song.88000.json','["煙拂柳梢留淡白，雲蒸山腹出深青。"]'),
('02964303-403b-4bc9-9811-9b5a1e89b69e','句  其三','吳激','宋','宋诗','song-poetry','','[]','山侵平野高低樹，水接晴空上下星。',16,'全唐诗/poet.song.88000.json','["山侵平野高低樹，水接晴空上下星。"]'),
('503b950d-1aa7-4b7b-bc21-4668b69981e4','句  其四','吳激','宋','宋诗','song-poetry','','[]','玉座煙霞春寂寂，石壇星斗夜蒼蒼。',16,'全唐诗/poet.song.88000.json','["玉座煙霞春寂寂，石壇星斗夜蒼蒼。"]'),
('9eb93dc6-47d7-4e29-96a2-ba82b9762596','句  其五','吳激','宋','宋诗','song-poetry','','[]','手版西山聊復爾，角巾東第定何時。',16,'全唐诗/poet.song.88000.json','["手版西山聊復爾，角巾東第定何時。"]'),
('98ee1a9c-ba1e-4b87-a6cb-d78fd1e650f2','句  其六','吳激','宋','宋诗','song-poetry','','[]','竹院鳴鐘疑物外，畫橋流水似江南。',16,'全唐诗/poet.song.88000.json','["竹院鳴鐘疑物外，畫橋流水似江南。"]'),
('c6f221c7-cec6-4ae4-8632-0a4c32c21a26','句  其七','吳激','宋','宋诗','song-poetry','','[]','數樹殘花喜春在，一聲啼鳥覺山深。',16,'全唐诗/poet.song.88000.json','["數樹殘花喜春在，一聲啼鳥覺山深。"]'),
('baefbaf1-39c4-43f5-b5d7-9425cb999c05','句  其八','吳激','宋','宋诗','song-poetry','','[]','玉雪自知塵不涴，丹青難寫酒微醺。',16,'全唐诗/poet.song.88000.json','["玉雪自知塵不涴，丹青難寫酒微醺。"]'),
('f08e77a5-8895-4fa5-b8e5-855da8d19362','句  其九','吳激','宋','宋诗','song-poetry','','[]','四海蒼生謝安石，一言宣室賈長沙。',16,'全唐诗/poet.song.88000.json','["四海蒼生謝安石，一言宣室賈長沙。"]'),
('311f4ed2-92d1-4dc0-8284-013c447eb324','句  其一○','吳激','宋','宋诗','song-poetry','','[]','海東絕域皇華使，天上仙官碧落卿。',16,'全唐诗/poet.song.88000.json','["海東絕域皇華使，天上仙官碧落卿。"]'),
('788a161f-dff3-471d-b359-0c1cc5d14717','句  其一一','吳激','宋','宋诗','song-poetry','','[]','江湖欹枕夢，風雪打窗時。',12,'全唐诗/poet.song.88000.json','["江湖欹枕夢，風雪打窗時。"]'),
('f7c1cb89-ef78-4b0b-ad73-4590b4fcc7bb','昨傳旨勞軍彰明蒙文孺智仲皆惠佳句道中先次文孺韻奉寄併以謝智仲','師驥','宋','宋诗','song-poetry','','[]','聖主寬仁念小臣，江湖未許去垂綸。',64,'全唐诗/poet.song.88000.json','["聖主寬仁念小臣，江湖未許去垂綸。", "眷言劍閣出車遠，用錫楓宸湛露春。", "燕豆恩光浮四坐，旌旗喜氣動三辰。", "顧余濫辱皇華命，更獲從容遇故人。"]'),
('2f49924b-feab-44ed-a1d7-57332a813a47','竹西懷古','李易','宋','宋诗','song-poetry','','[]','淮南昔繁麗，富庶天下稱。',132,'全唐诗/poet.song.88000.json','["淮南昔繁麗，富庶天下稱。", "管弦十萬戶，夜夜聞喧騰。", "不徒竹西寺，歌吹相豪矜。", "一朝烽火急，廛市爲溝塍。", "風月無歡場，睥睨皆射堋。", "荒荒野月白，照地如寒冰。", "自從畫江守，歲歲輸金繒。", "蕭條閭井間，水旱又頻仍。", "我來經故里，日暮此一登。", "隋唐倐己往，遺跡幾廢興。", "江山極蒼莽，望之涕沾膺。"]'),
('c7380a6e-6d5b-4fb1-9059-b148782da521','居剡寄鄭天和','李易','宋','宋诗','song-poetry','','[]','金庭洞在桐栢山，山高一萬八千丈。',192,'全唐诗/poet.song.88000.json','["金庭洞在桐栢山，山高一萬八千丈。", "中有神仙不死區，郁郁黄雲覆其上。", "透巖流壑繞四旁，面勢參差皆意向。", "雞登天姥有時聞，鶴在沃洲何待放。", "彩衣大勝宮錦袍，白髮奉親仍敬養。", "異才爭出輔清朝，爽氣自驚遊碧障。", "古來無位有重名，吾家謫仙陸魯望。", "平生願到猶不諧，矧復區區走俗狀。", "桃源康樂舊鄉存，路接風煙甘遠往。", "渡江正謂九華丹，石筍飛泉歸指掌。", "鸞翔鵠浴傳異時，列岫方池閑想像。", "剡溪隨處可卜居，乘興扁舟正相訪。"]'),
('8cb1f131-d062-4408-816c-eab06a13129e','三懸潭','李易','宋','宋诗','song-poetry','','[]','鹿山今是貴門山，盡室攜扶萬壑間。',64,'全唐诗/poet.song.88000.json','["鹿山今是貴門山，盡室攜扶萬壑間。", "流水相隨真自悟，遙岑一望若爲攀。", "風翻竹塢清如洗，月過松扉静不關。", "潭底卧龍煩一起，正須霖雨濟塵寰。"]'),
('71238b6d-b453-475a-850e-2626e44f0c5e','題剡山所見','李易','宋','宋诗','song-poetry','','[]','剡中無數野薔薇，黄雲爛漫相因依。',128,'全唐诗/poet.song.88000.json','["剡中無數野薔薇，黄雲爛漫相因依。", "玉杯淺琢承墜露，金鐘倒挂搖晨暉。", "斑竹筍行三畝地，紅藥花開一尺圍。", "豆角嘗新小麥秀，來禽長向櫻桃肥。", "歌舌隨風柳外囀，翠花带水煙中飛。", "魚跳破浪奮赤鬛，鶴唳投松翻縞衣。", "鄉關萬里久無夢，巖壑四年今息機。", "叮嚀杜宇往江北，爲喚故人令早歸。"]'),
('21aef54f-657d-4a93-92d7-9bbcc30b410f','卜居獨秀山','李易','宋','宋诗','song-poetry','','[]','訪戴溪長近若耶，金庭雪對赤城霞。',64,'全唐诗/poet.song.88000.json','["訪戴溪長近若耶，金庭雪對赤城霞。", "沼從鵠舉添蕭索，峰似鸞翔解嘆嗟。", "每愛林間百種蝶，難忘竹外四時花。", "剡川圖上他年指，獨秀山前是我家。"]'),
('974a470a-c386-40c2-9ab3-77c0f1f13c76','貴門卜築','李易','宋','宋诗','song-poetry','','[]','亂後亦擇居，筮山山輙許。',192,'全唐诗/poet.song.88000.json','["亂後亦擇居，筮山山輙許。", "居民百餘家，喜甚手欲舞。", "云久聞公名，此幸殆天與。", "感兹鄭重意，時節共雞黍。", "剡川非沃野，地僻民更窶。", "趁時務擷茗，餘力工搗楮。", "寡婦念遺秉，洿池憐數罟。", "我欲教耦耕，盡力循南畝。", "桃杏種連山，深居可長處。", "東鄰有節士，酒酣乃發語。", "公昔起布衣，高誼掩前古。", "親擢類平津，决見逢真主。", "兩宮佇六飛，萬乘思一舉。", "交侵正倔強，蠭起益旁午。", "浩然公獨歸，偶出寧有補。", "默塞復何言，長嘆汗如雨。"]'),
('e26df4b0-f626-4062-aabc-116c19c9418c','剡溪幽居','李易','宋','宋诗','song-poetry','','[]','勝絕剡溪邊，巢枝度半年。',48,'全唐诗/poet.song.88000.json','["勝絕剡溪邊，巢枝度半年。", "燕回銜落絮，魚涌接飛泉。", "丹鼎山頭氣，茶爐竹外煙。", "幽居己成趣，佳句若爲傳。"]'),
('9676ade2-8cb4-4fa8-a82d-198a3ffbbbda','咏吐綬鳥','李易','宋','宋诗','song-poetry','','[]','昔人仙去斷丹梯，憔悴深山吐綬雞。',32,'全唐诗/poet.song.88000.json','["昔人仙去斷丹梯，憔悴深山吐綬雞。", "百轉和鳴非我事，漫將錦服擅幽棲。"]'),
('e5800165-2631-475b-817b-52be14aac84b','仙人洞','李易','宋','宋诗','song-poetry','','[]','雲巘分佳茗，風潭矗怪松。',48,'全唐诗/poet.song.88000.json','["雲巘分佳茗，風潭矗怪松。", "書疑黄石授，税可紫芝供。", "抵玉那驚鵲，探珠欲近龍。", "晚來聽近雨，乞水濯塵容。"]'),
('ede2a636-317a-4dd3-8a2b-f1a9b082bf8a','羅漢石','李易','宋','宋诗','song-poetry','','[]','鐵騎侵淮海，龍潭碧始通。',48,'全唐诗/poet.song.88000.json','["鐵騎侵淮海，龍潭碧始通。", "雲生倚寶刹，月出見珠宮。", "瀉澗水噴薄，依巖樹鬰葱。", "神交難獨擅，吾黨契元同。"]'),
('55c3044c-00d6-42f2-bcfd-dd0c302a9c70','珠溪','李易','宋','宋诗','song-poetry','','[]','玉龍劈山開，南騖肆奔猛。',72,'全唐诗/poet.song.88000.json','["玉龍劈山開，南騖肆奔猛。", "風蕩雪濛濛，月流光炯炯。", "壯氣動貴門，前驅入蛟井。", "萬籟息中消，一區臨絕境。", "奔雷有餘音，垂磬得深省。", "白雲何所聞，就宿孤峰頂。"]'),
('38e322ed-e9f6-480e-802d-d301b0f618f5','浴鵠沼','李易','宋','宋诗','song-poetry','','[]','鵠沼開新鑑，纖塵莫遺遮。',48,'全唐诗/poet.song.88000.json','["鵠沼開新鑑，纖塵莫遺遮。", "翠光爭水鳥，紅影湛山花。", "天外時分明，林端更蔚霞。", "高飛留舊跡，八付謫仙家。"]'),
('4ca12d1d-6ffa-43f7-a239-793e7ae3942b','發軍營塢','李易','宋','宋诗','song-poetry','','[]','褰裳涉流水，倚水送歸雲。',48,'全唐诗/poet.song.88000.json','["褰裳涉流水，倚水送歸雲。", "海角春潛到，山腰路忽分。", "伏龍應厭睡，飛電駭論文。", "鸛雀知機早，翻然不待羣。"]'),
('dba25729-af45-4c5c-be56-7ca35790f5a5','題驛壁','黄燁','宋','宋诗','song-poetry','','[]','帝駕陷塵沙，孤臣誓靡他。',24,'全唐诗/poet.song.88000.json','["帝駕陷塵沙，孤臣誓靡他。", "丹心期報主，白髮不知家。"]'),
('8db9a531-f4ae-4a34-885d-5ee223d2a9e2','句','趙野','宋','宋诗','song-poetry','','[]','複道密通繁衍宅，諸王誰似鄆王賢。',16,'全唐诗/poet.song.88000.json','["複道密通繁衍宅，諸王誰似鄆王賢。"]'),
('eabbdfac-b627-4a2b-ac0a-c484fc75a04e','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其一','楊景','宋','宋诗','song-poetry','','[]','旌旗風暖颺春暉，的皪寒光照鐵衣。',32,'全唐诗/poet.song.88000.json','["旌旗風暖颺春暉，的皪寒光照鐵衣。", "壯士銜枚聽傳令，邊鴻敢傍陣雲飛。"]'),
('2b1ea476-245e-4132-ae59-7bc05ab90623','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其二','楊景','宋','宋诗','song-poetry','','[]','奏罷清笳聽凱歌，行啟細柳拂彫戈。',32,'全唐诗/poet.song.88000.json','["奏罷清笳聽凱歌，行啟細柳拂彫戈。", "征人盡道從軍樂，城上黄雲喜氣多。"]'),
('a75ec707-9b87-4053-b5c6-8b7cc48fb45a','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其三','楊景','宋','宋诗','song-poetry','','[]','天兵十萬擁貔貅，紫塞年年大有秋。',32,'全唐诗/poet.song.88000.json','["天兵十萬擁貔貅，紫塞年年大有秋。", "不是頡羌求款附，爲君唾手取靈州。"]'),
('b071dbc3-4629-478f-bfca-eb2380d84383','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其四','楊景','宋','宋诗','song-poetry','','[]','正塞從來豫虜謀，好將忠赤報衙頭。',32,'全唐诗/poet.song.88000.json','["正塞從來豫虜謀，好將忠赤報衙頭。", "速修朝覲趨丹鳳，乞汝河西十二州。"]'),
('f9db9bd8-0ebc-4a8e-badc-594a551d9369','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其五','楊景','宋','宋诗','song-poetry','','[]','王畿諸將戍沙場，亦有家書寄雁行。',32,'全唐诗/poet.song.88000.json','["王畿諸將戍沙場，亦有家書寄雁行。", "不說邊庭征戰苦，侍郎恩意似汾陽。"]'),
('aaf154e3-3a57-4764-b7b2-4d33a78d530f','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其六','楊景','宋','宋诗','song-poetry','','[]','丈丈蛇矛錦甲新，虬鬚虎頭漢將軍。',32,'全唐诗/poet.song.88000.json','["丈丈蛇矛錦甲新，虬鬚虎頭漢將軍。", "彎弓盤馬當牙帳，雙發鳴髇入塞雲。"]'),
('48d2d003-d287-4f98-b145-a5f4c24bb8c2','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其七','楊景','宋','宋诗','song-poetry','','[]','控弦十萬漢蕃兵，行鼓分屯細柳營。',32,'全唐诗/poet.song.88000.json','["控弦十萬漢蕃兵，行鼓分屯細柳營。", "白面元戎心似鐵，不教羌騎近長城。"]'),
('f4939a82-7c70-41db-91be-52fe05abbf55','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其八','楊景','宋','宋诗','song-poetry','','[]','崆峒猛士射鵰還，三石雕弓月樣彎。',32,'全唐诗/poet.song.88000.json','["崆峒猛士射鵰還，三石雕弓月樣彎。", "爲問轅門何似勇，劃騎生馬注南山。"]'),
('6b481d5e-99a8-428f-b8b6-84bdb501b90c','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其九','楊景','宋','宋诗','song-poetry','','[]','招馬紅旗繡浪開，戰鼙百面打春雷。',32,'全唐诗/poet.song.88000.json','["招馬紅旗繡浪開，戰鼙百面打春雷。", "南山萬仞陰崖險，似箭紅塵一溜來。"]'),
('99f27234-df95-44bc-9b23-609dd196c837','政和二年三月廿四日鄜延帥府大閱即席呈獻帥座賈公凱歌  其一○','楊景','宋','宋诗','song-poetry','','[]','宿麥斜桑滿塞垣，彎已經不復射遊魂。',33,'全唐诗/poet.song.88000.json','["宿麥斜桑滿塞垣，彎已經不復射遊魂。", "華戎說罷干戈事，萬歲山呼荷至尊。"]'),
('bff3c914-979b-4732-b1ee-cd2eda161908','和唐刺史崔公壁間二絕  其一','張述','宋','宋诗','song-poetry','','[]','年□筋力覺潛衰，自楚踰年復此移。',32,'全唐诗/poet.song.88000.json','["年□筋力覺潛衰，自楚踰年復此移。", "偶見舊題追古昔，只應風月似當時。"]'),
('24240098-6122-482c-a6b5-e82d4548578c','和唐刺史崔公壁間二絕  其二','張述','宋','宋诗','song-poetry','','[]','春花凝露草凝煙，訟簡民淳屢有年。',32,'全唐诗/poet.song.88000.json','["春花凝露草凝煙，訟簡民淳屢有年。", "每念舊山歸未得，何妨於此醉林泉。"]'),
('111c18b7-1ffd-4599-aa42-416002769275','偶成','張述','宋','宋诗','song-poetry','','[]','星星雙鬢已驚秋，尚竊州符只自羞。',32,'全唐诗/poet.song.88000.json','["星星雙鬢已驚秋，尚竊州符只自羞。", "官冗更無丞掾委，誰哀老子得遨遊。"]'),
('c0a09c6e-be95-4857-8f2b-52dcd90c2bbc','讀許太史祭黄長睿文','翁挺','宋','宋诗','song-poetry','','[]','秘書丹旐返，旅殯尚丹陽。',48,'全唐诗/poet.song.88000.json','["秘書丹旐返，旅殯尚丹陽。", "海路三山遠，江流萬古長。", "交情惟太史，傳業冀諸郎。", "誰與銘泉壤，臨文淚數行。"]'),
('c9eaa3ae-05f2-433f-a229-e7d4b13160d1','送劉羲仲檢討歸南康','翁挺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','先生來東都，貌如林間鶴。',144,'全唐诗/poet.song.88000.json','["先生來東都，貌如林間鶴。", "聞名今見之，信難塵中著。", "諸儒紛藏寶，人進已反卻。", "眇然千載事，獨與復商略。", "斯人昔俊豪，世故熟斟酌。", "冥棲二十年，不爲幽禪著。", "秋風有所思，木落廬山脚。", "豈爲菰蒓念，亦負溪友約。", "清霜動車輪，不復生四角。", "想見胸府間，天地瀉寥廓。", "平生杜陵老，妙處倚山閣。", "歲晚或相從，應分半巖壑。"]'),
('bcaf5ef6-1e0f-4d16-b9a2-47129caae20f','晚坐碧雲塢二首  其一','翁挺','宋','宋诗','song-poetry','','[]','夕陽黯將沉，缺月遲未吐。',24,'全唐诗/poet.song.88000.json','["夕陽黯將沉，缺月遲未吐。", "滿眼玻璃堆，翻疑夢中覩。"]'),
('fa8dce1a-da32-45aa-98f6-6d8fd353e796','晚坐碧雲塢二首  其二','翁挺','宋','宋诗','song-poetry','','[]','玉樹秋益明，驪珠夜方吐。',24,'全唐诗/poet.song.88000.json','["玉樹秋益明，驪珠夜方吐。", "繞檻碧雲收，塵蹤故難覩。"]'),
('7193750d-f891-4ef9-96c9-07fbcf3c4cd2','早桂','翁挺','宋','宋诗','song-poetry','','[]','山深風露易凄清，樹老於人若有情。',32,'全唐诗/poet.song.88000.json','["山深風露易凄清，樹老於人若有情。", "萬里好秋尋不見，一花香處便分明。"]'),
('7592fb65-d86f-487c-be2d-1103eddf12e1','送僧','釋法具','宋','宋诗','song-poetry','','[]','灘聲嘈嘈雜雨聲，舍北舍南春水平。',32,'全唐诗/poet.song.88000.json','["灘聲嘈嘈雜雨聲，舍北舍南春水平。", "拄杖穿花出門去，五湖風浪白鷗輕。"]'),
('c6b28f0e-79c7-4fff-9e4c-9c17afd6ec9b','送翁士特','釋法具','宋','宋诗','song-poetry','','[]','朝入羊腸暮鹿頭，十三官驛是荆州。',32,'全唐诗/poet.song.88000.json','["朝入羊腸暮鹿頭，十三官驛是荆州。", "具車秣馬曉將發，寒燭燒殘語未休。"]'),
('587c378c-aea4-4365-900c-716e00ca95c9','竹軒二首  其一','釋法具','宋','宋诗','song-poetry','','[]','老竹排簷誰手種，山日未斜寒翠重。',32,'全唐诗/poet.song.88000.json','["老竹排簷誰手種，山日未斜寒翠重。", "六月散髪葉底眠，冷雨斜風頻入夢。"]'),
('f98da3a8-b585-43c3-9205-71383f9e5e54','竹軒二首  其二','釋法具','宋','宋诗','song-poetry','','[]','冬凋峰木雪縞廬，落眼青青卻笑渠。',32,'全唐诗/poet.song.88000.json','["冬凋峰木雪縞廬，落眼青青卻笑渠。", "花時吹筍排林上，吳州還見竹溪圖。"]'),
('7875b3ce-bbd4-481c-91fd-a47bc3094540','和子蒼三馬圖','釋法具','宋','宋诗','song-poetry','','[]','從來畫馬稱神妙，至今只說江都王。',96,'全唐诗/poet.song.88000.json','["從來畫馬稱神妙，至今只說江都王。", "將軍曹霸實季仲，沙苑丞相猶諸郎。", "龍眠居士善畫馬，獨與二子遙相望。", "兩馬駢立真驌驦，一馬脫去仍騰驤。", "浣花老人今已亡，嗚呼五馬誰平章。", "飽知畫肉亦畫骨，妙處不減黄無雙。"]'),
('8a4774ee-4174-4e88-986e-aa7e96c7f2e8','春日','釋法具','宋','宋诗','song-poetry','','[]','燒燈過了客思家，獨立衡門數暝鴉。',32,'全唐诗/poet.song.88000.json','["燒燈過了客思家，獨立衡門數暝鴉。", "燕子未歸梅落盡，小窗明月屬梨花。"]'),
('a82c31eb-b177-4f61-b72b-ff9466c61b4e','題煙篷','釋法具','宋','宋诗','song-poetry','','[]','曹植波瀾闊，曾爲若士遊。',48,'全唐诗/poet.song.88000.json','["曹植波瀾闊，曾爲若士遊。", "江湖流滿眼，天地入扁舟。", "散髪邀明月，停杯問白鷗。", "他年歸紫禁，夢亦繞滄洲。"]'),
('23f7cbc5-0f5d-4776-ac75-0f1234cf388b','絕句二首  其一','釋法具','宋','宋诗','song-poetry','','[]','鶴鳴九皋秋夜永，紙帳芙蕖臥燈影。',32,'全唐诗/poet.song.88000.json','["鶴鳴九皋秋夜永，紙帳芙蕖臥燈影。", "九州之外更九州，誰解摩心發深省。"]'),
('453acb6a-c53a-4992-90d0-3dd5c9f50fda','絕句二首  其二','釋法具','宋','宋诗','song-poetry','','[]','看了青燈夢不成，東風捲雪落寒聲。',32,'全唐诗/poet.song.88000.json','["看了青燈夢不成，東風捲雪落寒聲。", "半生客裏無窮恨，告訴梅花說到明。"]'),
('13f15c0e-c221-4f83-ab76-a7b760eb6f8f','游華頂峰','釋法具','宋','宋诗','song-poetry','','[]','行盡一徑龍蛇蟠，病身忽上青雲端。',192,'全唐诗/poet.song.88000.json','["行盡一徑龍蛇蟠，病身忽上青雲端。", "天公豈念客來遠，偶吹一陣松風寒。", "摩挲老眼坐嘆息，信有物表非人寰。", "去天尺五步可到，雲夢八九吞何難。", "微陽遠映衆山綠，景氣搖動如波瀾。", "青蘿吐花葉嫋嫋，淺水落石聲潺潺。", "盤空巨石碧如削，暗澹老樹蒼煙漫。", "簷牙卓地殿影出，蝸涎上階夜雨殘。", "昔人遺跡不復見，但見滿目圍蒼巒。", "懸知此地可送老，黄葉滿庭風閉關。", "玉京五城信不遠，神仙綬短誰能攀。", "妄庸柳泌真可笑，安用採藥乘朱轓。"]'),
('d9b0273a-f1dd-42b9-b1ef-b7a7f04d6bda','送僧之天台','釋法具','宋','宋诗','song-poetry','','[]','意在天台住過春，雪崖流水斷橋分。',32,'全唐诗/poet.song.88000.json','["意在天台住過春，雪崖流水斷橋分。", "今因送子入青嶂，老夢荒荒落冷雲。"]'),
('6cceb04b-6d36-4dc6-9f5e-39aea3ed6617','登道場山','釋法具','宋','宋诗','song-poetry','','[]','野吹竹色寒，下有古澗道。',24,'全唐诗/poet.song.88000.json','["野吹竹色寒，下有古澗道。", "牧兒放箠眠，牛馬齕風草。"]'),
('8413cd43-b149-4be5-b833-a73a0aa3f721','新興','釋法具','宋','宋诗','song-poetry','','[]','老子愛江水，江面開竹門。',24,'全唐诗/poet.song.88000.json','["老子愛江水，江面開竹門。", "江流竹影薄，子細見前村。"]'),
('e588f4db-8c6f-4aa3-9115-5a3ffd946041','客中會友','釋法具','宋','宋诗','song-poetry','','[]','愁中有句可消除，客裏無人問所須。',32,'全唐诗/poet.song.88000.json','["愁中有句可消除，客裏無人問所須。", "竹屋青燈雨聲冷，白頭相對話江湖。"]'),
('b49be14a-9368-47a7-964e-69151e9d88fd','東山','釋法具','宋','宋诗','song-poetry','','[]','窗中遠看眉黛綠，盡是當年歌吹愁。',32,'全唐诗/poet.song.88000.json','["窗中遠看眉黛綠，盡是當年歌吹愁。", "鳥語夕陽人不見，薔薇花暗小江流。"]'),
('f7165c2a-23e5-4a0a-a874-de6420c91f7b','月夜游錢塘江','釋法具','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','小舟爲我載月色，白沙翠竹光相射。',32,'全唐诗/poet.song.88000.json','["小舟爲我載月色，白沙翠竹光相射。", "自從李白下金陵，四百年無此豪逸。"]'),
('fb05c199-b408-4a3e-8a6b-f49d6207ad67','題華蓋仙山院默齋','釋法具','宋','宋诗','song-poetry','','[]','道人掛口蒼煙裏，萬象無聲忽轉雷。',32,'全唐诗/poet.song.88000.json','["道人掛口蒼煙裏，萬象無聲忽轉雷。", "老去不知塵世事，東風又上屋頭梅。"]'),
('ee1a5f8a-4add-4209-a4f6-a37824547337','句','呼延韓仲','宋','宋诗','song-poetry','','[]','況此春欲暮，風溫脫花鬚。',12,'全唐诗/poet.song.88000.json','["況此春欲暮，風溫脫花鬚。"]'),
('10352fcf-f312-47ad-8900-3789da0b193a','句','葛道人','宋','宋诗','song-poetry','','[]','百囀已休鶯哺子，三眠初罷柳飛花。',16,'全唐诗/poet.song.88000.json','["百囀已休鶯哺子，三眠初罷柳飛花。"]'),
('d6fc5d48-4b9c-4545-9038-1ef52e940d47','柳眼','劉博文','宋','宋诗','song-poetry','','[]','青眼相看君可知，精神渾在艷陽時。',32,'全唐诗/poet.song.88000.json','["青眼相看君可知，精神渾在艷陽時。", "只因嫁得東君後，兩淚相看是別離。"]'),
('35e0121d-b585-4c53-a3ec-dfe4f95a4e28','程之徒','李正民','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','堂堂王夫子，實爲鄉曲英。',288,'全唐诗/poet.song.88000.json','["堂堂王夫子，實爲鄉曲英。", "十年遊太學，冬雪而秋螢。", "南宫掇異等，四海馳儁聲。", "未展霄漢志，憂患遽所丁。", "自言程之徒，高論何峥嶸。", "彬彬媚學子，鼓篋稱諸生。", "何必騖時文，但貴存其誠。", "道義苟內充，爵禄必爾纓。", "吾師昔如斯，草澤膺弓旌。", "勸講邇英閣，探頤多研精。", "祝李樂其說，談辨惟縱横。", "仲子頗守常，歸來自窮經。", "一日賢詔下，折桂何芳馨。", "先生遂薦之，横經闔閭城。", "又欲薦祝子，可方古巖耕。", "宜從布衣起，知足平攙搶。", "貴公問其人，科舉頗所更。", "答言彼材豪，不肯循度程。", "貴公聞之笑，何以取官榮。", "推轂既未效，鼓枻歸洞庭。", "先生躋禁從，仲子亦飛騰。", "召對趨九陛，一言帝心傾。", "亟命遷京秩，訓詞人所驚。", "庶可共學者，品題自師評。"]'),
('54654dff-9162-48f0-95ea-1eb14252b618','寄彦章內翰','李正民','宋','宋诗','song-poetry','','[]','少希端木賜，遇事多臆度。',240,'全唐诗/poet.song.88000.json','["少希端木賜，遇事多臆度。", "老矣智慮衰，所見頗疏略。", "都將幾許鐵，鑄成一大錯。", "歸來自悔咎，俛仰懷愧怍。", "經營水雲居，逝將老寂寞。", "爲欠草堂資，此計殊牢落。", "欣聞故人近，鐵甕羅戟槊。", "坐覽江山勝，守彼北門籥。", "嘗觀萬卷書，素號精且博。", "爾雅偶未熟，遂中蟛蜞惡。", "那知謝太傅，雅志在丘壑。", "䆉稏連百頃，場圃正收穫。", "黄花已經霜，餘英猶爍爍。", "仍攜縹緲人，有酒可酙酌。", "老拙失所望，宛如魚在涸。", "鬼笑伯龍貧，人憂顔氏樂。", "海瀕富蝦菜，尚有驕藜藿。", "妄意苕霅間，數畝躬耕鑿。", "相望幸不遠，鄙吝資發藥。", "扁舟泛烟波，乘興聊一噱。"]'),
('35d4d829-c6ac-442c-beed-3254989cc01c','枯木歎','李正民','宋','宋诗','song-poetry','','[]','海隅有喬木，枝葉多離披。',120,'全唐诗/poet.song.88000.json','["海隅有喬木，枝葉多離披。", "庇廕數畝地，鬱鬱凌雲霓。", "歲久漸生蠹，蠹盛木乃衰。", "朝蠹食其葉，暮蠹食其枝。", "蠹蟲日滋長，食飽肌肉肥。", "衆葉漸零落，枝榦亦枯萎。", "僵仆大道側，但存乾死皮。", "羣蠹盡羽化，鼓舞四散飛。", "蠹各得其所，此木誰憐之。", "吾嗟守株叟，抱膝空傷悲。"]'),
('ad173c6d-44c5-4a65-bcb6-e8b891280899','和元叔秋懷','李正民','宋','宋诗','song-poetry','','[]','隴頭飛浮雲，山色時隱蔽。',120,'全唐诗/poet.song.88000.json','["隴頭飛浮雲，山色時隱蔽。", "曦馭轉層霄，漸減炎歊熾。", "商飇折蒲葦，清露泣蘭蕙。", "梁燕話歸期，塞鴻懷遠志。", "畸人感物化，閲世如夢寐。", "滴階聞雨聲，嚼蠟忘世味。", "故園久離阻，浩蕩起歸意。", "髙詠秋興篇，安仁有佳思。", "自憐守幽獨，壯懷日憔悴。", "聊擷秋菊英，銜盃玩浮世。"]'),
('816a4d91-51dd-4364-8583-d44ade13a865','送聞人伯封','李正民','宋','宋诗','song-poetry','','[]','應奉見車工，楊愔逢選士。',240,'全唐诗/poet.song.88000.json','["應奉見車工，楊愔逢選士。", "古人記半面，落落纔一二。", "羡君眸子明，洞徹無纖翳。", "小吏曛黑來，匆匆便能識。", "憶昔到君家，經史肆論議。", "簡編討遺忘，指擿須臾至。", "别來五六年，學問益純粹。", "薦名上天閽，嚢錐見鋒鋭。", "少年好奇偉，萬卷欲盡記。", "春官方用賦，所尚在詞藝。", "前人存矩矱，雕篆有深意。", "寒窗務探討，詎可輕小技。", "窮理盡性學，推論良有自。", "士方騖場屋，未能臻極摯。", "山中有老儒，發藥祛其蔽。", "潛心造妙理，離合見同異。", "我懷伯業能，嗜學忘肉味。", "摩笈得異書，事理了無滯。", "况子氣方豪，青萍嘗一試。", "孜孜其勉旃，青霄將自致。"]'),
('b344fc8e-d45a-4244-aaea-332ea9f152aa','春日城東送韓玉汝赴兩浙轉運以池塘生春草園柳變鳴禽爲韻分得生字','李正民','宋','宋诗','song-poetry','','[]','野岸漲流水，名園紛雜英。',96,'全唐诗/poet.song.88000.json','["野岸漲流水，名園紛雜英。", "旭景冠蓋集，清談尊酒傾。", "重此臺省秀，駕言江海行。", "已喜懷抱粹，况推材實精。", "衆許極髙遠，時方藉經營。", "詎止富中廩，固將澤東氓。", "還當本朝用，不待芳歲更。", "功名自兹始，勿嘆華髪生。"]'),
('4380524f-6f31-463f-9327-1e1fdfea6098','寄題史伯魚讀書堂','李正民','宋','宋诗','song-poetry','','[]','臧室繙經何太漫，鄴侯萬軸新堪玩。',128,'全唐诗/poet.song.88000.json','["臧室繙經何太漫，鄴侯萬軸新堪玩。", "長大誰如伯業勤，晝眠多似邊韶慢。", "斯堂扁榜號讀書，讀之百過樂有餘。", "焚膏繼晷自克己，彬彬學子顔之徒。", "念我壯年遊天禄，萬卷盡觀如不足。", "羽陵蠹簡拂蟫魚，太一青藜曾照燭。", "辛勤白髪但嘗膽，燕坐茅齋猶泛覽。", "年來老眼漸昏眵，每展青編憎墨淡。"]'),
('2041001e-7eb9-4b2d-8dab-2946adea4d9a','今歲梅花春中猶未開因思三衢冬月之盛作長句','李正民','宋','宋诗','song-poetry','','[]','前年柯山芳意早，肯使寒梅例枯槁。',128,'全唐诗/poet.song.88000.json','["前年柯山芳意早，肯使寒梅例枯槁。", "溪邊幾樹發偏繁，牆角數枝看更好。", "玉顔冒雪不奈寒，香心怯雨尤相惱。", "南枝爛漫北枝催，空惜飄零綴芳草。", "朅來海角風景遲，經冬不見端可疑。", "紅蕚涉春纔似染，青苞映日未全披。", "千山隔兮萬山阻，想見瑶英詎如許。", "一枝誰與寄相思，回首舊遊心獨苦。"]'),
('88c6a434-de26-445a-b9a5-68ee58958407','息交行','李正民','宋','宋诗','song-poetry','','[]','君不見子列禦寇居鄭圃，四十餘年人莫睹。',230,'全唐诗/poet.song.88000.json','["君不見子列禦寇居鄭圃，四十餘年人莫睹。", "外遊不若務內觀，食豨如人忘爾汝。", "又不見玉川先生洛城裏，閉關不出歲踰紀。", "狂吟大句語驚人，勸之請謁輒掩耳。", "古來賢達貴安閑，豈務奔走塵埃前。", "深居簡出悔吝少，治心養氣精神全。", "我念奇窮自平昔，險阻艱難多所歷。", "十年京洛困虀鹽，五載江湖負覊靮。", "比沭天恩處閑散，琳宫賦禄容家食。", "老僧參罷返林泉，病馬力疲棲皂櫪。", "掃除一室空復空，收還魂魄安其躬。", "衣冠深藏罷應接，杜門却掃閑奴僮。", "放懷書史得真樂，坐忘乃與希微通。", "不須疑我何爲爾，亦有文字如長虹。"]'),
('2d733b2c-431d-43c6-8b31-548ebcb9d796','余君贈我以茶僕答以酒','李正民','宋','宋诗','song-poetry','','[]','投我以建溪北焙之新茶，報君以烏程若下之醇酒。',196,'全唐诗/poet.song.88000.json','["投我以建溪北焙之新茶，報君以烏程若下之醇酒。", "茶稱瑞草世所珍，酒爲美禄天之有。", "碾碎龍團乳滿甌，傾來竹葉香盈卣。", "滌煩療熱氣味長，消憂破悶醺酣久。", "君不見竟陵陸羽號狂生，細烟小鼎親煎烹。", "扁舟短棹江湖上，茶爐釣具常隨行。", "又不見沛國劉伶稱達士，捧罌銜盃忘世累。", "無思無慮樂陶陶，席地幕天聊快意。", "欲醉則飲酒，欲醒則烹茶。", "酒狂但酩酊，茶癖無咨嗟。", "古今二者皆靈物，蕩滌肺腑無紛華。", "清風明月雅相得，君心自此思無邪。"]'),
('f0973e67-8cbb-4ff6-8b9a-38b9095c793d','覽新達詩卷有感','李正民','宋','宋诗','song-poetry','','[]','昔人作詩例苦窮，今人作詩乃得通。',96,'全唐诗/poet.song.88000.json','["昔人作詩例苦窮，今人作詩乃得通。", "何意崩騰永嘉末，復見正始之遺風。", "杜陵太白困覉旅，孟郊賈島亦不逢。", "聖俞不得一校理，子美謫死吳山東。", "升沈富貴何足道，名聲顯赫摩蒼穹。", "新編起予爲太息，萬事得失疇能同。"]'),
('50d3fe09-47af-4742-8b19-88f9775ebf91','寄邦求擬南食作','李正民','宋','宋诗','song-poetry','','[]','不到浙鄉辜負口，昔人有語真可取。',192,'全唐诗/poet.song.88000.json','["不到浙鄉辜負口，昔人有語真可取。", "我住柯山三四年，厭飫蕨薇幾噎嘔。", "扁舟乘流來檇李，極目江湖幾千里。", "白魚市上爛如銀，紫蠏籪頭多似蟻。", "舒鳬帖帖墮水面，亦有麕麞來近縣。", "黄閒射雉出林中，田鼠化鶉毛彩絢。", "况復海物錯難名，蝤蛑輪囷似斗升。", "紛紛蝦蛤不足數，淡菜蚶蠣資多腥。", "僻居海岸久寂寞，寒擁紅爐聊獨酌。", "芼之橙桂薦玉盤，不比屠門空大嚼。", "我念孫卿久滯留，欲致數品無傳郵。", "烹羊炰羔自不惡，更有負郭新良疇。"]'),
('5078b6a5-8080-4ab4-b2e4-b6628fb7f9f5','寄尹叔','李正民','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖三萬六千頃，中有長橋墮虹影。',243,'全唐诗/poet.song.88000.json','["太湖三萬六千頃，中有長橋墮虹影。", "茅屋漁舟數百家，譙門打鼓官爲令。", "往來舟楫何紛紛，拜揖將迎皆要人。", "自從兵興急供億，千槍萬槊如魚鱗。", "又有强宗并大姓，索課催租惟所命。", "忽然平地起風波，造謗興讒喧衆聽。", "歲前官家欲移蹕，葦席茅茨千百室。", "科敷比户與僧坊，髙下等差皆普及。", "一時應辦姑求備，嘖有煩言長官罪。", "差官密切來體量，三尺深文想難避。", "君不見海鹽令尹祝夫子，去年蒙恩當百里。", "催科急迫不忍言，鞭撻黎民非所喜。", "一朝解印謝疲民，至今豪强猶切齒。", "國讐未雪兵未休，安得斯民無瘡痏。", "但願中興功業成，盡鎖劍戟充耘耔。"]'),
('ac462e51-8c73-455a-a74c-7c680995b61c','寄祝舜俞','李正民','宋','宋诗','song-poetry','','[]','彭澤縣令五斗米，陶潛輕之辭百里。',144,'全唐诗/poet.song.88000.json','["彭澤縣令五斗米，陶潛輕之辭百里。", "蜀道嶮崎九折坂，王陽畏之能自免。", "君今行事古人同，要作閑官興非淺。", "胡爲窮臘遠覉遊，路指太末干賢侯。", "風霜皴膚雪撲面，舟幾折櫓車摧輈。", "歸來贈我雙鯉魚，尺素中藏一幅書。", "具言勞苦自悔責，乃知世事非良圖。", "苕溪春回波泛綠，况有淲田可耕斸。", "我今亦欲賦歸與，便約臨流結茅屋。"]'),
('b659e984-b720-4580-ade6-f8d0229826da','早春次韻  其一','李正民','宋','宋诗','song-poetry','','[]','春色方薫草，南來未見鶯。',48,'全唐诗/poet.song.88000.json','["春色方薫草，南來未見鶯。", "身閑聊適野，志弱敢論兵。", "落落松筠質，欣欣桃柳情。", "不妨聯騎出，蠻榼亦攜行。"]'),
('78d33348-9d2c-4a2e-8b3c-dab842bdbb68','早春次韻  其二','李正民','宋','宋诗','song-poetry','','[]','平原齊吐麥，幽谷未遷鶯。',48,'全唐诗/poet.song.88000.json','["平原齊吐麥，幽谷未遷鶯。", "王者雖無戰，元戎盍治兵。", "山川羈客恨，桃李故園情。", "何處花先發，籃輿取次行。"]'),
('3f856d4d-35b1-49eb-accd-9fd16d21a811','早春次韻  其三','李正民','宋','宋诗','song-poetry','','[]','乍暖先催柳，餘寒尚蟄鶯。',48,'全唐诗/poet.song.88000.json','["乍暖先催柳，餘寒尚蟄鶯。", "淮壖嚴斥堠，江國偃戎兵。", "得句重尋律，銜杯舊有情。", "經營賴耆哲，閑客且閑行。"]'),
('d6a12d91-51b8-4ee1-a7f6-16e2bc7141e2','早春次韻  其四','李正民','宋','宋诗','song-poetry','','[]','佳人思燕燕，公子眷鶯鶯。',48,'全唐诗/poet.song.88000.json','["佳人思燕燕，公子眷鶯鶯。", "酒户如懸磬，詩壇未息兵。", "林花還自發，巢鵲豈無情。", "好泛清溪曲，扁舟盡日行。"]'),
('b243b89d-70a3-43df-9b8a-852931293b68','早春次韻  其五','李正民','宋','宋诗','song-poetry','','[]','畫梁將宿燕，楊柳欲藏鶯。',48,'全唐诗/poet.song.88000.json','["畫梁將宿燕，楊柳欲藏鶯。", "賢傑籌前箸，寰區望洗兵。", "懸鶉空自愧，磨楯敢言情。", "聞說山西將，揚威正啓行。"]'),
('66be6461-b636-4e2c-b3ce-a6ab5df7d838','少遊','李正民','宋','宋诗','song-poetry','','[]','少遊詞藝域，文陣欲横行。',48,'全唐诗/poet.song.88000.json','["少遊詞藝域，文陣欲横行。", "徐庶髙朋友，王家好弟兄。", "鸞龍觀筆落，珠玉鬭詩成。", "老境猶思舊，忘言看後生。"]'),
('c878e8ed-3531-4b21-aa72-7379002f4aae','夜坐','李正民','宋','宋诗','song-poetry','','[]','鄉井千餘里，江湖一病身。',48,'全唐诗/poet.song.88000.json','["鄉井千餘里，江湖一病身。", "新年逢甲子，清夜守庚申。", "冷落爐中火，溟濛榻上塵。", "永懷愁不寐，惟聽漏聲頻。"]'),
('ef436bc8-3bb6-4078-8553-1e5bb34331c1','久雨不解次韻  其一','李正民','宋','宋诗','song-poetry','','[]','雪後仍霖雨，閑中積旅愁。',48,'全唐诗/poet.song.88000.json','["雪後仍霖雨，閑中積旅愁。", "雷車聲忽轉，雲陣濕難收。", "坐久頻搖膝，詩成苦掉頭。", "静觀身世事，泛泛一虚舟。"]'),
('88c0428f-3d9c-41da-acb2-be68ad5a8af9','久雨不解次韻  其二','李正民','宋','宋诗','song-poetry','','[]','易覺東陽瘦，難祛庾信愁。',48,'全唐诗/poet.song.88000.json','["易覺東陽瘦，難祛庾信愁。", "雪寒殘更積，雨慣落還收。", "妄欲附驥尾，終難料虎頭。", "五湖波浪闊，歸泛釣魚舟。"]'),
('87990ab7-bb7a-4945-9088-7d34ead09eda','久雨不解次韻  其三','李正民','宋','宋诗','song-poetry','','[]','春事寒應晚，旅人閑轉愁。',48,'全唐诗/poet.song.88000.json','["春事寒應晚，旅人閑轉愁。", "空階宵更滴，遠靄曉難收。", "嗜好藏龜殻，行年問虎頭。", "孫郎多智策，箭重却回舟。"]'),
('52a6d791-456c-4849-bce5-6acf735e42eb','久雨不解次韻  其四','李正民','宋','宋诗','song-poetry','','[]','閻閭苦貧病，皂隸亦饑愁。',48,'全唐诗/poet.song.88000.json','["閻閭苦貧病，皂隸亦饑愁。", "入夜聲尤急，連山勢未收。", "無言閑麈尾，有意念刀頭。", "獨酌難成醉，空乾瑶玉舟。"]'),
('48bbddc1-0ed3-46c5-bf56-1b4355d21721','建昌寄紙被','李正民','宋','宋诗','song-poetry','','[]','擣楮爲衾被，旴江遠寄將。',48,'全唐诗/poet.song.88000.json','["擣楮爲衾被，旴江遠寄將。", "夜寒如挾纊，晨起訝凝霜。", "雅稱維摩室，增輝杜老堂。", "心平可髙臥，蝴蝶夢飛揚。"]'),
('49e8f70e-43f5-476e-a8b6-09276ee9432c','得平叔信','李正民','宋','宋诗','song-poetry','','[]','越絕覉遊久，相思斷旅魂。',48,'全唐诗/poet.song.88000.json','["越絕覉遊久，相思斷旅魂。", "漂零鴻雁序，憔悴鶺鴒原。", "解綬辭巖邑，全家寄嶼村。", "何時能過我，詩律細重論。"]'),
('dea72455-8d79-4816-8334-38262b0fa97d','雜詩  其一','李正民','宋','宋诗','song-poetry','','[]','海岸收殘雨，西風放晚晴。',48,'全唐诗/poet.song.88000.json','["海岸收殘雨，西風放晚晴。", "霜林紅未脫，寒草綠猶生。", "老覺光陰速，閑觀世累輕。", "端憂多暇日，憔悴庾蘭成。"]'),
('54410e5c-a858-484f-af43-c54a284937ef','雜詩  其二','李正民','宋','宋诗','song-poetry','','[]','喬木丘園古，疏籬舍屋深。',48,'全唐诗/poet.song.88000.json','["喬木丘園古，疏籬舍屋深。", "路隨山脚轉，岸近海潮侵。", "樵叟欣相遇，禪房許獨尋。", "杖藜聊縱步，乘興欲投簪。"]'),
('eeaeefa3-5988-45a0-86f3-abd930f16c88','雜詩  其三','李正民','宋','宋诗','song-poetry','','[]','衰病驚殘歲，生涯類轉蓬。',48,'全唐诗/poet.song.88000.json','["衰病驚殘歲，生涯類轉蓬。", "滔滔嬾回首，默默但觀空。", "山映歸雲白，窗留落照紅。", "地偏人跡絕，厖臥短籬東。"]'),
('84064762-75e4-4b4c-a96e-598d2c8ee7ee','雜詩  其四','李正民','宋','宋诗','song-poetry','','[]','放曠人間世，棲遲一草堂。',48,'全唐诗/poet.song.88000.json','["放曠人間世，棲遲一草堂。", "神交傳遠信，漁父許同行。", "黄菊猶霑雨，丹楓未隕霜。", "午餘幽夢斷，清磬出禪房。"]'),
('8d7b0b7b-4e1e-43ef-9493-e2f0013b7208','雜詩  其五','李正民','宋','宋诗','song-poetry','','[]','岸幘茅簷下，西郊轉夕曛。',48,'全唐诗/poet.song.88000.json','["岸幘茅簷下，西郊轉夕曛。", "暮鵶低接翅，寒鵲閙鳴羣。", "有炭勝東野，無氈類廣文。", "虛名三十載，外物漫浮雲。"]'),
('3be278e2-3860-4262-b1b2-259708229678','雜詩  其六','李正民','宋','宋诗','song-poetry','','[]','野岸營茅屋，修篁出短籬。',48,'全唐诗/poet.song.88000.json','["野岸營茅屋，修篁出短籬。", "紙窗迎暖日，石硯結冰凘。", "種菊陶元亮，栽松杜拾遺。", "田園已蕪沒，飄泊竟何之。"]'),
('52ace8d6-2de6-487c-b416-4d8d0d7ba73d','雜詩  其七','李正民','宋','宋诗','song-poetry','','[]','九醖聞新熟，三盃且自娛。',48,'全唐诗/poet.song.88000.json','["九醖聞新熟，三盃且自娛。", "已能開杜室，寧復論兵厨。", "浮蟻盈春甕，流霞注魯壺。", "醉來聊欲寐，不覺日還晡。"]'),
('a3dc78d6-9897-486f-bd2c-91544e8b1ff4','雜詩  其八','李正民','宋','宋诗','song-poetry','','[]','通宵風雨急，甕牖曉光催。',48,'全唐诗/poet.song.88000.json','["通宵風雨急，甕牖曉光催。", "冷枕驚殘夢，寒爐聚宿灰。", "作文無處賣，覓句有時來。", "疏嬾忘巾櫛，柴門且未開。"]'),
('305ea857-2a09-4f7b-989d-e9624e7c388e','雜詩  其九','李正民','宋','宋诗','song-poetry','','[]','歲晏多風雨，寒雲曉更濃。',48,'全唐诗/poet.song.88000.json','["歲晏多風雨，寒雲曉更濃。", "晚菘長乍翦，香稻細新舂。", "路遠思行客，年荒嘆老農。", "秖園人不到，惟聽飯時鐘。"]'),
('29572378-656b-46a4-9621-5f7a82206b27','雜詩  其一○','李正民','宋','宋诗','song-poetry','','[]','汲汲謀三徑，區區卜一廛。',48,'全唐诗/poet.song.88000.json','["汲汲謀三徑，區區卜一廛。", "艱難歸舊隱，荏苒嘆流年。", "欲設維摩榻，重尋子敬氈。", "飄零來海角，華髪已盈顛。"]'),
('effab273-7815-4e20-9936-d9b92b3884a4','雜詩  其一一','李正民','宋','宋诗','song-poetry','','[]','久雨渾無節，重雲凝不收。',48,'全唐诗/poet.song.88000.json','["久雨渾無節，重雲凝不收。", "朔風吹甕牖，寒色透貂裘。", "幸不妨農務，何堪助客愁。", "擁爐消短晷，閉户但商謳。"]'),
('f9486905-fb5e-4ae4-a7fe-f46bca877615','春雪次韻  其一','李正民','宋','宋诗','song-poetry','','[]','寒風初淅瀝，密雪遽霏微。',48,'全唐诗/poet.song.88000.json','["寒風初淅瀝，密雪遽霏微。", "冷敵鵝黄酒，輕沾駝褐衣。", "未教新柳展，且伴落梅飛。", "惟有翟廷尉，門前鳥雀稀。"]'),
('e252153c-6d1b-43c8-a221-da637147328b','春雪次韻  其二','李正民','宋','宋诗','song-poetry','','[]','花猶吹六出，氣已應三微。',48,'全唐诗/poet.song.88000.json','["花猶吹六出，氣已應三微。", "路破公車履，祥呈光禄衣。", "乍疑鷴失素，稍怪鷺于飛。", "盤瓠空驚走，南方此瑞稀。"]'),
('14d4456d-832e-4722-9e94-d1b4c88b8c44','再次春雪韻  其一','李正民','宋','宋诗','song-poetry','','[]','旬浹寒彌急，陽春暖尚微。',48,'全唐诗/poet.song.88000.json','["旬浹寒彌急，陽春暖尚微。", "西華愁葛帔，漁父點蓑衣。", "京洛殘堪望，龍山度正飛。", "麟經書大雪，此瑞古今稀。"]'),
('5da092b1-d02a-4178-b650-70c263aea00b','再次春雪韻  其二','李正民','宋','宋诗','song-poetry','','[]','萬壑鋪平練，千巖鎖翠微。',48,'全唐诗/poet.song.88000.json','["萬壑鋪平練，千巖鎖翠微。", "車能翻縞带，塵不化緇衣。", "撼樹桄榔滿，張圖蛺蝶飛。", "敲門傳詩卷，此曲郢中稀。"]'),
('cac1527e-6a7e-4a3f-8d84-906faef1f966','挽劉刑部  其一','李正民','宋','宋诗','song-poetry','','[]','西漢于張手，傳家舊得名。',48,'全唐诗/poet.song.88000.json','["西漢于張手，傳家舊得名。", "金科惟尚恕，棘寺每持平。", "丹筆流餘慶，朱轓藹政聲。", "他年門下客，接武位秋卿。"]'),
('fcdc9354-9afc-4a20-b2e0-65a8f9f09cdb','挽劉刑部  其二','李正民','宋','宋诗','song-poetry','','[]','避地辭髙密，僑居寓武原。',48,'全唐诗/poet.song.88000.json','["避地辭髙密，僑居寓武原。", "放懷樂棋酒，餘力治田園。", "方茂三松壽，俄成萬日墦。", "九原簫鼓咽，難駐已招魂。"]'),
('3edbe90b-ef8e-411b-8cfb-cfb38e78f1fe','挽曾公衮寶文  其一','李正民','宋','宋诗','song-poetry','','[]','靖國開皇極，先公秉化鈞。',48,'全唐诗/poet.song.88000.json','["靖國開皇極，先公秉化鈞。", "謝庭知有子，孫閤遂延賓。", "烜赫蕭周上，蒼黄屈賈鄰。", "欲明當日事，正論墨猶新。"]'),
('9dde39c1-de34-41fb-8868-afdd80a658bf','挽曾公衮寶文  其二','李正民','宋','宋诗','song-poetry','','[]','際會光華旦，傳家各有人。',48,'全唐诗/poet.song.88000.json','["際會光華旦，傳家各有人。", "榮名今已矣，陳迹重悲辛。", "曷報生芻禮，難留玉樹春。", "隼旟空望斷，清淚落衣巾。"]'),
('230d42a0-ded0-4906-977a-686beb46269f','挽沈伯華','李正民','宋','宋诗','song-poetry','','[]','望出東陽裔，蟬聯濟美材。',48,'全唐诗/poet.song.88000.json','["望出東陽裔，蟬聯濟美材。", "海邦歌政化，澤國早歸來。", "甲第朱門掩，佳城白日開。", "松風九原陌，薤露有餘哀。"]'),
('6d15eafd-f8ab-4cac-a48b-0705b88516d3','挽劉朝請  其一','李正民','宋','宋诗','song-poetry','','[]','世德流芳遠，身兼五福全。',48,'全唐诗/poet.song.88000.json','["世德流芳遠，身兼五福全。", "華堂優几杖，蠟屐訪林泉。", "白髪光陰永，青雲嗣子賢。", "佳城開吉兆，松柏已蒼然。"]'),
('ce78ac4b-9df3-4c28-8499-37ccde0d2d1f','挽劉朝請  其二','李正民','宋','宋诗','song-poetry','','[]','眉壽人生貴，題輿善政聞。',48,'全唐诗/poet.song.88000.json','["眉壽人生貴，題輿善政聞。", "中心如止水，外物等浮雲。", "方樂千鍾養，俄成萬日墳。", "欲知流慶遠，霅水自沄沄。"]'),
('21c9ab12-d821-40c2-b4ea-bc1f049b06f9','挽廣川先生','李正民','宋','宋诗','song-poetry','','[]','萬卷胸中富，千年筆下新。',48,'全唐诗/poet.song.88000.json','["萬卷胸中富，千年筆下新。", "廣川揚素業，延閣想芳塵。", "晚陟螭坳峻，俄留鳯沼津。", "遺書應滿篋，不愧泣麒麟。"]'),
('87acadd2-ccf5-4b78-b495-7caad8f1a8f0','挽鍾處士','李正民','宋','宋诗','song-poetry','','[]','日昊身猶健，居閑道更優。',48,'全唐诗/poet.song.88000.json','["日昊身猶健，居閑道更優。", "庭栽蘭九畹，户種橘千頭。", "惠施曾無倦，陰功祗自修。", "荀裴門户壯，他日振餘休。"]'),
('1ade551f-5c6a-457c-9c2f-5c1ff6e0d389','挽綦內翰  其一','李正民','宋','宋诗','song-poetry','','[]','扈蹕來江表，同時掌掖垣。',48,'全唐诗/poet.song.88000.json','["扈蹕來江表，同時掌掖垣。", "鯨波連畫鷁，鹿野對清樽。", "涉世行藏異，論交道義敦。", "遽成生死隔，回首淚潺湲。"]'),
('2139795d-754a-4d05-9356-dadbe1c9805c','挽綦內翰  其二','李正民','宋','宋诗','song-poetry','','[]','鼇禁凝嚴地，雍容侍北扉。',48,'全唐诗/poet.song.88000.json','["鼇禁凝嚴地，雍容侍北扉。", "花磚朝直晚，蓮燭夜分歸。", "玉節恩雖異，金甌事已非。", "飄零舊僚友，華髪老漁磯。"]'),
('d2799822-7ed1-400a-8eda-4f923b0ed0ae','挽綦內翰  其三','李正民','宋','宋诗','song-poetry','','[]','東土游觀樂，西亭風景悲。',48,'全唐诗/poet.song.88000.json','["東土游觀樂，西亭風景悲。", "漫餘曾躡屐，空覆舊傳巵。", "髙密山川隔，丹邱草木滋。", "凄涼謝道藴，泣對白紗帷。"]'),
('1f6eb66c-f317-431b-ac92-716b48cf7d00','挽魯奉議  其一','李正民','宋','宋诗','song-poetry','','[]','華胄流芳遠，平湖世載昌。',48,'全唐诗/poet.song.88000.json','["華胄流芳遠，平湖世載昌。", "鯉庭遵善教，龜組賁恩章。", "勞佚身兼適，悲歡念兩忘。", "平生修凈業，歸路指西方。"]'),
('8cabc7d9-cbad-4557-b120-d22b5d83f06c','挽魯奉議  其二','李正民','宋','宋诗','song-poetry','','[]','盛大身攸致，勤勞力克堪。',48,'全唐诗/poet.song.88000.json','["盛大身攸致，勤勞力克堪。", "仁心兼五福，慶澤在諸男。", "經罷翻靈運，人知弔老聃。", "百年嗟已矣，終始自無慚。"]'),
('9dd89b6b-da9b-4c6d-84e2-46dc42788d6b','挽胡茂老樞密  其一','李正民','宋','宋诗','song-poetry','','[]','盛際符千載，中朝第一人。',48,'全唐诗/poet.song.88000.json','["盛際符千載，中朝第一人。", "鳯池鳴委佩，朱邸奉重輪。", "右府謀猷密，殊鄰意氣伸。", "佐時遺事業，誰爲勒蒼珉。"]'),
('f781c725-287a-4372-9cd0-9f4a0bae53fa','挽胡茂老樞密  其二','李正民','宋','宋诗','song-poetry','','[]','人物熙朝盛，瓊林夐出羣。',48,'全唐诗/poet.song.88000.json','["人物熙朝盛，瓊林夐出羣。", "髙名題鴈塔，平步上青雲。", "未應三壬兆，先修萬日墳。", "丹臺應有籍，脫屐謝塵氛。"]'),
('f3f03093-ae9f-48a2-b434-c56a98c3f368','挽胡茂老樞密  其三','李正民','宋','宋诗','song-poetry','','[]','昔日蓬山會，平居笑語親。',48,'全唐诗/poet.song.88000.json','["昔日蓬山會，平居笑語親。", "薄材陪賈馬，髙義繼雷陳。", "南國居方卜，東山道益振。", "遽嗟埋玉恨，清淚灑衣巾。"]'),
('173d116b-eeb8-43e5-9ebc-74ee61924886','挽董舍人','李正民','宋','宋诗','song-poetry','','[]','華髪年方永，祠廷力未愆。',48,'全唐诗/poet.song.88000.json','["華髪年方永，祠廷力未愆。", "誰云牖下死，疑是醉中仙。", "驥子持門户，魚軒泣几筵。", "浮生真瞬息，誰與問青天。"]'),
('665a0bec-6c68-4975-82c7-214b055e8626','挽齊安郡夫人','李正民','宋','宋诗','song-poetry','','[]','懿範閨房秀，齊姜素望優。',48,'全唐诗/poet.song.88000.json','["懿範閨房秀，齊姜素望優。", "廣川名益盛，內壼德彌修。", "壽量方難老，生涯遽若浮。", "延平雙劍逝，遺恨在營丘。"]'),
('5dba66d7-f62e-47af-abc1-e307efcc401f','元日示邦求','李正民','宋','宋诗','song-poetry','','[]','濟時材術本無庸，長大猶存伯業功。',64,'全唐诗/poet.song.88000.json','["濟時材術本無庸，長大猶存伯業功。", "騏驥已消千里志，鶢鶋聊避廣川風。", "論都正恐譏傖父，置酒深慚及寓公。", "早晚共謀歸去計，煙波䆉稏五湖東。"]'),
('0500a8f8-da40-42ef-8206-c92ba0180b92','示艾若訥','李正民','宋','宋诗','song-poetry','','[]','文章自昔爲難事，詞賦于今豈易工。',64,'全唐诗/poet.song.88000.json','["文章自昔爲難事，詞賦于今豈易工。", "入室升堂方盡善，取青配白漫稱雄。", "師資未省逢勍敵，衡鑑應宜探古風。", "顧我平生章句學，强談文律愧空空。"]'),
('93caa1e8-bef4-4ce4-bfd9-79f03fe241c5','寄汪彦章內翰','李正民','宋','宋诗','song-poetry','','[]','文華風采壓時流，惠政春温著六州。',64,'全唐诗/poet.song.88000.json','["文華風采壓時流，惠政春温著六州。", "纔向卞山歸舊隱，忽尋湘水泛扁舟。", "愚溪勝踐今親見，清境西偏幾客遊。", "臯壌山林皆可樂，不須重作畔牢愁。"]'),
('8b59c356-0a06-4f9c-b39e-a78b97a2e296','寄彦章內翰','李正民','宋','宋诗','song-poetry','','[]','翰林名德冠鑾坡，暫解塵纓逸興多。',64,'全唐诗/poet.song.88000.json','["翰林名德冠鑾坡，暫解塵纓逸興多。", "敢謂交游同阮謝，不妨詩句敵陰何。", "耳根到處聞犍鬭，心地閑來契羯磨。", "此去苕溪三百里，扁舟終擬泛烟波。"]'),
('35d46b40-d4ce-469b-8df0-13bfcf7d0840','訪祝舜俞新居','李正民','宋','宋诗','song-poetry','','[]','平湖渺渺浸城陰，窈窕垂楊一徑深。',64,'全唐诗/poet.song.88000.json','["平湖渺渺浸城陰，窈窕垂楊一徑深。", "千萬買鄰真得計，六年種竹已成林。", "棋枰勝負消長日，琴韻清幽見古心。", "萍泛蓬飛本無繫，新亭何必苦霑襟。"]'),
('1287f085-e583-41d3-9f65-5fb8e1d43132','送尹叔倅濠梁','李正民','宋','宋诗','song-poetry','','[]','淮邦井邑苦蕭條，尚可觀魚訪古濠。',64,'全唐诗/poet.song.88000.json','["淮邦井邑苦蕭條，尚可觀魚訪古濠。", "志士攬衣辭舊隱，餘民拭目看垂櫜。", "清傳闔境持盃水，器賞名賢解佩刀。", "無復髙陽舊閭里，爲尋故宅薙蓬蒿。"]'),
('c1cc4e33-2356-4d0b-b644-8e13f561e2b1','贈劉無虞侍郎','李正民','宋','宋诗','song-poetry','','[]','粉户爲郎贊冢卿，十年先後典銓衡。',64,'全唐诗/poet.song.88000.json','["粉户爲郎贊冢卿，十年先後典銓衡。", "要津詎可馳髙足，大器於今見晚成。", "相對樽前歎華髪，寧於紙上校虚名。", "萬釘寶带知非稱，欲買良田待退耕。"]'),
('f70704a3-96d7-4ebc-92b4-bc45c92d9d66','聞吕丞相還朝  其一','李正民','宋','宋诗','song-poetry','','[]','粉户爲郎兩見春，當時曾識濟川人。',64,'全唐诗/poet.song.88000.json','["粉户爲郎兩見春，當時曾識濟川人。", "留侯再踐功名地，白也今爲放逐臣。", "自笑鳬鴻飛渤澥，却慚冠劍拂埃塵。", "數奇自是平生事，終始須期入大鈞。"]'),
('4a8449cc-226b-4eeb-88ef-313947f25d28','聞吕丞相還朝  其二','李正民','宋','宋诗','song-poetry','','[]','赤子潢池久弄兵，暫辭台席抗蜺旌。',64,'全唐诗/poet.song.88000.json','["赤子潢池久弄兵，暫辭台席抗蜺旌。", "屏風隔坐方調燮，棨戟前驅遽遠征。", "淮蔡巳瞻裴相節，秦川猶列武侯營。", "策勳未用膺光寵，待復中原致太平。"]'),
('eeec6823-c590-4cef-8a75-aad538c24314','送尹叔之行朝','李正民','宋','宋诗','song-poetry','','[]','三年製錦在江吳，游刃恢恢地有餘。',64,'全唐诗/poet.song.88000.json','["三年製錦在江吳，游刃恢恢地有餘。", "賈誼已膺前席問，嵇康新有絕交書。", "田間雨過禾收早，庭下風來葉落初。", "此去青雲前路穏，未應搔首賦歸與。"]'),
('83a3eb27-27ea-402c-8a03-49e40a2eff9e','題海月亭','李正民','宋','宋诗','song-poetry','','[]','新亭注目極無邊，脫屣塵寰思杳然。',64,'全唐诗/poet.song.88000.json','["新亭注目極無邊，脫屣塵寰思杳然。", "萬頃秋濤翻浩渺，一輪夜月對虛圓。", "光連銀漢疑無地，望斷蓬萊别有天。", "赤水棗花君莫問，新詩賡唱似朱絃。"]'),
('b9d87f5d-cbcf-4bad-b3b4-f3ea8be08f7f','章季萬送示其祖內制次元叔韻詩','李正民','宋','宋诗','song-poetry','','[]','運際熙豐政日新，近臣摛藻掞天門。',64,'全唐诗/poet.song.88000.json','["運際熙豐政日新，近臣摛藻掞天門。", "當年翰墨文章妙，晚歲經綸德業尊。", "紀事豐碑推大手，憂民温詔盡嘉言。", "大門接武登鼇禁，猶喜交游到子孫。"]'),
('4b37e5b2-99be-456c-ade6-a2eb957ba97d','簡劉卿任待制','李正民','宋','宋诗','song-poetry','','[]','暑雨霖霪朱夏寒，登門暫著鵔鸃冠。',64,'全唐诗/poet.song.88000.json','["暑雨霖霪朱夏寒，登門暫著鵔鸃冠。", "管絃豈解陪張禹，葱菜真宜待井丹。", "五技已窮甘退處，一錢不直嘆衰殘。", "明朝鼓枻辭公去，却向滄浪把釣竿。"]'),
('82510065-23eb-472a-8f50-48d310c27563','書事','李正民','宋','宋诗','song-poetry','','[]','嬾拙山林合退藏，客情歲晚倍淒涼。',64,'全唐诗/poet.song.88000.json','["嬾拙山林合退藏，客情歲晚倍淒涼。", "梅飄苔蘚香初歇，雪積簷溝色尚粧。", "舊歷細看能幾日，新詩屢和斷來章。", "何如認取安心法，坐對爐熏一穗長。"]'),
('5e5a1b8d-dab7-4074-90d6-5f3011370db9','示姪淇','李正民','宋','宋诗','song-poetry','','[]','分符江左力難支，竊食琳宫得禄遲。',64,'全唐诗/poet.song.88000.json','["分符江左力難支，竊食琳宫得禄遲。", "淮上故園生杞棘，江邊大將列旌旗。", "未知疏傅揮金日，正是公孫脱粟時。", "爲報阿咸休悵望，十年窮巷困朝饑。"]'),
('d946be3d-1e2a-41bf-a25f-3388c93c84ec','送劉子材四明幕官','李正民','宋','宋诗','song-poetry','','[]','雉堞連雲左海傍，曾攀鯨背到扶桑。',64,'全唐诗/poet.song.88000.json','["雉堞連雲左海傍，曾攀鯨背到扶桑。", "蒙衝聲教通韓國，梵刹光明記育王。", "地接天台仙聖宅，山藏奎畫妙圓章。", "時清幕府多餘暇，薄採江珧薦豆觴。"]'),
('f800f780-46a6-4672-89e2-baa99d26ec4b','徐元美甲第新修同諸公賦詩','李正民','宋','宋诗','song-poetry','','[]','大厦沈沈結綺櫳，誅茅新就化人宫。',64,'全唐诗/poet.song.88000.json','["大厦沈沈結綺櫳，誅茅新就化人宫。", "春臺亂落桃花雨，北牖遙披柳葉風。", "遁迹娛遊同梓澤，卜居窮僻似蕭公。", "人生適意方爲樂，何必簞瓢歎屢空。"]'),
('88443e67-de17-4d55-a0ad-76d87a400631','再賦戲元美','李正民','宋','宋诗','song-poetry','','[]','綿綿千載亢華宗，大棟髙甍闢廣宫。',64,'全唐诗/poet.song.88000.json','["綿綿千載亢華宗，大棟髙甍闢廣宫。", "柳徑乍穿迷去路，桃蹊初過面春風。", "閑居不羨潘常侍，投轄當如陳孟公。", "竹外梅花猶可折，莫教碧玉髻鬟空。"]'),
('480a9485-ea8e-4c5d-98dd-af398d30f9c7','秀士詩','李正民','宋','宋诗','song-poetry','','[]','一葉扁舟一席風，夢回已聽景陽鐘。',64,'全唐诗/poet.song.88000.json','["一葉扁舟一席風，夢回已聽景陽鐘。", "奪袍有意趨文陣，鼓篋無言拙筆鋒。", "好把犂鋤傍東郭，難陪衿佩集西雝。", "只緣未富三冬學，飲墨何須見愠容。"]'),
('0be4ecb1-079d-4e41-b85e-830e89c17ba9','退老堂','李正民','宋','宋诗','song-poetry','','[]','將相勳名紀太常，旌旄聊駐水雲鄉。',64,'全唐诗/poet.song.88000.json','["將相勳名紀太常，旌旄聊駐水雲鄉。", "栽培草木平泉里，放浪琴書綠野堂。", "身健未應親几杖，公歸正欲望軒裳。", "東山謝傅風流在，盛事齊稱左海傍。"]'),
('1de59cef-de63-4e9a-9dbb-fe480b454f0a','野步','李正民','宋','宋诗','song-poetry','','[]','步屧尋春日正暄，杖藜徐步小橋邊。',64,'全唐诗/poet.song.88000.json','["步屧尋春日正暄，杖藜徐步小橋邊。", "身如柳惠人皆識，名比韓康世漫傳。", "雪壓寒梅枝嫋嫋，煙籠脩竹翠娟娟。", "途窮興盡空回首，却見招提獨巋然。"]'),
('b77fb880-9086-4b6e-9366-71c1d05abeb8','食蛤蜊','李正民','宋','宋诗','song-poetry','','[]','泊水沈沙族類豐，外緘頑殻力難攻。',64,'全唐诗/poet.song.88000.json','["泊水沈沙族類豐，外緘頑殻力難攻。", "雖云眉目虧天巧，誰使瓊瑶美內充。", "海畔屢曾逢野士，坐間那復識王融。", "一樽風味思傾倒，賴有芳鮮可薦公。"]'),
('c9c47222-aa47-4301-9c44-790ae9533dce','次韻邦求少監  其一','李正民','宋','宋诗','song-poetry','','[]','投老窮途乃叫閽，再棲琳館奉高真。',64,'全唐诗/poet.song.88000.json','["投老窮途乃叫閽，再棲琳館奉高真。", "自憐奇蹇生華髪，豈有聲名繼昔人。", "梨棗栽培功未半，林泉卜築興方新。", "看公穏步星辰去，何必乘槎更問津。"]'),
('20ab9956-3f12-4ecb-bf68-00270a6f0e83','次韻邦求少監  其二','李正民','宋','宋诗','song-poetry','','[]','歷落嶔崎寓海濱，放懷林壑任吾真。',64,'全唐诗/poet.song.88000.json','["歷落嶔崎寓海濱，放懷林壑任吾真。", "恩垂雨露沾枯枿，義重金蘭有故人。", "玉筍班聯年尚少，筠筒詩律意尤新。", "三陽交泰逢亨運，策足須登要路津。"]'),
('a0beadf7-aa0f-4f78-b909-7079d595aef3','和元叔冬至大風','李正民','宋','宋诗','song-poetry','','[]','風掀籬落盡欹傾，夜半銅壺凍已生。',64,'全唐诗/poet.song.88000.json','["風掀籬落盡欹傾，夜半銅壺凍已生。", "塞鴈衝寒雲路杳，林烏啼曉夢魂驚。", "貧探龍頷嗟無策，愁望鴒原祗攪情。", "擬學髙齋枯淡叟，不妨姓字且雙行。"]'),
('ca3de0ae-8366-453c-a8d9-91e13cd2b61e','海邑少交遊相見者以爲言故作此詩','李正民','宋','宋诗','song-poetry','','[]','結友觀光少壯年，一時英俊與周旋。',64,'全唐诗/poet.song.88000.json','["結友觀光少壯年，一時英俊與周旋。", "曳裾璧水三千士，接武瀛洲十八賢。", "夜對短檠愁不寐，朝飡苜蓿歎無錢。", "如今只欲藏形影，槁木寒灰學坐禪。"]'),
('98968353-5014-4b03-b0ee-a469dc2dabb1','寄霅上故人','李正民','宋','宋诗','song-poetry','','[]','交流苕霅轉城闉，尚想汀洲詠白蘋。',64,'全唐诗/poet.song.88000.json','["交流苕霅轉城闉，尚想汀洲詠白蘋。", "擇勝已居蓮社界，歸耕恰及杏花春。", "彫胡映盌抄雲子，鱠縷堆盤破玉鱗。", "鮭菜腥鹹何足道，未應回首海之濱。"]'),
('8f97ca15-8414-4b6c-9b76-ebf0078333a8','挽陳志行寺正','李正民','宋','宋诗','song-poetry','','[]','昔日陵陽接俊遊，松蘿崇好重綢繆。',64,'全唐诗/poet.song.88000.json','["昔日陵陽接俊遊，松蘿崇好重綢繆。", "青衿共處披黄卷，黑髪相看到白頭。", "苕水卜鄰方有志，青山埋玉竟難留。", "飄零更覺親朋少，東望新阡涕淚流。"]'),
('cb5b9660-fee6-4999-8e74-7d373a41af81','簡邦求宗博','李正民','宋','宋诗','song-poetry','','[]','荆州清德畏人知，况值中原戰鼓鼙。',64,'全唐诗/poet.song.88000.json','["荆州清德畏人知，况值中原戰鼓鼙。", "公自南來無薏苡，我從東渡乏朱提。", "珍臺鶴禄慚非稱，别乘瓜期奈久稽。", "明日重陽菊花好，且拚痛飲醉如泥。"]'),
('d94dd913-e88d-428a-8181-afa12b12594a','寄艾若訥','李正民','宋','宋诗','song-poetry','','[]','宅相凋零久不振，喜君文采日清新。',64,'全唐诗/poet.song.88000.json','["宅相凋零久不振，喜君文采日清新。", "彈琴密令能官業，獻頌王褒邁等倫。", "豈有青松蟠澗谷，待看騄驥絕風塵。", "諸儒方講升平事，策足須登要路津。"]'),
('b14b4194-95e2-4169-a519-4a2185c3dcc6','寄聞人茂德  其一','李正民','宋','宋诗','song-poetry','','[]','詩人比興隱而彰，三百餘篇妙義藏。',64,'全唐诗/poet.song.88000.json','["詩人比興隱而彰，三百餘篇妙義藏。", "已識鴟鴞爲巧婦，仍知杕杜是甘棠。", "書生未省離城闕，物理何從見否臧。", "閉户先生學不厭，更同許郭辨毫芒。"]'),
('0f39d1b5-e173-42fe-b910-78ea008991f7','寄聞人茂德  其二','李正民','宋','宋诗','song-poetry','','[]','未捐辛苦讀書燈，老矣猶懷伯業能。',64,'全唐诗/poet.song.88000.json','["未捐辛苦讀書燈，老矣猶懷伯業能。", "齊國吹竽吾獨否，荆山泣玉恨難勝。", "滿籝自足傳兒子，堆案何勞謝友朋。", "已注蟲魚窮窈眇，却遊溟海看鵾鵬。"]'),
('fabeee4f-ad07-441f-aaa5-4f92e7edf706','寄元叔','李正民','宋','宋诗','song-poetry','','[]','涉世崎嶇三十年，棲遲琳館祝堯天。',64,'全唐诗/poet.song.88000.json','["涉世崎嶇三十年，棲遲琳館祝堯天。", "桔橰不用身謀拙，梨棗先栽氣守全。", "何幸童烏新忝命，應容老鶴漸歸田。", "嚢金未足營三徑，搔首東風一慨然。"]'),
('8055957d-7482-475a-9fe6-958dd87d3573','寄李成德舍人','李正民','宋','宋诗','song-poetry','','[]','蓬瀛當日接英遊，俛仰星霜十見秋。',64,'全唐诗/poet.song.88000.json','["蓬瀛當日接英遊，俛仰星霜十見秋。", "紅藥青苔叨並命，西山南浦動離愁。", "寧論圓觀情猶在，且喜維摩病少休。", "欲就書堂訪髙隱，便疑猿鶴不相留。"]'),
('57e36466-8bff-471d-b571-5c6efc7ee13d','買舟之苕溪','李正民','宋','宋诗','song-poetry','','[]','二年宴坐縠溪濱，廷尉門前鳥雀馴。',64,'全唐诗/poet.song.88000.json','["二年宴坐縠溪濱，廷尉門前鳥雀馴。", "問舍求田將欲老，畜雞種黍孰爲隣。", "曾遭太僕興讒口，粗勝漳江抱病身。", "暫泛扁舟苕霅去，鱖鱸聊醉五湖春。"]'),
('ec358437-4275-405b-8bf2-262f3f73f649','自苕溪回棹','李正民','宋','宋诗','song-poetry','','[]','扁舟東下霅溪濱，擬伴漁翁整釣緡。',64,'全唐诗/poet.song.88000.json','["扁舟東下霅溪濱，擬伴漁翁整釣緡。", "黄紙紅旗慚許國，落花流水送殘春。", "拏舟處處争行樂，脩禊年年要及辰。", "悵望故園桃李月，東風吹淚漫霑巾。"]'),
('f274550b-8b20-46a2-ae00-d9de1ad10c16','頤慶堂爲徐氏賦','李正民','宋','宋诗','song-poetry','','[]','朱方玉几邈千齡，落落雲孫尚典刑。',64,'全唐诗/poet.song.88000.json','["朱方玉几邈千齡，落落雲孫尚典刑。", "跂翼翬飛新棟宇，筆精墨妙舊丹青。", "十旬醸酒宜爲頌，七水煎茶必有經。", "積善故知頤慶遠，詵詵蘭玉長階庭。"]'),
('c638deb8-045c-491d-bf7a-771d94cc71ec','哭友人詩  其一','李正民','宋','宋诗','song-poetry','','[]','流落生涯集百憂，十年抱病甬東州。',64,'全唐诗/poet.song.88000.json','["流落生涯集百憂，十年抱病甬東州。", "忽驚白璧埋黄壤，漫說朱衣駕赤虬。", "髙論難投衆人耳，壯心空逐逝川流。", "死生暌隔傷千里，淚灑叢蘭泣素秋。"]'),
('203abddf-2a72-4d6a-88bb-5354f982a812','哭友人詩  其二','李正民','宋','宋诗','song-poetry','','[]','王謝門中鸞鳯翔，少年奇志已昂藏。',64,'全唐诗/poet.song.88000.json','["王謝門中鸞鳯翔，少年奇志已昂藏。", "空餘詩律知誰敵，欲繼家聲失所望。", "作賦曾驚禰衡俊，行歌不見接輿狂。", "臨終一念歸空寂，詎肯修文學卜商。"]'),
('c3786221-20f1-477c-a578-6df6c27abb1f','追憶大觀丁亥年自新安侍下入宣城學路中作','李正民','宋','宋诗','song-poetry','','[]','朝雲黯黯結秋陰，疊疊層巒霧靄深。',64,'全唐诗/poet.song.88000.json','["朝雲黯黯結秋陰，疊疊層巒霧靄深。", "農叟盡愁苗欲稿，行人翻恐雨成霖。", "四方奔走男兒事，千里淒涼倦客心。", "稍喜西風破殘暑，又攜書劍度遥岑。"]'),
('6fc0965e-8a4d-4bef-89e8-12d34fbccf1d','縣學','李正民','宋','宋诗','song-poetry','','[]','碧瓦鱗鱗接近郊，青青衿珮得同袍。',64,'全唐诗/poet.song.88000.json','["碧瓦鱗鱗接近郊，青青衿珮得同袍。", "欣聞庠序儒風盛，不見桑榆太白髙。", "魯國已觀沂上舞，漢朝應貨蜀中刀。", "獻酬濟濟昇平事，泮水從今有弁髦。"]'),
('331cd3b1-6470-4797-8dfe-41d6d3b9ef44','送敏申赴勅局','李正民','宋','宋诗','song-poetry','','[]','弟兄接武上天關，行色差池一歲間。',64,'全唐诗/poet.song.88000.json','["弟兄接武上天關，行色差池一歲間。", "獻納已看騰碧落，編摩寧久曳青班。", "雨蒸梅暑蘭舟穏，綱解秋茶赤筆閑。", "病鶴乘軒嗟老矣，毰毸短羽戀雲山。"]'),
('02fd363a-f685-4194-a239-d6b635a5a3d6','先疇戲簡尹叔','李正民','宋','宋诗','song-poetry','','[]','檇李城東雀墓邊，先疇蕪沒僅名傳。',64,'全唐诗/poet.song.88000.json','["檇李城東雀墓邊，先疇蕪沒僅名傳。", "南來書契今無有，歲遠比隣屢變遷。", "剪葉舊疆幾并沃，釣璜遺業久輸田。", "莫言雞肋難料理，猶勝區區貸子錢。"]'),
('ac17ba2e-8735-4f02-8a95-a9a6ae4a17fa','辭髙安之行','李正民','宋','宋诗','song-poetry','','[]','投林倦翼漫差池，揣分量材祗自知。',64,'全唐诗/poet.song.88000.json','["投林倦翼漫差池，揣分量材祗自知。", "鬱鬱安能久居此，栖栖若是欲何爲。", "文軒華轂非余望，白髪蒼顔嘆我衰。", "聞說風波猶未靖，難於江海把旌麾。"]'),
('c0eef313-3c82-49d4-8d18-1de86b1b5666','尹叔若訥和邊字韻因再寄  其一','李正民','宋','宋诗','song-poetry','','[]','遁迹東遊滄海邊，全家到處寄郵傳。',64,'全唐诗/poet.song.88000.json','["遁迹東遊滄海邊，全家到處寄郵傳。", "江淮李監人多厭，甲乙商墟利則遷。", "遣興千鍾猶有酒，思歸一馬尚無田。", "買山擬作誅茅計，難學巢由不用錢。"]'),
('915e07da-7115-4151-8430-fb1d2955e9b0','尹叔若訥和邊字韻因再寄  其二','李正民','宋','宋诗','song-poetry','','[]','將相驅馳正事邊，風聲喜自道途傳。',64,'全唐诗/poet.song.88000.json','["將相驅馳正事邊，風聲喜自道途傳。", "鯫生豈解求三捷，榮路如何望九遷。", "勵志陶公朝運甓，決疑平子賦歸田。", "誰人肯爲將軍地，自笑都無直一錢。"]'),
('47a93044-ee1a-48d9-b00a-e9540e27035b','寄曹明甫','李正民','宋','宋诗','song-poetry','','[]','憶昔宣城接俊遊，回頭三十六清秋。',64,'全唐诗/poet.song.88000.json','["憶昔宣城接俊遊，回頭三十六清秋。", "少年志氣青霄近，老境飄零白髪羞。", "可嘆飛光如電往，自憐外物等雲浮。", "何時相對一樽酒，與子同消萬斛愁。"]'),
('aea5fc61-8cb1-4966-9ea4-30b4bda5cbe1','寄艾若訥','李正民','宋','宋诗','song-poetry','','[]','擬尋荒僻事田園，竊食祠庭愧國恩。',64,'全唐诗/poet.song.88000.json','["擬尋荒僻事田園，竊食祠庭愧國恩。", "休論鶴長鳬甚短，且看齒落舌猶存。", "陶潛昔去因多忤，房琯今知欠不言。", "欲問大鈞吾豈敢，喙長三尺亦須吞。"]'),
('3eeb05d2-e715-4d7f-b189-5c9d0d316349','寄孫邦求','李正民','宋','宋诗','song-poetry','','[]','少年英氣已峥嶸，泮水曾傳御史名。',64,'全唐诗/poet.song.88000.json','["少年英氣已峥嶸，泮水曾傳御史名。", "白簡自宜繩列位，皂嚢終不負家聲。", "且隨郡守尋春去，未向班心布武行。", "知有彈冠貢公喜，休嗟華髪鏡中生。"]'),
('10e514e4-7cd0-45d3-a3f4-cf9d5e723de9','寄張子安  其一','李正民','宋','宋诗','song-poetry','','[]','縠水分襟十五秋，此身萍梗任飄浮。',64,'全唐诗/poet.song.88000.json','["縠水分襟十五秋，此身萍梗任飄浮。", "久棲孤館爲真隱，未訪名山作勝遊。", "醉裏周郎曾度曲，閑中庾信祗添愁。", "西風起我江湖興，擬把蘭橈上釣舟。"]'),
('e95d0b33-e7ff-4cff-ba2a-bb7f790334a9','寄張子安  其二','李正民','宋','宋诗','song-poetry','','[]','來往三吳二十年，星星華髪已盈顛。',64,'全唐诗/poet.song.88000.json','["來往三吳二十年，星星華髪已盈顛。", "未開松菊陶潛徑，且泛江湖范蠡船。", "黄石不逢寧論富，丹砂可就試求仙。", "乘閑欲訪張公子，共說昇平一慨然。"]'),
('2276097d-8db9-4fc0-97ed-29b380f0d617','寄元叔','李正民','宋','宋诗','song-poetry','','[]','湖海飄零畏甲兵，敢將筆墨論功名。',64,'全唐诗/poet.song.88000.json','["湖海飄零畏甲兵，敢將筆墨論功名。", "好官未憶羊元保，萬户難侯李北平。", "智短雲霄曾踠足，老來農圃合謀生。", "王維薦弟雖無愧，尚恐諸公厭禰衡。"]'),
('1d7d635c-551c-4234-acc5-97d9f7d34db5','再寄曹明甫','李正民','宋','宋诗','song-poetry','','[]','憶昔陵陽寓學時，登山臨水共追隨。',64,'全唐诗/poet.song.88000.json','["憶昔陵陽寓學時，登山臨水共追隨。", "並遊志氣青雲近，投老光陰白髪垂。", "顧我家無阿堵物，喜君門有寧馨兒。", "仍聞歲晚聊棲棘，願訪茅齋杜拾遺。"]'),
('89853931-9bd8-49dd-b3a6-5509cad78143','和叔食黄雀有詩求葉公書次韻','李正民','宋','宋诗','song-poetry','','[]','驚禽投案庇微軀，尚見頭顱萬里餘。',64,'全唐诗/poet.song.88000.json','["驚禽投案庇微軀，尚見頭顱萬里餘。", "敢謂苞苴猶到我，偶因棠棣得逢渠。", "身閑幸飽公孫粟，地散難移薛相書。", "聞道舍人已傾蓋，承明何必戀吾廬。"]'),
('038e2de9-b5bb-4203-9856-28dcfaed35fb','邦求假僕制槀示詩褒拂次韻爲謝','李正民','宋','宋诗','song-poetry','','[]','漫試詞科久綴文，誤升禁掖掌絲綸。',64,'全唐诗/poet.song.88000.json','["漫試詞科久綴文，誤升禁掖掌絲綸。", "判花舊職懷先德，留草私家愧古人。", "珍寶未能逃拙澀，詔書何以變温純。", "相如多病辭源涸，紫槖同君再拂塵。"]'),
('1d21f313-7409-48aa-abe7-425581f34cbd','與客往天寧素飯以惠山水煎茶','李正民','宋','宋诗','song-poetry','','[]','精舍閒遊結勝緣，老來寧復嗜腥羶。',64,'全唐诗/poet.song.88000.json','["精舍閒遊結勝緣，老來寧復嗜腥羶。", "共分摩詰衆香飯，仍試華山第二泉。", "石鼎煎來甘有味，乳花浮處色尤鮮。", "幾年瀉鹵傷牙頰，吮潄華池便欲仙。"]'),
('84b5f90d-d271-48fd-a8de-df71503bbac5','聞人餘慶見和因再賦','李正民','宋','宋诗','song-poetry','','[]','世路功名懶著鞭，閒中乘興便逃禪。',64,'全唐诗/poet.song.88000.json','["世路功名懶著鞭，閒中乘興便逃禪。", "檀欒林裏禽初囀，阿耨池邊柳正妍。", "未怕俗情嗤北阮，只愁神物戲南泉。", "我來不爲尋春色，試舉開遮問竺乾。"]'),
('3a58da39-67b8-473c-9a89-9ddd329a1622','次韻許希文','李正民','宋','宋诗','song-poetry','','[]','少年豪氣壓詞場，晚喜松筠耐雪霜。',64,'全唐诗/poet.song.88000.json','["少年豪氣壓詞場，晚喜松筠耐雪霜。", "但見貂裘嗟季子，焉知素髪老潘郎。", "黄公壚畔山河邈，陶令門前草木長。", "邂逅正當戎馬際，共驚飄泊在他鄉。"]'),
('d5107350-156d-4e6f-af2b-17bd526dba00','次韻王廷老','李正民','宋','宋诗','song-poetry','','[]','珥筆風謡萃此州，二年坐嘯政非優。',64,'全唐诗/poet.song.88000.json','["珥筆風謡萃此州，二年坐嘯政非優。", "樽前自愧孔文舉，竹下欣逢王子猷。", "九瑣洞天空悵望，一麾江海漫淹留。", "歸心擬借南風便，萬里滄波一葉舟。"]'),
('562327d5-44fa-47f8-a682-114691e807d4','徐大諫道漳南與舍弟倡和次韻  其一','李正民','宋','宋诗','song-poetry','','[]','天涯流落髩絲生，喜見英豪一坐傾。',64,'全唐诗/poet.song.88000.json','["天涯流落髩絲生，喜見英豪一坐傾。", "雲靄微茫分島嶼，風濤歘忽變陰晴。", "幸逢勝餞開樽俎，必有嘉言補聖明。", "憂國濟時公自任，十年寰海困戈兵。"]'),
('b1414852-4392-4e5d-a6b5-4c20b6e86ab6','徐大諫道漳南與舍弟倡和次韻  其二','李正民','宋','宋诗','song-poetry','','[]','謝公今起爲蒼生，樽酒相看只細傾。',64,'全唐诗/poet.song.88000.json','["謝公今起爲蒼生，樽酒相看只細傾。", "戲綵鯉庭窺麗藻，披雲鯨海屬新晴。", "感時華髪蕭蕭改，致主丹心皎皎明。", "從此靈臺應偃伯，共知堂上有奇兵。"]'),
('b3283ce7-e32b-4f25-a554-ed54c788b191','次韻德卲見寄','李正民','宋','宋诗','song-poetry','','[]','三年持槖侍君軒，誤剖麟符去日邊。',64,'全唐诗/poet.song.88000.json','["三年持槖侍君軒，誤剖麟符去日邊。", "暫解塵纓尋紫府，愧無棠蔭在螺川。", "羲之詔郡難爲政，邴曼辭官不待年。", "等是飄零江海客，祗應同病自相憐。"]'),
('4117b9dd-9f7a-4241-b19a-370995737573','次韻邦求宗博','李正民','宋','宋诗','song-poetry','','[]','番禺薏苡舊傳名，公酌貪泉志愈清。',64,'全唐诗/poet.song.88000.json','["番禺薏苡舊傳名，公酌貪泉志愈清。", "絳帳有經談訓詁，淮壖無地可歸耕。", "鴻飛久困孫內史，龍具寧悲王仲卿。", "琳館素飱公自愧，秋風蕭颯二毛生。"]'),
('9781cbba-df1e-4072-b231-aae5ef7f768a','次元叔韻','李正民','宋','宋诗','song-poetry','','[]','吳越飄零一葉輕，戰場暫息虎狼争。',64,'全唐诗/poet.song.88000.json','["吳越飄零一葉輕，戰場暫息虎狼争。", "身閑自適琴書樂，耳冷寧聞寵辱驚。", "繫表對談通妙義，禪源默契滌凡情。", "他年更遂茅齊約，重使雲間見弟兄。"]'),
('4411f2ce-735e-4119-a074-7fd6c3c9804f','次平叔韻','李正民','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','草長江南送暮春，誰憐羈羽及沈鱗。',64,'全唐诗/poet.song.88000.json','["草長江南送暮春，誰憐羈羽及沈鱗。", "放懷自適漁樵樂，會面欣逢手足親。", "齒髪漸凋嗟晚景，田園粗葺作閑人。", "材髙莫嘆時相負，會見諸公寵薦頻。"]'),
('544f7d09-4333-441f-8cf8-6097b572264e','和同院蠟梅  其一','李正民','宋','宋诗','song-poetry','','[]','曾笑江妃粉面光，化工端爲拂嬌黄。',64,'全唐诗/poet.song.88000.json','["曾笑江妃粉面光，化工端爲拂嬌黄。", "蜜脾旋滴明如剪，宫額新塗暗有香。", "應與鞏梅分氣味，不同陶菊鬭輕狂。", "捧心誰識西施病，臨鑑深顰未試粧。"]'),
('676d7d8c-4083-4bc0-aba0-5fe9fba6c81d','和同院蠟梅  其二','李正民','宋','宋诗','song-poetry','','[]','嶺梅開過已飄揚，獨出奇姿淺淡黄。',64,'全唐诗/poet.song.88000.json','["嶺梅開過已飄揚，獨出奇姿淺淡黄。", "綘蕚巧粘花蘂蜜，緗羅輕熨水沉香。", "光搖燭跋連宵賞，色映鵝兒殢酒狂。", "只恐壽陽公主怪，蛾眉畫了不成粧。"]'),
('ff233a88-8d6d-47ea-a4c5-ad7b3aa0746a','和同院蠟梅  其三','李正民','宋','宋诗','song-poetry','','[]','瘦骨纖肌出衆芳，嘉名聊占蜜脾黄。',64,'全唐诗/poet.song.88000.json','["瘦骨纖肌出衆芳，嘉名聊占蜜脾黄。", "秦酥亂點寒生粟，春酒初開凍發香。", "事異代薪矜屋潤，巧同刻鳯伴兒狂。", "十年不見春風面，依舊輕輕薄薄粧。"]'),
('b42746bb-ddcb-40c2-841c-37dbc0e6106d','再賦','李正民','宋','宋诗','song-poetry','','[]','不雜寒枝冰雪光，蜜脾初點一分黄。',64,'全唐诗/poet.song.88000.json','["不雜寒枝冰雪光，蜜脾初點一分黄。", "裁時巧借韓湘手，到處濃薫荀令香。", "東閣斂藏羞太白，游蜂邂逅恍如狂。", "艶陽時節閒桃李，任學風流時世粧。"]'),
('33dd785f-3019-453a-a9f5-4ac25566eba3','東海生欲以酒見遺而郡禁方嚴僕每飲又少作詩謝之','李正民','宋','宋诗','song-poetry','','[]','霜凝鴛瓦曉纖纖，靜擁寒爐火屢添。',64,'全唐诗/poet.song.88000.json','["霜凝鴛瓦曉纖纖，靜擁寒爐火屢添。", "白墮春醪空有意，青州從事邈難瞻。", "幸逢朱博盃盤少，况值曹公禁令嚴。", "瓶汲甘泉聊漱齒，鴟夷應笑若清廉。"]'),
('ace9d663-9fa0-4d33-8dac-ca01e966608c','覽鏡','李正民','宋','宋诗','song-poetry','','[]','覽鏡空驚鬢髪凋，暮年蹤跡逐漁樵。',64,'全唐诗/poet.song.88000.json','["覽鏡空驚鬢髪凋，暮年蹤跡逐漁樵。", "如無似有梅天雨，暫去還來海浦潮。", "栗里忘憂惟濁酒，錦城排悶且長謡。", "草堂日晏猶髙枕，不怕當關苦見招。"]'),
('0eb56dec-37b9-4a50-9682-1186627b91f8','客有以茶易竹次韻','李正民','宋','宋诗','song-poetry','','[]','琅玕黝璧兩清虛，不比山陰鵝換書。',64,'全唐诗/poet.song.88000.json','["琅玕黝璧兩清虛，不比山陰鵝換書。", "花乳試烹應有味，龍孫新種未嫌疏。", "輕身通氣宜君飲，冒雪停霜稱我居。", "斜曲短長休更問，森羅萬象已如如。"]'),
('3882b356-64e0-4092-beb8-644297ee1a92','再和換竹','李正民','宋','宋诗','song-poetry','','[]','此君風度不可無，禪老方翻貝葉書。',64,'全唐诗/poet.song.88000.json','["此君風度不可無，禪老方翻貝葉書。", "試遣酪奴相問訊，爲邀青士看扶疏。", "芳香雅稱松江水，蒼翠還宜長者居。", "明月清風随處是，去來有分意何如。"]'),
('6eaef426-2189-4b4a-96e2-5b33045c17d1','和同院梅花  其一','李正民','宋','宋诗','song-poetry','','[]','歲殘萬木凍如癡，聚窟飄香起玉肌。',64,'全唐诗/poet.song.88000.json','["歲殘萬木凍如癡，聚窟飄香起玉肌。", "韻勝自依山谷裏，膚清偏稱月明時。", "且看雪後微微折，只怕風前細細吹。", "蓬島瑶池空入夢，不將清興屬芳枝。"]'),
('05098c36-3e74-4350-85fe-7a3e39bd9c6d','和同院梅花  其二','李正民','宋','宋诗','song-poetry','','[]','孤標無物可相宜，淺淺嬌黄點素肌。',64,'全唐诗/poet.song.88000.json','["孤標無物可相宜，淺淺嬌黄點素肌。", "曾向揚州動詩興，不勞杜宇囀芳時。", "髙情已與雲爲友，冷艶仍愁雪共吹。", "自笑剛腸如鐵石，難陪徐庾賦南枝。"]'),
('7f46f86f-cc78-49bf-8a1c-b9b9d2c348d4','和同院梅花  其三','李正民','宋','宋诗','song-poetry','','[]','清真淡薄正相宜，肯使赬容透玉肌。',64,'全唐诗/poet.song.88000.json','["清真淡薄正相宜，肯使赬容透玉肌。", "自倚懷冰難受染，何妨凌雪獨先時。", "煙迷遠樹依稀見，風度迴塘取次吹。", "聞說江南春信早，憑君折取最繁枝。"]'),
('21d45010-b5a9-4efe-911e-753fdd81f2db','和舒伯源梅花韻  其一','李正民','宋','宋诗','song-poetry','','[]','極目凄迷杳靄間，羣芳斂迹自知難。',64,'全唐诗/poet.song.88000.json','["極目凄迷杳靄間，羣芳斂迹自知難。", "半穿籬落塗黄淺，靜對溪流照影寒。", "月地雲階偏適意，雪車冰柱苦相干。", "莫随羌笛風前舞，却怕青青逼齒酸。"]'),
('c8b0ccb2-b864-4261-8505-50276f3fe92a','和舒伯源梅花韻  其二','李正民','宋','宋诗','song-poetry','','[]','羣芳誰與鬭時宜，淡拂鉛華不著肌。',64,'全唐诗/poet.song.88000.json','["羣芳誰與鬭時宜，淡拂鉛華不著肌。", "愛靜悄無蜂蝶影，耐寒孤映雪霜時。", "瓏璁喜見銀蟾滿，零落愁聼畫角吹。", "幾許妍詞傳不盡，只誇半樹與横枝。"]'),
('978ffea4-5469-4856-8c95-6d01399364ce','和舒伯源梅花韻  其三','李正民','宋','宋诗','song-poetry','','[]','葉落千林景最宜，天教姑射露冰肌。',64,'全唐诗/poet.song.88000.json','["葉落千林景最宜，天教姑射露冰肌。", "輕明素粉初勻後，淺淡嬌黄半吐時。", "青女有情來慰藉，姮娥着意借嘘吹。", "不須驛使傳消息，看盡南枝與北枝。"]'),
('bc3a227d-7f13-4d90-98da-5681ab34be40','和舒伯源梅花韻  其四','李正民','宋','宋诗','song-poetry','','[]','簷蔔花開鷲嶺西，何如江國見纖肌。',64,'全唐诗/poet.song.88000.json','["簷蔔花開鷲嶺西，何如江國見纖肌。", "自矜六出非凡格，獨占三冬最晚時。", "刻玉漫勞誇智巧，鏤冰那復耐風吹。", "短墻深院淒涼甚，竹外攲斜一兩枝。"]'),
('11f8506a-d3d0-4177-bfc4-25d1c28cabda','和舒伯源梅花韻  其五','李正民','宋','宋诗','song-poetry','','[]','一種幽香取次宜，耻同桃杏獻瓊肌。',64,'全唐诗/poet.song.88000.json','["一種幽香取次宜，耻同桃杏獻瓊肌。", "爲嫌脂粉汙真色，誰道冰容不入時。", "寒透芳心能底痩，風欺弱質等閒吹。", "清樽何惜花前醉，莫待飄零空折枝。"]'),
('0dfc3a03-ca49-48f7-8bb3-6a9e690e61d5','春遊','李正民','宋','宋诗','song-poetry','','[]','草薫風暖氣潛催，桃李商量次第開。',64,'全唐诗/poet.song.88000.json','["草薫風暖氣潛催，桃李商量次第開。", "纂纂何須歌棗下，熙熙聊復上春臺。", "田園粗足終歸去，軒冕無心任儻來。", "盡道人生行樂爾，勿辭頻覆掌中盃。"]'),
('f7ce2e54-c6db-44cc-be55-79b751cd6771','觀德邵詩卷','李正民','宋','宋诗','song-poetry','','[]','天涯幾點四明山，萬里滄溟去路難。',64,'全唐诗/poet.song.88000.json','["天涯幾點四明山，萬里滄溟去路難。", "春晚池塘空夢草，老來塵土倦彈冠。", "文雄自可收三捷，詩好那能博一官。", "秋賦已聞丹詔下，九霄寥廓看鵬摶。"]'),
('d24c256b-ba7d-49e4-bb25-a5f88916a173','次韻同院晚春  其一','李正民','宋','宋诗','song-poetry','','[]','病思愁腸叵奈何，新詩無復苦磋磨。',64,'全唐诗/poet.song.88000.json','["病思愁腸叵奈何，新詩無復苦磋磨。", "欣聞郢客陽春曲，罷唱吴儂小海歌。", "幽徑雨餘芳草綠，小園風靜落花多。", "融樽正好酬佳景，休歎朋簪不我過。"]'),
('fdcb5309-efcd-4175-a630-72c52dee65d6','次韻同院晚春  其二','李正民','宋','宋诗','song-poetry','','[]','華年衮衮似江波，更被閒愁暗折磨。',64,'全唐诗/poet.song.88000.json','["華年衮衮似江波，更被閒愁暗折磨。", "嬾逐西園飛皂盖，却尋嚴瀨聼新歌。", "春光不爲干戈減，花發長嗟風雨多。", "已束輕装增别恨，竹林髙會阻經過。"]'),
('974941f4-3824-45b4-a63a-99ac1323f30c','寄和叔  其一','李正民','宋','宋诗','song-poetry','','[]','雙魚來自縠溪端，手把緘書子細看。',64,'全唐诗/poet.song.88000.json','["雙魚來自縠溪端，手把緘書子細看。", "授業馬融褰綘帳，懷歸王粲倚危欄。", "且憑黄耳傳消息，未辦青蚨濟急難。", "七十從心今已過，保兹遐福願加餐。"]'),
('6a9450b7-1dcc-49e7-a10c-d8f05f3dc837','寄和叔  其二','李正民','宋','宋诗','song-poetry','','[]','飄泊柯山二十春，琴書索莫困埃塵。',64,'全唐诗/poet.song.88000.json','["飄泊柯山二十春，琴書索莫困埃塵。", "憶攀楊柳當年别，愁見桃花幾度新。", "公業有田猶告乏，淵明解綬便憂貧。", "浮生種種皆爲累，况是羈棲一旅人。"]'),
('24571083-aa1c-471b-bcdd-9bba2a1de074','寄尹叔  其一','李正民','宋','宋诗','song-poetry','','[]','來往三吴幾度春，星星華髪鏡中新。',64,'全唐诗/poet.song.88000.json','["來往三吴幾度春，星星華髪鏡中新。", "厭餐柯嶺冷毛羜，急趁松江雉尾蓴。", "東海且垂任子釣，西風尚畏庾公塵。", "二千石禄慚非稱，未作隳官謝病人。"]'),
('7d6530df-7486-40cd-9a25-e66c258f6d03','寄尹叔  其二','李正民','宋','宋诗','song-poetry','','[]','爲人疏懶自天真，從宦區區本爲貧。',64,'全唐诗/poet.song.88000.json','["爲人疏懶自天真，從宦區區本爲貧。", "尚恨有情難學道，正緣無事不随人。", "腥鹹連日逢河伯，擊拍終宵困黍民。", "樂靜愛閒吾得計，何須更問要塗津。"]'),
('d51c0924-5e98-462c-83f4-6af969b4214d','寄畢少董','李正民','宋','宋诗','song-poetry','','[]','求金未有張車子，夢草聊同謝客兒。',64,'全唐诗/poet.song.88000.json','["求金未有張車子，夢草聊同謝客兒。", "萬里辛勤形骨痩，十年流落髩毛衰。", "蓬蒿繞舍春歸後，苜蓿堆盤日上時。", "極目五湖烟水闊，扁舟重理釣魚絲。"]'),
('6fbf5f66-518b-4160-a86a-63aa55a5a197','寄元叔','李正民','宋','宋诗','song-poetry','','[]','十束三鍾未苦貧，端居終歲謝塵氛。',64,'全唐诗/poet.song.88000.json','["十束三鍾未苦貧，端居終歲謝塵氛。", "春回苒苒生芳草，日暮悠悠對碧雲。", "往事已嗟存土梗，乘時争欲辨蕕薫。", "傷心極目空千里，膓斷稽山正憶君。"]'),
('9bad6a85-d160-445c-9691-5afe6b14301d','寄和叔  其一','李正民','宋','宋诗','song-poetry','','[]','君書於我不能忘，我亦思君苦斷膓。',64,'全唐诗/poet.song.88000.json','["君書於我不能忘，我亦思君苦斷膓。", "女嫁兒婚方擾擾，宦情文意愈茫茫。", "病來頗厭盃中綠，老去時添鬢畔霜。", "一夜西風破殘暑，蛩吟四壁倍淒涼。"]'),
('09707c66-58f2-43e7-a446-9dfb09754b71','寄和叔  其二','李正民','宋','宋诗','song-poetry','','[]','阮公痛哭到途窮，碧海相望西與東。',64,'全唐诗/poet.song.88000.json','["阮公痛哭到途窮，碧海相望西與東。", "流落真同土木偶，奔馳方類馬牛風。", "烏衣舊會嗟難繼，黄耳家書杳不通。", "桂樹連蜷猿嘯苦，王孫何久滯山中。"]'),
('d1cad28c-494f-4d4c-a280-b09333c20076','寄和叔  其三','李正民','宋','宋诗','song-poetry','','[]','木落山髙斷旅魂，可堪雲水隔煙村。',64,'全唐诗/poet.song.88000.json','["木落山髙斷旅魂，可堪雲水隔煙村。", "分甘賴有東屯稻，託贈初無西瀼園。", "淮上紛紜鼙鼓震，海隅絡繹羽書奔。", "何時却得同樽酒，弟勸兄酬笑語喧。"]'),
('b247aa00-24a4-46a6-b2ea-4d5fbdc616a1','寄和叔  其四','李正民','宋','宋诗','song-poetry','','[]','半生粗糲嗣先芬，肯向朝晡造業因。',64,'全唐诗/poet.song.88000.json','["半生粗糲嗣先芬，肯向朝晡造業因。", "夜鯉晨鳬那競爽，露葵霜薤自稱珍。", "烝豚未辨王武子，豆粥猶慚石季倫。", "惟有清髙井居士，葱虀麥飯久酸辛。"]'),
('8c7e9eb4-30b2-4954-813c-da8822daa7cc','再領宫祠','李正民','宋','宋诗','song-poetry','','[]','流落天涯任轉蓬，三千竊禄愧無功。',64,'全唐诗/poet.song.88000.json','["流落天涯任轉蓬，三千竊禄愧無功。", "身遊烏帽黄塵外，名在丹臺紫府中。", "賴有俸錢優白傅，且教閒處着司空。", "揮毫擬就歸田賦，檢點山資苦未豐。"]'),
('ef64f4dd-bd88-4346-bbb5-b1ee15d5eaae','劉卿任嘗新茶于佛舍元叔弟賦詩次韻  其一','李正民','宋','宋诗','song-poetry','','[]','禁籞初嘗瑞草新，侯邦仍得貴餘珍。',64,'全唐诗/poet.song.88000.json','["禁籞初嘗瑞草新，侯邦仍得貴餘珍。", "筠籃带霧分佳品，禪榻颺煙集衆賓。", "花乳清泠仙掌露，雲腴浮泛建溪春。", "草堂睡起傳佳句，愧我難陪清路塵。"]'),
('f9b53107-4eca-4224-8a68-24a435f083e7','劉卿任嘗新茶于佛舍元叔弟賦詩次韻  其二','李正民','宋','宋诗','song-poetry','','[]','北苑春芽鬭後先，斵成圭璧任方圓。',64,'全唐诗/poet.song.88000.json','["北苑春芽鬭後先，斵成圭璧任方圓。", "泉輕火活湯宜嫩，乳聚雲浮色更鮮。", "一種風流香味别，幾苞輻輳貴豪偏。", "華堂飲散纖纖捧，氣爽神清作地仙。"]'),
('fc771a95-1733-4b35-9167-20daa0c97d80','懷舊','李正民','宋','宋诗','song-poetry','','[]','遁迹漁鹽遠市朝，回廊落葉響蕭蕭。',64,'全唐诗/poet.song.88000.json','["遁迹漁鹽遠市朝，回廊落葉響蕭蕭。", "雲迷嶺岫天將雪，草沒汀洲海上潮。", "欲寄新詩人杳杳，重尋舊會恨迢迢。", "暮年更欠劉龔語，門翳蓬蒿轉寂寥。"]'),
('ecfa2448-045f-4f92-b371-ce1f6081a330','泉守汪兄內翰惠荔子蕉乾','李正民','宋','宋诗','song-poetry','','[]','遠使擔簦到草堂，泉州太守未相忘。',64,'全唐诗/poet.song.88000.json','["遠使擔簦到草堂，泉州太守未相忘。", "素書豈但寒暄問，篚實仍分果蓏香。", "荔子尚滋閩嶺露，蕉乾猶带粤林霜。", "自憐遼鶴歸飛倦，咀嚼偏知氣味長。"]'),
('4588af7b-05fb-4b32-bccf-d88c4cd1ea55','和叔來謁李守值其在告作詩戲之','李正民','宋','宋诗','song-poetry','','[]','赤袍畫戟擁朱門，鈴閣晨扃正謝賓。',64,'全唐诗/poet.song.88000.json','["赤袍畫戟擁朱門，鈴閣晨扃正謝賓。", "京兆欲行猶案事，杜陵投老尚論親。", "蕙帷鶴怨空寒夜，名紙毛生踏路塵。", "南郡髙風非託疾，未應吐哺愧前人。"]'),
('87e50d40-d4a1-4750-8fd8-e9d62f71d8b4','送元叔守建昌  其一','李正民','宋','宋诗','song-poetry','','[]','論都獻賦動凝旒，誰料材髙却滯留。',64,'全唐诗/poet.song.88000.json','["論都獻賦動凝旒，誰料材髙却滯留。", "芸閣九烏刊蠹簡，霜臺一鶚在清秋。", "中年未得文章力，儉歲空懷兒女憂。", "游刃小邦真易爾，且將歌吹薦觥籌。"]'),
('f3e84bbe-f72e-494a-880b-df3046c2f131','送元叔守建昌  其二','李正民','宋','宋诗','song-poetry','','[]','少時佔畢共辛勤，晚歲飄零寂寞濱。',64,'全唐诗/poet.song.88000.json','["少時佔畢共辛勤，晚歲飄零寂寞濱。", "未分塵埃蒙琬琰，豈容蹭蹬老麒麟。", "文因飽學多多辨，詩爲窮愁日日新。", "五十專城雖不晚，漢廷詔令要詞臣。"]'),
('d6f59be0-e5ed-4dd0-9b70-6f6ad89af5c7','寄宣守內翰汪彦章','李正民','宋','宋诗','song-poetry','','[]','中朝舊德號儒宗，鳯閣鸞臺揖下風。',64,'全唐诗/poet.song.88000.json','["中朝舊德號儒宗，鳯閣鸞臺揖下風。", "夢寐升沉十年事，歲寒情分兩人同。", "竹籬茅舍窮愁我，紅旆油幢富貴公。", "應有澄江如練白，願憑尺素寄冥鴻。"]'),
('a8285b43-68d5-4a3b-8364-22c37579a6e4','邦求示詩述其昆弟鼎臣寶臣守平江因以和之','李正民','宋','宋诗','song-poetry','','[]','玉昆金友播先芬，兩驥騰驤踵後塵。',64,'全唐诗/poet.song.88000.json','["玉昆金友播先芬，兩驥騰驤踵後塵。", "瓊笈繼繙羣玉府，麟符更鎮五湖春。", "政成比屋冰霜肅，慶衍髙門雨露新。", "棠棣不須刊善頌，家風稱述有安仁。"]'),
('f99ac84e-231c-4671-9eb3-81608a5fea91','納涼詩','李正民','宋','宋诗','song-poetry','','[]','鑠石流金正此時，乍收羲馭霽餘威。',64,'全唐诗/poet.song.88000.json','["鑠石流金正此時，乍收羲馭霽餘威。", "屋頭艶艶蟾蜍滿，草際熒熒熠燿飛。", "沉李浮瓜聊自適，披襟散髪欲忘歸。", "只愁玉漏頻催轉，坐使清涼與願違。"]'),
('675c9211-97ca-4200-9050-23e18df16e75','寓居','李正民','宋','宋诗','song-poetry','','[]','昔年南渡苦奔波，天幸驚禽脫網羅。',64,'全唐诗/poet.song.88000.json','["昔年南渡苦奔波，天幸驚禽脫網羅。", "結綬懷黄真忝竊，求田問舍已蹉跎。", "爛柯山下樵蘇賤，檇李城邊魚蠏多。", "萍泛蓬飄終未靖，作勞聊復强悲歌。"]'),
('5b1090cf-5018-461d-8c59-be900f5e01ed','投老','李正民','宋','宋诗','song-poetry','','[]','投老疏慵分棄捐，潛心終日玩韋編。',64,'全唐诗/poet.song.88000.json','["投老疏慵分棄捐，潛心終日玩韋編。", "欲臨南浦開三徑，更就東臯卜一廛。", "得意故人多厚禄，入流舊吏亦登仙。", "閒來且泛秦溪水，笑把蘭橈上釣船。"]'),
('09da86f6-41f7-433d-b481-f2c013582752','次韻汪汝直同年','李正民','宋','宋诗','song-poetry','','[]','紫陌同尋上苑春，升沉榮謝事難論。',64,'全唐诗/poet.song.89000.json','["紫陌同尋上苑春，升沉榮謝事難論。", "時危重歎青氈失，老去空驚白髪新。", "共待聲名繼裴馬，更崇風義比雷陳。", "自慚持橐終無補，擬乞麾符寂寞濱。"]'),
('10df5cc0-0763-44af-8986-d4b8f417a8f2','大暑呈彦章內翰','李正民','宋','宋诗','song-poetry','','[]','亭午炎曦轉轂遲，好風時復問雄雌。',64,'全唐诗/poet.song.89000.json','["亭午炎曦轉轂遲，好風時復問雄雌。", "難爲褦襶造門客，正是村原渇雨時。", "玉醴注荷灣象鼻，金盃貯水漬龍皮。", "琳宫散吏寧論此，幸免文書苦見治。"]'),
('2220e4d9-a31d-42bb-8f26-5d99438e7d46','題蒙園','李正民','宋','宋诗','song-poetry','','[]','翛然風景可怡情，採菊東籬曉露零。',64,'全唐诗/poet.song.89000.json','["翛然風景可怡情，採菊東籬曉露零。", "天上早聯卿士月，雲間今見少微星。", "映門楊柳絲垂地，對岸芙蓉錦作屏。", "擬結茅茨相近住，往來二老可忘形。"]'),
('e6f4a342-4fba-4bb2-a6a4-9c40888f1d77','聞元叔移居姚江','李正民','宋','宋诗','song-poetry','','[]','漲海連天古縣幽，浮家泛宅竟何求。',64,'全唐诗/poet.song.89000.json','["漲海連天古縣幽，浮家泛宅竟何求。", "紅旗黄紙俱無預，白璧明珠豈易投。", "世路久諳聊爾爾，宦情將老亦悠悠。", "不須更說黄粱夢，二頃良田早自謀。"]'),
('80adeb5c-d0ca-4cd5-825b-9642298f6fcd','次韻葉舍人  其一','李正民','宋','宋诗','song-poetry','','[]','宣室君王欲受釐，斯民將見少休期。',64,'全唐诗/poet.song.89000.json','["宣室君王欲受釐，斯民將見少休期。", "閒中把卷空遮眼，亂後操心甚累棋。", "郵置未傳殷浩信，筠筒先寄樂天詩。", "壺中日月公應惜，拚醉樽前十様眉。"]'),
('285dc09a-ec17-48df-b9f5-901d70bb68e9','次韻葉舍人  其二','李正民','宋','宋诗','song-poetry','','[]','艱難險阻寄餘生，重奏塤篪耳屢傾。',64,'全唐诗/poet.song.89000.json','["艱難險阻寄餘生，重奏塤篪耳屢傾。", "靜對竹陰談近事，頻看山色驗初晴。", "老來漸覺憂婚嫁，禄厚寧無耻聖明。", "稍喜幽燕通使者，叔孫當使郢投兵。"]'),
('a4cb853f-f657-4037-b286-63cdae8fabec','次韻葉舍人  其三','李正民','宋','宋诗','song-poetry','','[]','螭坳執筆侍清光，天閣峨峨聳百常。',64,'全唐诗/poet.song.89000.json','["螭坳執筆侍清光，天閣峨峨聳百常。", "便合揮毫演綸綍，何勞琢句鬭琳琅。", "峰巒對户千重碧，䆉稏連雲六月涼。", "鳯閣鸞臺有虛位，未容諸葛臥南陽。"]'),
('cd71f409-1843-4d61-966f-efb6083ae574','卜居','李正民','宋','宋诗','song-poetry','','[]','吴越飄零已十年，侵尋綠髪變華顛。',64,'全唐诗/poet.song.89000.json','["吴越飄零已十年，侵尋綠髪變華顛。", "身閒且運陶公甓，力弱難先祖逖鞭。", "兵火廣陵無舊業，溝渠檇李有新田。", "此懷應被元龍笑，更傍苕溪卜一廛。"]'),
('f8208099-0a84-4bf2-b0ca-d2b6ba17f45e','别邦求','李正民','宋','宋诗','song-poetry','','[]','流落天涯見友生，笑談宛似舊宣城。',64,'全唐诗/poet.song.89000.json','["流落天涯見友生，笑談宛似舊宣城。", "春愁黯黯渾無奈，别恨綿綿誰與平。", "膠漆久要前日契，風霜不改故人情。", "三年留滯覉懷惡，且向雲間跨海鯨。"]'),
('d3935673-00df-46bb-9c89-2b2eac488bec','將之海鹽留别和叔  其一','李正民','宋','宋诗','song-poetry','','[]','閒官贏得自由身，且逐漁鹽滄海濱。',64,'全唐诗/poet.song.89000.json','["閒官贏得自由身，且逐漁鹽滄海濱。", "老去心情尤惜别，亂餘宗黨喜相親。", "向平兒女催婚嫁，陶令田園翳棘榛。", "擾擾浮生須有後，不應迢遞爲鱸蓴。"]'),
('36b4897c-0269-4146-8b28-e7d2289d5685','將之海鹽留别和叔  其二','李正民','宋','宋诗','song-poetry','','[]','國恩未報作閒人，猶愧塵蹤待玉宸。',64,'全唐诗/poet.song.89000.json','["國恩未報作閒人，猶愧塵蹤待玉宸。", "松菊就荒徒引領，山川信美獨傷神。", "杜陵衰老終辭蜀，王粲登臨苦憶秦。", "行止非人難預料，他年重上縠溪津。"]'),
('b4b98213-de08-4f8a-ba06-429e68992a67','將之海鹽留别和叔  其三','李正民','宋','宋诗','song-poetry','','[]','煙塵倉猝到淮東，僅亢衰宗擾擾中。',64,'全唐诗/poet.song.89000.json','["煙塵倉猝到淮東，僅亢衰宗擾擾中。", "浩氣不爲憂患折，直辭寧與詭随同。", "西清自愧名浮實，河潤深慚惠未豐。", "白髪相看真惜别，祗憑一溉養衰翁。"]'),
('34c4cb14-ec4c-4407-8922-b0b2d79a56ec','連雨薪舫不至','李正民','宋','宋诗','song-poetry','','[]','大隱堂中岸角巾，尚叨微禄不憂貧。',64,'全唐诗/poet.song.89000.json','["大隱堂中岸角巾，尚叨微禄不憂貧。", "未論方朔一嚢粟，正乏支離十束薪。", "澤國煙波偏苦雨，梅天蒸潤更兼旬。", "扁舟會泛江湖去，鷗鳥相随作散人。"]'),
('2b531321-927d-4de7-adb4-63d8d1b458c4','髙安得請  其一','李正民','宋','宋诗','song-poetry','','[]','免涉風波千里行，江西道院久榛荆。',64,'全唐诗/poet.song.89000.json','["免涉風波千里行，江西道院久榛荆。", "早知季子非忘故，自笑樊生不習兵。", "禄賦百朋恩未報，門開三徑計難成。", "老來漸覺無多累，遯世終期學向平。"]'),
('ab05c587-6ef2-4a1b-9e61-7cbd5c555ac6','髙安得請  其二','李正民','宋','宋诗','song-poetry','','[]','九霄飛下白雲章，寵假琳宫許退藏。',64,'全唐诗/poet.song.89000.json','["九霄飛下白雲章，寵假琳宫許退藏。", "夢得固難之播水，汲生安敢薄淮陽。", "寧随鷄鶩同爭食，自喜芝蘭保獨芳。", "苕霅西山猶好在，扁舟從此釣滄浪。"]'),
('80eb1165-d3ad-42ee-a3bd-1b654d236a56','戲德邵','李正民','宋','宋诗','song-poetry','','[]','漫說靈犀一點通，人生誰肯困途窮。',64,'全唐诗/poet.song.89000.json','["漫說靈犀一點通，人生誰肯困途窮。", "遠同漢代東方朔，近比江西黄仲熊。", "休戴南金雙德勝，幸逢膏澤屢年豐。", "薄田正可捐鷄肋，義士于今少古鴻。"]'),
('20f24235-1b83-4060-a361-e87aed2dffc8','戲和叔','李正民','宋','宋诗','song-poetry','','[]','耆年多病心未老，異縣久羈家益窮。',64,'全唐诗/poet.song.89000.json','["耆年多病心未老，異縣久羈家益窮。", "貽書乞米朝不飽，作賦教子文尤工。", "春風不消兩鬢雪，酒力尚借雙腮紅。", "歸來羣芳已零落，苦恨鶗鴂鳴匆匆。"]'),
('519644ff-2b1c-47b0-a406-d74fab72acdd','人日和同院  其一','李正民','宋','宋诗','song-poetry','','[]','層冰積雪已經旬，霽色初欣日在人。',64,'全唐诗/poet.song.89000.json','["層冰積雪已經旬，霽色初欣日在人。", "一歲暗添身漸老，百篇賡和筆如神。", "金花柏葉聊圖醉，車柳舟芻漫逐貧。", "苦恨郊原芳意晚，預期聯騎去尋春。"]'),
('e468dc86-83e2-45a2-851c-95c021be9b52','人日和同院  其二','李正民','宋','宋诗','song-poetry','','[]','跳丸日月走虛空，又見曦輪參尾中。',64,'全唐诗/poet.song.89000.json','["跳丸日月走虛空，又見曦輪參尾中。", "冰雪侵凌傷暖律，芳菲排辦待和風。", "家無儋石猶能樂，腹有詩書未是窮。", "酒後笑談無畔岸，更將妙道問鴻濛。"]'),
('df7c02df-65a9-4d50-8235-3795e21953c2','人日和同院  其三','李正民','宋','宋诗','song-poetry','','[]','玉燭初更品物新，又觀剪綵鏤金人。',64,'全唐诗/poet.song.89000.json','["玉燭初更品物新，又觀剪綵鏤金人。", "休嗟歲歲年年貌，且送奇奇怪怪神。", "酒有十千元自富，食兼三九未全貧。", "王孫詩筆能鏖戰，夜遣偏師敵富春。"]'),
('029b7d1b-09f0-476b-9c6a-ef8d9d493676','人日和同院  其四','李正民','宋','宋诗','song-poetry','','[]','一三五七變而通，端月駸駸氣已中。',64,'全唐诗/poet.song.89000.json','["一三五七變而通，端月駸駸氣已中。", "花勝菜羮新節物，柳條桃蕚舊春風。", "詩成杜老曾悲雪，文就韓公向諱窮。", "我有鄉名實不足，已將貧富任空濛。"]'),
('e7c6be55-2693-4fb7-b286-2afd7fe08ede','贈章生','李正民','宋','宋诗','song-poetry','','[]','廷尉歸來解組纓，門前羅雀自飛鳴。',64,'全唐诗/poet.song.89000.json','["廷尉歸來解組纓，門前羅雀自飛鳴。", "已悲楚相爲廉吏，更愧相如擅長名。", "十部貽書寧有補，五漿先饋豈無驚。", "朝廷不晚頒賢詔，佇看鵬摶萬里程。"]'),
('0ac48d12-1c7a-44ab-b16b-5d4c5ef27db4','寄德邵  其一','李正民','宋','宋诗','song-poetry','','[]','躡屩擔簦又徙居，未能慷慨賦歸與。',64,'全唐诗/poet.song.89000.json','["躡屩擔簦又徙居，未能慷慨賦歸與。", "浯溪難繼中興頌，西塞重尋漁父書。", "故國山川懷望切，在廷知舊記憐疏。", "不須更論升沉事，鍾釡年年粟有餘。"]'),
('85055879-bf73-4381-b187-5366ea687efc','寄德邵  其二','李正民','宋','宋诗','song-poetry','','[]','聞說王門久曳裾，餘皇曾奉數行書。',64,'全唐诗/poet.song.89000.json','["聞說王門久曳裾，餘皇曾奉數行書。", "柯山倥偬難爲客，海岸蕭條且屏居。", "侯喜不應操耒具，井丹寧肯食葱菹。", "扁舟過我非難事，百結心旌待子舒。"]'),
('c22115c6-fdd6-4a14-9281-b234c728e3e2','寄元叔因呈知府內翰','李正民','宋','宋诗','song-poetry','','[]','聞說移居向越州，三生風月舊曾遊。',64,'全唐诗/poet.song.89000.json','["聞說移居向越州，三生風月舊曾遊。", "秦碑古字應難讀，禹穴餘書尚可求。", "海蠏江珧薦醽醁，林苞野蕨助肴羞。", "遥知屢下陳蕃榻，顧我飄零阻獻酬。"]'),
('5fc1668c-ad23-41fc-87be-48e7be629e17','寄元叔  其一','李正民','宋','宋诗','song-poetry','','[]','十年出處略相同，名在丹臺第幾重。',64,'全唐诗/poet.song.89000.json','["十年出處略相同，名在丹臺第幾重。", "欲富未能求五牸，爲貧聊且受三鍾。", "寒灰復焰慚安國，窮鬼何知笑伯龍。", "泛宅浮家苕霅上，一觴一詠可從容。"]'),
('1742b483-993e-44e4-8970-70546dc2de86','寄元叔  其二','李正民','宋','宋诗','song-poetry','','[]','海上欣逢梅柳新，旅懷悽惨倍傷春。',64,'全唐诗/poet.song.89000.json','["海上欣逢梅柳新，旅懷悽惨倍傷春。", "飄浮正類河中木，聚散還同陌上塵。", "終擬文章爲世用，未應富貴後時人。", "登臨况有新詩句，滿篋珠璣豈患貧。"]'),
('9ae4db5c-b635-44c7-8f98-5aa1438c4a8e','寄元叔  其三','李正民','宋','宋诗','song-poetry','','[]','十日寒雲不肯晴，黑貂裘敝客心驚。',64,'全唐诗/poet.song.89000.json','["十日寒雲不肯晴，黑貂裘敝客心驚。", "旗亭雪濕難沽酒，煬竈煙消類戛羮。", "學辯痴龍真末技，文摛彩鳯亦虚名。", "山居自足三冬用，老大何嫌秉燭明。"]'),
('85ffea80-1d8e-476f-a968-3263a318aac8','和元叔再至分水韻','李正民','宋','宋诗','song-poetry','','[]','倦翼卑飛憶故林，弟兄隔闊倍傷心。',64,'全唐诗/poet.song.89000.json','["倦翼卑飛憶故林，弟兄隔闊倍傷心。", "神州翻作豺狼窟，天塹猶防馬箠侵。", "何幸鴒原同急難，寧將茅茹論升沉。", "不須更語劉玄德，始覺元龍用意深。"]'),
('d575e8ed-0bbc-4dc3-a0a4-8beaea4732da','自嘲','李正民','宋','宋诗','song-poetry','','[]','寥落覊栖向海隅，終年局促臥蝸廬。',64,'全唐诗/poet.song.89000.json','["寥落覊栖向海隅，終年局促臥蝸廬。", "閑如白傅不飲酒，窮似虞卿懶著書。", "永夜悲涼聼蟋蟀，幾回圓缺看蟾蜍。", "扶搖何日乘風去，獨跨鯨魚上碧虛。"]'),
('8b82f0c2-25a4-4e13-9222-c622e4c6be51','和元叔聞德邵省下之作','李正民','宋','宋诗','song-poetry','','[]','文塲決勝事何如，神助曾無合浦珠。',64,'全唐诗/poet.song.89000.json','["文塲決勝事何如，神助曾無合浦珠。", "正論久知傳木鐸，哇音寧使混錞釪。", "土風未改猶思楚，射御今應復教吴。", "白雪調髙難繼和，壎篪歌詠古相須。"]'),
('4da71d39-85a7-42a1-a342-f7ae7fb81366','和孫邦求  其一','李正民','宋','宋诗','song-poetry','','[]','筆硯情親二十年，相逢直欲盡君歡。',64,'全唐诗/poet.song.89000.json','["筆硯情親二十年，相逢直欲盡君歡。", "短檠况味同春夢，老鶴精神耐歲寒。", "閉户每欣聞杖履，啣盃屢笑倒巾冠。", "墻頭梅蕚休嗟晚，爲恐騷人思漸闌。"]'),
('5186850a-3e87-4599-a0f9-a22f2c03dee8','和孫邦求  其二','李正民','宋','宋诗','song-poetry','','[]','回首宣城一夢間，黄公壚畔記前歡。',64,'全唐诗/poet.song.89000.json','["回首宣城一夢間，黄公壚畔記前歡。", "故交十載窮空谷，得路三人到廣寒。", "韓愈應須拜東野，鍾儀未必困南冠。", "平津晚佩黄金印，穏步青雲興始闌。"]'),
('70a858aa-4307-4809-b115-6de1364dcef6','和孫邦求  其三','李正民','宋','宋诗','song-poetry','','[]','投老侵尋兩鬢斑，十年情緒幾悲歡。',64,'全唐诗/poet.song.89000.json','["投老侵尋兩鬢斑，十年情緒幾悲歡。", "深傾玉醑何辭醉，養就金丹不畏寒。", "鶴馭且芸崑閬草，鸞臺曾著鵔鸃冠。", "少時豪氣消磨盡，賴有詩情偶未闌。"]'),
('85ee96ee-9104-4688-b2a9-7b6c689c344d','和孫邦求  其四','李正民','宋','宋诗','song-poetry','','[]','結友何殊杵臼間，舊遊重話發清歡。',64,'全唐诗/poet.song.89000.json','["結友何殊杵臼間，舊遊重話發清歡。", "西江候月愁宵永，南郭尋梅耐歲寒。", "老筆尚凌游獵賦，剛腸宜戴觸邪冠。", "鶚書屢上初無補，宣室咨詢待夜闌。"]'),
('e634f9cd-bae5-4c46-917f-4f9b6252cb1d','和孫邦求  其五','李正民','宋','宋诗','song-poetry','','[]','流落天涯强自寛，清樽相對漫追歡。',64,'全唐诗/poet.song.89000.json','["流落天涯强自寛，清樽相對漫追歡。", "難求美玉能回暖，豈有良金解辟寒。", "放曠尚慚垂貝带，招徠安敢望皮冠。", "野梅官柳聊行樂，坐見崢嶸歲已闌。"]'),
('294e8df5-0636-4600-9e4d-f6eefdad2320','再和邦求一首','李正民','宋','宋诗','song-poetry','','[]','曾綴楓宸供奉班，異鄉飄泊若爲歡。',64,'全唐诗/poet.song.89000.json','["曾綴楓宸供奉班，異鄉飄泊若爲歡。", "翟公羅雀交情見，鄭老無氈客坐寒。", "稍喜羽書清紫塞，欲從鞍馬愧儒冠。", "篋中未有歸田賦，敢謂臨波意便闌。"]'),
('b8113cc7-67a9-4769-b4db-1911d6e5509c','和平叔見寄','李正民','宋','宋诗','song-poetry','','[]','手折梅花驛使傳，在原鴒翼尚翩翩。',64,'全唐诗/poet.song.89000.json','["手折梅花驛使傳，在原鴒翼尚翩翩。", "老來庾信多愁思，歸去陶潛只醉眠。", "窮巷悄無車馬跡，安心久解祖師禪。", "夢回雲海遙千里，春草池塘憶惠連。"]'),
('ba23a9e1-d6f5-46aa-a71d-64c7ccd305ba','和邦求見寄','李正民','宋','宋诗','song-poetry','','[]','坐看霜霰送窮冬，流落天涯類斷蓬。',64,'全唐诗/poet.song.89000.json','["坐看霜霰送窮冬，流落天涯類斷蓬。", "詞翰難陪杜陵老，滄浪聊訪紫谿翁。", "想尋芳草門庭在，憶對梅花笑語同。", "海腊腥鹹難致遠，漫憑黄耳附書筒。"]'),
('7bdc2b9a-0f9c-437a-90fd-1515a31d69bd','和德邵','李正民','宋','宋诗','song-poetry','','[]','文傳臺閣播聲名，我老何庸作重輕。',64,'全唐诗/poet.song.89000.json','["文傳臺閣播聲名，我老何庸作重輕。", "束緼莫能還逐婦，亡羊因使歎無兄。", "初期薦牘青冥上，忽泛扁舟滄海行。", "病已好同遊甫里，虹橋風月待秋清。"]'),
('309b12e9-74c6-4af1-beaa-8370e25aa224','和尹叔見寄  其一','李正民','宋','宋诗','song-poetry','','[]','海濱遯迹擬求安，老矣尤諳世路難。',64,'全唐诗/poet.song.89000.json','["海濱遯迹擬求安，老矣尤諳世路難。", "地遠巳辭龜鈕印，身閒仍带鹿皮冠。", "少陵宴坐惟觀壁，彭澤知非欲去官。", "鵬鷃逍遙皆自適，勿疑控地笑扶摶。"]'),
('f19c34dd-d0fa-4342-9e23-025a97b560f7','和尹叔見寄  其二','李正民','宋','宋诗','song-poetry','','[]','心似行雲憶故山，干戈滿地欲歸難。',64,'全唐诗/poet.song.89000.json','["心似行雲憶故山，干戈滿地欲歸難。", "愁腸索寞頻澆酒，病骨支離懶正冠。", "鄭太田多猶乏食，阮公錢入便辭官。", "久知身世皆如夢，萬事何須苦控摶。"]'),
('ded581e3-8f20-4899-9cfd-cd98cff105de','和平叔  其一','李正民','宋','宋诗','song-poetry','','[]','舊結茅茨閱十春，憶曾捫蝨話酸辛。',64,'全唐诗/poet.song.89000.json','["舊結茅茨閱十春，憶曾捫蝨話酸辛。", "當年巳訝霜髭老，今日何辭酒盞頻。", "得儁東床人似玉，頌功槐府筆揮銀。", "從今稳步青雲上，聊慰投閒物外人。"]'),
('7f48117f-cf2a-4467-8b53-7c8c0cceb92b','和平叔  其二','李正民','宋','宋诗','song-poetry','','[]','紅日新添一線催，竹爐紙閣聚寒灰。',64,'全唐诗/poet.song.89000.json','["紅日新添一線催，竹爐紙閣聚寒灰。", "雨滋長畝纔抽麥，雪漬南枝欲放梅。", "歲月峥嶸嗟老矣，弟兄漂泊思悠哉。", "扁舟過我消離恨，肯使雲帆取次回。"]'),
('4056351c-8ba6-4d77-8887-ff4ff238ba47','和平叔  其三','李正民','宋','宋诗','song-poetry','','[]','歲晚棲棲作遠遊，足音真可慰窮愁。',64,'全唐诗/poet.song.89000.json','["歲晚棲棲作遠遊，足音真可慰窮愁。", "身閒文史聊覃思，老去田園亦强謀。", "旋撥濁醪篘凍酒，何嫌糲食辦晨羞。", "新篇起我超然興，苦恨輕装不少留。"]'),
('6118d918-c1eb-4ca1-b5f5-053696b932d6','示鹿苑如老','李正民','宋','宋诗','song-poetry','','[]','隱約平林夕照紅，杖藜松徑叩蓮宫。',64,'全唐诗/poet.song.89000.json','["隱約平林夕照紅，杖藜松徑叩蓮宫。", "有言未必輸摩詰，得句何妨示己公。", "自靜其心心合道，無情于境境成空。", "誰知覿面相看處，洞水西流信已通。"]'),
('8d68473d-13f3-4957-b6d0-8b1064dca724','立春  其一','李正民','宋','宋诗','song-poetry','','[]','餘閏推遷歲已新，青陽不待月加寅。',64,'全唐诗/poet.song.89000.json','["餘閏推遷歲已新，青陽不待月加寅。", "朔風卷雪寒催臘，和氣消冰早變春。", "細餅堆盤随舊俗，磔牛當路樂村民。", "流光衮衮催人老，心地閒來只任真。"]'),
('c0d8e522-4f58-458a-85d7-45d994e3dd6e','立春  其二','李正民','宋','宋诗','song-poetry','','[]','七始初華國令新，芸芸品彙達于寅。',64,'全唐诗/poet.song.89000.json','["七始初華國令新，芸芸品彙達于寅。", "葭灰潛動先占候，柳眼偷開早報春。", "曾見花枝沾近侍，且頒寛詔澤編民。", "鏡中鬢髪蕭蕭改，却羡松筠自葆真。"]'),
('ed5bb1d6-ca34-4458-affb-e5329bed4caa','次韻邢丞立春','李正民','宋','宋诗','song-poetry','','[]','一望東郊草色勻，暄然和氣物皆春。',64,'全唐诗/poet.song.89000.json','["一望東郊草色勻，暄然和氣物皆春。", "發生青陸權輿始，恢復皇州送喜頻。", "勝鏤金花人漸老，盤堆生菜味尤新。", "賡歌共睹中興日，擊壤難酬堯舜仁。"]'),
('09164c3c-c8ed-4ff7-90cb-20e9c4cee1a8','書花蕚集後','李正民','宋','宋诗','song-poetry','','[]','二李詩名播浙東，二車豪邁氣争雄。',64,'全唐诗/poet.song.89000.json','["二李詩名播浙東，二車豪邁氣争雄。", "霜臺健筆凌騷雅，鳯沼餘波入古風。", "賦就崧髙辭並美，集編華蕚句皆工。", "龐眉書客遺音在，白玉樓成事已空。"]'),
('608eef06-dd0b-419b-aa03-1dae9c5954de','快閣','李正民','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江勢若傾，登臨仍值雨初晴。',64,'全唐诗/poet.song.89000.json','["萬里長江勢若傾，登臨仍值雨初晴。", "前山依約雲方斂，遠樹參差晚更明。", "禪榻靜尋僧舍宿，扁舟閒傍釣磯横。", "時危滿目傷心事，誰把留犁再歃盟。"]'),
('272cd689-ca1a-4632-9b4f-f7128591ba5b','中秋對月','李正民','宋','宋诗','song-poetry','','[]','流年苒苒又秋中，對酒何須念固窮。',64,'全唐诗/poet.song.89000.json','["流年苒苒又秋中，對酒何須念固窮。", "颯颯西風破殘暑，迢迢銀漢瀉長空。", "一輪已見今宵滿，千里寧知此意同。", "名姓舊聞題斧扆，重看通籍大明宫。"]'),
('0eacae2b-7b11-4812-8416-1bee1e6c1b77','行縣福清憇廬山院竹軒用壁間韻','李正民','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','伏雨闌風倦暑途，傍簷疏竹暫清虛。',64,'全唐诗/poet.song.89000.json','["伏雨闌風倦暑途，傍簷疏竹暫清虛。", "藍田頗畏趙卿日，裹飯頻經乾竺居。", "過嶺黄雲收䆉稏，隔溪烟瞑點舂鉏。", "山川信美懷吾土，何必臨川更羡魚。"]'),
('942286df-8d6e-47a2-a590-f7b003e87b2f','風雨','李正民','宋','宋诗','song-poetry','','[]','淒淒風雨卷重茅，幽徑荒涼杞菊凋。',64,'全唐诗/poet.song.89000.json','["淒淒風雨卷重茅，幽徑荒涼杞菊凋。", "媚學僅能延趙子，言詩何遽失參寥。", "人情狙詐真難測，愁緒牛毛未易消。", "靜閉柴門誰與晤，惟堪痛飲讀離騷。"]'),
('d949c118-c575-47e0-bb14-71dd702c63f5','括蒼泛舟','李正民','宋','宋诗','song-poetry','','[]','一溪春水碧潺湲，舟泝奔灘激浪喧。',64,'全唐诗/poet.song.89000.json','["一溪春水碧潺湲，舟泝奔灘激浪喧。", "雨洗隴苗何限綠，日催林杏不勝繁。", "峰巒環合疑無路，草木蒙茸忽見村。", "自歎經年久爲客，靜聼啼鳥更消魂。"]'),
('53804af7-9e64-4203-8cce-b4236f4a3935','邦求置酒賞梅','李正民','宋','宋诗','song-poetry','','[]','短籬深院獨開遲，似恐芳心别有期。',64,'全唐诗/poet.song.89000.json','["短籬深院獨開遲，似恐芳心别有期。", "細雨班班珠濺淚，苦寒戚戚玉消肌。", "數枝屋角爭先見，萬點墻陰爛漫披。", "冷艶清香能幾許，虛堂猶得薦瑶巵。"]'),
('9d491f8e-163b-4922-8dc3-037715515170','再賦','李正民','宋','宋诗','song-poetry','','[]','破臘開花苦恨遲，雪中辜負賞心期。',64,'全唐诗/poet.song.89000.json','["破臘開花苦恨遲，雪中辜負賞心期。", "鉛黄猶見塗嬌額，獺髓應難補病肌。", "淚滴玉容空寂寞，粧成半面已離披。", "莫教點綴蒼苔地，要對殘芳釂屈巵。"]'),
('0fca1202-9ac8-470b-a710-6fc8f71eb998','賦雪  其一','李正民','宋','宋诗','song-poetry','','[]','六花撩亂似飛蓬，落處寧分室與宫。',64,'全唐诗/poet.song.89000.json','["六花撩亂似飛蓬，落處寧分室與宫。", "墨突不黔非减爨，秦烏變白罷盤風。", "華顛欺我三千丈，勁氣輸他十八公。", "待得燭龍銜耀至，冰消雲卷靜歸空。"]'),
('09f2e660-45cf-46b5-ab71-b110a620aadc','賦雪  其二','李正民','宋','宋诗','song-poetry','','[]','深巷髙眠路不通，誰知車騎謁王宫。',64,'全唐诗/poet.song.89000.json','["深巷髙眠路不通，誰知車騎謁王宫。", "威凌布被秋宵雨，色比麻衣曹國風。", "亂撃鴈陂思李將，閑披鶴氅憶王公。", "淒涼惟有詩人苦，忍凍孤吟四壁空。"]'),
('2c26894b-1ebf-4e22-8e21-892c4a1b05dd','和趙表之大監對雪  其一','李正民','宋','宋诗','song-poetry','','[]','韜霞掩日冷雲同，恍惚身遊銀色宫。',64,'全唐诗/poet.song.89000.json','["韜霞掩日冷雲同，恍惚身遊銀色宫。", "善巧作花輕墮砌，强名解舞漫随風。", "四郊普覆沾豐澤，萬室平分荷至公。", "興減有時無著相，觀空是色色還空。"]'),
('bc66566e-b4a9-426b-b65d-763ab63af98e','和趙表之大監對雪  其二','李正民','宋','宋诗','song-poetry','','[]','瑶花飛舞下洪濛，冷落茶煙古佛宫。',64,'全唐诗/poet.song.89000.json','["瑶花飛舞下洪濛，冷落茶煙古佛宫。", "剪水装花俱是幻，開簾入隙總因風。", "門無行迹知袁令，坐擁重裘屬衛公。", "遙想凈名禪榻上，蒙頭端坐萬緣空。"]'),
('77e2195f-dce0-495c-9c13-6abaa1c27046','再賦  其一','李正民','宋','宋诗','song-poetry','','[]','寒威逗曉入簾櫳，亂雨天花帝釋宫。',64,'全唐诗/poet.song.89000.json','["寒威逗曉入簾櫳，亂雨天花帝釋宫。", "皜皜易汙休擁篲，紛紛何似祗從風。", "能文誰復延枚叟，乘興真宜訪戴公。", "老去映書無眼力，夜闌惟喜月當空。"]'),
('5111bf4a-8c9d-447b-9db8-eb06be97dab2','再賦  其二','李正民','宋','宋诗','song-poetry','','[]','靄靄雲衢凝不通，人間化出玉華宫。',64,'全唐诗/poet.song.89000.json','["靄靄雲衢凝不通，人間化出玉華宫。", "汗漫光轉方輿地，淅瀝聲随廣莫風。", "飛絮比輕知酷似，寒梅妬潔諒非公。", "已占三白爲嘉瑞，愁殺貧家甔石空。"]'),
('3a44772c-ca4b-451a-88d9-e341c463b9db','對雪','李正民','宋','宋诗','song-poetry','','[]','朔風千里凍寒雲，三白呈祥副所聞。',64,'全唐诗/poet.song.89000.json','["朔風千里凍寒雲，三白呈祥副所聞。", "洒處蕭蕭仍淅淅，風來靄靄復雰雰。", "糢糊碧瓦俱同色，挺特疏梅自出羣。", "忽憶去年詩酒會，鄒枚司馬盡能文。"]'),
('98381665-4273-463a-a546-bebe59c3e30f','舟中值雪','李正民','宋','宋诗','song-poetry','','[]','百里清波一葦航，茅簷燈火照漁梁。',64,'全唐诗/poet.song.89000.json','["百里清波一葦航，茅簷燈火照漁梁。", "寒吹褐袂風頭急，夜洒篷窗雪片颺。", "乘興去尋戴安道，異書思見蔡中郎。", "胸懷礧碨須傾倒，樽酒相看氣味長。"]'),
('17bdb717-0b39-4328-8c2c-3f56ed0a9baf','酬德邵','李正民','宋','宋诗','song-poetry','','[]','三年絕域寄孤身，齧雪吞旃踵昔人。',64,'全唐诗/poet.song.89000.json','["三年絕域寄孤身，齧雪吞旃踵昔人。", "琴奏南音惟念楚，雞鳴中夜忽離秦。", "重來澤國尋漁父，免向沙埸逐鴈臣。", "好在五湖波浪闊，解纓濯盡塞垣塵。"]'),
('a581d976-44c7-4036-8d5a-882cc249957f','送李及甫侍郎知筠州','李正民','宋','宋诗','song-poetry','','[]','珥筆風聲播上流，舊聞道院頗優游。',64,'全唐诗/poet.song.89000.json','["珥筆風聲播上流，舊聞道院頗優游。", "好將省闥彌綸手，聊寄朝廷共理憂。", "闔境鈎鋤知少盜，他時襦袴會騰謳。", "自慚爲郡無佳政，且作盧敖汗漫遊。"]'),
('ea2b1fda-8ca1-48c7-9719-002906d00cbd','送明仲舍人知邵州','李正民','宋','宋诗','song-poetry','','[]','凛然氣節壓冰霜，經歲朝紳惹御香。',64,'全唐诗/poet.song.89000.json','["凛然氣節壓冰霜，經歲朝紳惹御香。", "吾道難行驚俗眼，斯文將堕振頽綱。", "他年致主千秋鑑，此日榮親太守章。", "父子相仍居兩省，萊衣歸奉凍醪觴。"]'),
('18c18460-ae5a-406c-bf0e-efc230bec30a','奉和元叔錫服','李正民','宋','宋诗','song-poetry','','[]','榮路回翔莫歎遲，郊居連歲捧泥芝。',64,'全唐诗/poet.song.89000.json','["榮路回翔莫歎遲，郊居連歲捧泥芝。", "虎符已被新章綬，茜紱猶循舊品儀。", "應佩寶瓶三日寵，却同顯祖四明時。", "一門豐澤知難報，就日傾心比露葵。"]'),
('6ac5c493-39b8-4ffa-84cf-a4639dee2636','寄和叔','李正民','宋','宋诗','song-poetry','','[]','蹤迹飄然寄海隅，往來寧復論親疏。',192,'全唐诗/poet.song.89000.json','["蹤迹飄然寄海隅，往來寧復論親疏。", "風烟冷落漁樵市，鐘磬蕭條釋梵居。", "卜築擬爲常侍賦，干時休奉子公書。", "泰亨乃見能連茹，剝極安知不得輿。", "蹭蹬且同棲櫪馬，噞喁真類失波魚。", "男兒所患無能爾，窮達終應有命與。", "戰伐干戈誅猰貐，急難兄弟困雝渠。", "敢忘越石思梟虜，終學陶潛自荷鋤。", "婢膝奴顔焉敢比，蠟言梔貌亦羞予。", "嵇康豈肯爲尸祝，楊意何能薦子虛。", "流落丹心徒許國，衰遲華髪漸盈梳。", "勿驚歲晚多懷感，處順安排樂有餘。"]'),
('36c66f74-6408-4e1f-bf2c-e995e4b5035e','送艾若訥赴青田  其一','李正民','宋','宋诗','song-poetry','','[]','驂鸞駕鶴上青田，萬壑千巖古洞天。',32,'全唐诗/poet.song.89000.json','["驂鸞駕鶴上青田，萬壑千巖古洞天。", "堂上絃歌真吏隱，不愁淮浦有風傳。"]'),
('d9a3da0c-8ad6-4b07-adaa-6b9d255adc25','送艾若訥赴青田  其二','李正民','宋','宋诗','song-poetry','','[]','春光欲動草芊芊，水綠山青上瀨船。',32,'全唐诗/poet.song.89000.json','["春光欲動草芊芊，水綠山青上瀨船。", "若使周公但茅屋，雪袍寧醉楚江邊。"]'),
('3f3dd3d5-09d3-42ee-a727-f455be6a9c1a','元叔易去假服戲作','李正民','宋','宋诗','song-poetry','','[]','幾歲飄零領外祠，新銜不带假銀緋。',32,'全唐诗/poet.song.89000.json','["幾歲飄零領外祠，新銜不带假銀緋。", "尋魚不管嬌癡女，措大從來自綠衣。"]'),
('c5ffa876-bb6a-463c-8cbb-255dd0b5ea91','題大安驛詩大安驛距信州分水嶺二十五里壁間有鮑娘題詩云雞聲哽入江南路柳暗鶯殘别是春因題  其一','李正民','宋','宋诗','song-poetry','','[]','平生未省歷甌閩，疊巘層峰困旅人。',32,'全唐诗/poet.song.89000.json','["平生未省歷甌閩，疊巘層峰困旅人。", "珍重鮑娘詩句好，江南别是一家春。"]'),
('9bff92b8-a933-4926-acd9-795bf9c5bad7','題大安驛詩大安驛距信州分水嶺二十五里壁間有鮑娘題詩云雞聲哽入江南路柳暗鶯殘别是春因題  其二','李正民','宋','宋诗','song-poetry','','[]','兩州水向嶺頭分，入眼溪山處處新。',32,'全唐诗/poet.song.89000.json','["兩州水向嶺頭分，入眼溪山處處新。", "春色故應無彼此，江南未必勝甌閩。"]'),
('8e361938-421a-4fc2-9280-add03d41afc4','訟牒','李正民','宋','宋诗','song-poetry','','[]','決遣慚非朱子元，紛紛訟牒擁輶軒。',32,'全唐诗/poet.song.89000.json','["決遣慚非朱子元，紛紛訟牒擁輶軒。", "自嗟虚忝皇華使，材拙將何廣上恩。"]'),
('8709649d-f9b5-4a16-bb22-1376eb94855d','餘杭泛舟','李正民','宋','宋诗','song-poetry','','[]','滮田苒苒新苗出，烟隴翛翛宿麥黄。',32,'全唐诗/poet.song.89000.json','["滮田苒苒新苗出，烟隴翛翛宿麥黄。", "正是春晴蠺月好，家家織婦採柔桑。"]'),
('52205419-fd7f-439c-972d-096dfa9ed964','校舊書','李正民','宋','宋诗','song-poetry','','[]','塵垢紛紛漫掃除，可憐乾死蠹書魚。',32,'全唐诗/poet.song.89000.json','["塵垢紛紛漫掃除，可憐乾死蠹書魚。", "何須更待青藜照，只合齋心讀誤書。"]'),
('35e2d846-2398-40ab-ba04-dd6bac0623f9','趙表之創葺禪寂之室以名求詩  其一','李正民','宋','宋诗','song-poetry','','[]','誰知至寶秘冥山，費盡聰明覓轉艱。',32,'全唐诗/poet.song.89000.json','["誰知至寶秘冥山，費盡聰明覓轉艱。", "漫說化城爲止息，我今已得髻珠還。"]'),
('33f652db-8656-463d-a895-cf51a1d86146','趙表之創葺禪寂之室以名求詩  其二','李正民','宋','宋诗','song-poetry','','[]','徧覆包容等太空，乾坤都在範圍中。',32,'全唐诗/poet.song.89000.json','["徧覆包容等太空，乾坤都在範圍中。", "須知一點靈臺地，妙湛圓明未易窮。"]'),
('b5f110c5-4de0-4971-bca7-59be0e4baada','呈趙表之大監爲祥符藏基也','李正民','宋','宋诗','song-poetry','','[]','凡聖同居亦偶然，誰知龍藏結良緣。',32,'全唐诗/poet.song.89000.json','["凡聖同居亦偶然，誰知龍藏結良緣。", "聞公舊有談天口，爲借深潭五百年。"]'),
('89f3e075-eb64-4ded-ad33-5ab2cf8d80a9','木魚','李正民','宋','宋诗','song-poetry','','[]','華鯨祗爲催晨粥，想像滄波夜不冥。',32,'全唐诗/poet.song.89000.json','["華鯨祗爲催晨粥，想像滄波夜不冥。", "香飯已聞鐘鼓響，何須呼喚若丁寧。"]'),
('7cdc927f-91a9-4577-ba4c-58a3d733b39e','書河東李驤事','李正民','宋','宋诗','song-poetry','','[]','君既擇臣臣擇君，胡爲委贄事愚人。',32,'全唐诗/poet.song.89000.json','["君既擇臣臣擇君，胡爲委贄事愚人。", "李生若是真王佐，豈向偏方遽殺身。"]'),
('92f93075-f8fa-4e6a-8ce1-66eda360494e','題鹿苑寺一撃軒  其一','李正民','宋','宋诗','song-poetry','','[]','本來無物可修治，一擊當年何所知。',32,'全唐诗/poet.song.89000.json','["本來無物可修治，一擊當年何所知。", "拱手問師都不語，等閒拈起布毛吹。"]'),
('c4fab353-9dc8-4882-8850-4eb21b3b0b5f','題鹿苑寺一撃軒  其二','李正民','宋','宋诗','song-poetry','','[]','列戟排鎗幾百竿，森森直節逼人寒。',32,'全唐诗/poet.song.89000.json','["列戟排鎗幾百竿，森森直節逼人寒。", "從初一擊心方悟，篩月吟風盡可觀。"]'),
('0955088c-7bfb-42de-b949-134483956581','題羊裘軒詩','李正民','宋','宋诗','song-poetry','','[]','世祖馳驅復漢家，故人髙臥老烟霞。',32,'全唐诗/poet.song.89000.json','["世祖馳驅復漢家，故人髙臥老烟霞。", "至今只說羊裘好，拜衮誰思鄧仲華。"]'),
('a5675c28-18da-40f3-9870-395710d7b109','題丞廳清節軒詩','李正民','宋','宋诗','song-poetry','','[]','新種修篁翠葉稠，凜然清節坐驚秋。',64,'全唐诗/poet.song.89000.json','["新種修篁翠葉稠，凜然清節坐驚秋。", "官曹咸類崔斯立，風味仍同王子猷。", "暫卻鷺鵷仍退食，鸞凰此日小遲留。", "吟哦自是公家事，我亦身閒愧食浮。"]'),
('424eb7d7-21e1-4501-a377-04fee134af17','扈從航海','李正民','宋','宋诗','song-poetry','','[]','雲濤雪浪蹙天浮，隱隱征帆去未休。',32,'全唐诗/poet.song.89000.json','["雲濤雪浪蹙天浮，隱隱征帆去未休。", "蛟蜃伏藏舟楫穏，將軍何用說防秋。"]'),
('a53bc472-43c7-484f-ac94-2192feb09341','友人來詩有紙價髙之句次韻','李正民','宋','宋诗','song-poetry','','[]','文章小技等秋毫，鄙作空令筆史勞。',32,'全唐诗/poet.song.89000.json','["文章小技等秋毫，鄙作空令筆史勞。", "聞道東家方給札，柯籐穀楮兩相髙。"]'),
('e6488782-4881-42fd-8013-5ec92b438e43','觀近報','李正民','宋','宋诗','song-poetry','','[]','眼看時事又更新，尚對黄花笑逐臣。',32,'全唐诗/poet.song.89000.json','["眼看時事又更新，尚對黄花笑逐臣。", "鳬鴈去來緣底事，功名真復付何人。"]'),
('98068811-bcab-40b5-8ea7-d5adac332369','因客話有感','李正民','宋','宋诗','song-poetry','','[]','女子爭桑事至微，兩國暴骨實堪悲。',32,'全唐诗/poet.song.89000.json','["女子爭桑事至微，兩國暴骨實堪悲。", "太行孟門豈嶄絕，坐覺人情尤嶮巇。"]'),
('9b0000f7-39b5-49c5-9a7f-4f1bb0e8af6e','破賊凱歌八章  其一','李正民','宋','宋诗','song-poetry','','[]','兩宫北狩未能歸，歲歲愁看塞鴈飛。',32,'全唐诗/poet.song.89000.json','["兩宫北狩未能歸，歲歲愁看塞鴈飛。", "馬上勤勞天子詔，莫教霜霰拂龍衣。"]'),
('68c3c2c2-72f6-4530-a409-f9e5a8086053','破賊凱歌八章  其二','李正民','宋','宋诗','song-poetry','','[]','淮南千里少遺民，萬頃膏腴變棘榛。',32,'全唐诗/poet.song.89000.json','["淮南千里少遺民，萬頃膏腴變棘榛。", "闢地營田真上策，稻粱已見滿倉囷。"]'),
('746f92f5-09f6-4641-92bd-41a460f88568','破賊凱歌八章  其三','李正民','宋','宋诗','song-poetry','','[]','萬幕如雲振鼓鼙，角聲嗚咽馬驚嘶。',32,'全唐诗/poet.song.89000.json','["萬幕如雲振鼓鼙，角聲嗚咽馬驚嘶。", "亞夫持重惟堅壁，應爲桑榆太白低。"]'),
('0387aa34-5198-4371-b39e-e89c6fe0f5a1','破賊凱歌八章  其四','李正民','宋','宋诗','song-poetry','','[]','聞道淮西遏賊鋒，捷書半夜到行宫。',32,'全唐诗/poet.song.89000.json','["聞道淮西遏賊鋒，捷書半夜到行宫。", "投戈盡是三齊士，不用鯨鯢志武功。"]'),
('ac717c76-8d0c-46e2-aed6-cef6c27a0399','破賊凱歌八章  其五','李正民','宋','宋诗','song-poetry','','[]','簽軍五萬立降旗，虜將倉皇去莫追。',32,'全唐诗/poet.song.89000.json','["簽軍五萬立降旗，虜將倉皇去莫追。", "已出壽春三百里，將軍旋旆整歸師。"]'),
('f05c7728-ff23-45c2-b02b-23155f3bb044','破賊凱歌八章  其六','李正民','宋','宋诗','song-poetry','','[]','君王聖武自臨戎，諸將歡呼戰必躬。',32,'全唐诗/poet.song.89000.json','["君王聖武自臨戎，諸將歡呼戰必躬。", "不是江頭旗鼓出，退師安得却成功。"]'),
('c7cc54e4-cc98-4f6f-9b4c-ab80e09b7190','破賊凱歌八章  其七','李正民','宋','宋诗','song-poetry','','[]','再歲吴門賦出車，廟堂謀斷兩相符。',32,'全唐诗/poet.song.89000.json','["再歲吴門賦出車，廟堂謀斷兩相符。", "中興功業休嗟晚，收復關河是壯圖。"]'),
('9ddc68ad-ce7c-4b63-885b-451093615e7a','破賊凱歌八章  其八','李正民','宋','宋诗','song-poetry','','[]','皇朝德澤浸寰瀛，僞虜乘時敢抗衡。',32,'全唐诗/poet.song.89000.json','["皇朝德澤浸寰瀛，僞虜乘時敢抗衡。", "南北生民皆赤子，自然不戰屈人兵。"]'),
('386c3617-34a7-4b70-a43c-13edec6c74e6','至嘉禾','李正民','宋','宋诗','song-poetry','','[]','溪山繚繞踰千里，水陸馳驅閱五州。',32,'全唐诗/poet.song.89000.json','["溪山繚繞踰千里，水陸馳驅閱五州。", "不是江鱸勝肥羜，此身那肯便東遊。"]'),
('b999a706-29b3-4296-a1ec-ffc020488fb0','覧史  其一','李正民','宋','宋诗','song-poetry','','[]','塞侯微巧爲求名，司馬巧宦至九卿。',32,'全唐诗/poet.song.89000.json','["塞侯微巧爲求名，司馬巧宦至九卿。", "汲黯戇直安仁拙，千載悠悠誰重輕。"]'),
('493561cf-680f-47c9-ad3b-13a93bb73016','覧史  其二','李正民','宋','宋诗','song-poetry','','[]','廷尉結襪名愈重，力士脫靴讒遽臻。',32,'全唐诗/poet.song.89000.json','["廷尉結襪名愈重，力士脫靴讒遽臻。", "君子小人所懷異，擇地而行乃保身。"]'),
('6e493b35-7bc8-4641-be42-b485729e0d09','覧史  其三','李正民','宋','宋诗','song-poetry','','[]','司馬萬事只稱好，司空老矣三宜休。',32,'全唐诗/poet.song.89000.json','["司馬萬事只稱好，司空老矣三宜休。", "處世何庸誇蹇蹇，濟時無術早抽頭。"]'),
('6de445c0-388a-4a96-8ed2-8c8db7b60ecc','覓松江水','李正民','宋','宋诗','song-poetry','','[]','啄腐吞腥聊當肉，消煩止渇必資茶。',32,'全唐诗/poet.song.89000.json','["啄腐吞腥聊當肉，消煩止渇必資茶。", "憑君爲汲松江水，活火煎來泛乳花。"]'),
('2fd938dd-3e75-4eee-a6ec-d42fa618cf0e','鄭相家遇盗僑年以貧訴于朝得倅泉州','李正民','宋','宋诗','song-poetry','','[]','當衢甲第起青烟，曾見升平富貴年。',32,'全唐诗/poet.song.89000.json','["當衢甲第起青烟，曾見升平富貴年。", "一旦淒涼人事改，不勞優孟戲君前。"]'),
('471a69e5-58f6-4e80-bca6-39e88b856693','移桃栽晚發','李正民','宋','宋诗','song-poetry','','[]','綠葉盈條巧剪裁，餘花猶有兩三開。',32,'全唐诗/poet.song.89000.json','["綠葉盈條巧剪裁，餘花猶有兩三開。", "新來試手移桃李，待向茅堂取次栽。"]'),
('0721bdf5-9dc9-43bd-b04a-14ae0a15d8a9','大姓輸錢詩','李正民','宋','宋诗','song-poetry','','[]','大姓輸錢欲贍軍，州符縣帖閙如雲。',32,'全唐诗/poet.song.89000.json','["大姓輸錢欲贍軍，州符縣帖閙如雲。", "于今却羡鍾山老，用盡經綸得二分。"]'),
('032931da-3fb3-4d9f-9cab-abad1e9e034c','蘭溪懷和叔','李正民','宋','宋诗','song-poetry','','[]','山遙水闊方通婺，筍嫩魚肥已勝衢。',32,'全唐诗/poet.song.89000.json','["山遙水闊方通婺，筍嫩魚肥已勝衢。", "寄語長潭隱君子，别來薇蕨味何殊。"]'),
('74bb95c4-0f14-43e8-a9f2-bd34d915be68','慈雲老人','李正民','宋','宋诗','song-poetry','','[]','白足蒼顔老行全，曾随逐客海南邊。',32,'全唐诗/poet.song.89000.json','["白足蒼顔老行全，曾随逐客海南邊。", "願將一滴曹溪水，救取城中劫火然。"]'),
('dd0da1e1-7a9d-422d-94d8-5b456534ff84','瓶花','李正民','宋','宋诗','song-poetry','','[]','折得寒梅全未開，銅瓶貯水養根荄。',32,'全唐诗/poet.song.89000.json','["折得寒梅全未開，銅瓶貯水養根荄。", "臨鸞競洗晨粧面，疑是春風入户來。"]'),
('3be164bf-d466-4f73-81e0-773143faf534','夜半','李正民','宋','宋诗','song-poetry','','[]','虚堂臥聽雨如傾，却訝蟾光透牖明。',32,'全唐诗/poet.song.89000.json','["虚堂臥聽雨如傾，却訝蟾光透牖明。", "起喚僕人猶未醒，樓頭撾鼓報三更。"]'),
('1e108d32-ded6-4e8f-b843-be336d5f3d25','南歸  其一','李正民','宋','宋诗','song-poetry','','[]','淪身絕域久睽孤，投老歸來鬢髪疏。',32,'全唐诗/poet.song.89000.json','["淪身絕域久睽孤，投老歸來鬢髪疏。", "不但髙人能笑我，此生安敢食鱸魚。"]'),
('ed889f0e-e902-4812-871c-9fd4e1a7706b','南歸  其二','李正民','宋','宋诗','song-poetry','','[]','三年海上牧羊羣，已分沙埸寄旅魂。',32,'全唐诗/poet.song.89000.json','["三年海上牧羊羣，已分沙埸寄旅魂。", "滿面塵埃人不識，相看惟覺語音存。"]'),
('c712733f-ecd8-4e10-b7dd-df16ddaef1a2','南歸  其三','李正民','宋','宋诗','song-poetry','','[]','風霜不改舊茅茨，自悔輕身觸禍機。',32,'全唐诗/poet.song.89000.json','["風霜不改舊茅茨，自悔輕身觸禍機。", "丈室本來無一物，猶存禪榻待翁歸。"]'),
('deb2b5a1-8b84-4b5e-9b07-333986a72a8d','南歸  其四','李正民','宋','宋诗','song-poetry','','[]','黄童白叟喜相迎，底事吴儂亦有情。',32,'全唐诗/poet.song.89000.json','["黄童白叟喜相迎，底事吴儂亦有情。", "絕域歸來真異事，幸逢西北罷戈兵。"]'),
('859980d0-96d2-4713-96c7-3a3907667b72','南歸  其五','李正民','宋','宋诗','song-poetry','','[]','蕭蕭草木映疏籬，猿鶴相看似見疑。',32,'全唐诗/poet.song.89000.json','["蕭蕭草木映疏籬，猿鶴相看似見疑。", "大雅保身還自愧，不須更誦北山移。"]'),
('e727cff1-82a3-4c41-af07-1cae2cc5c7ee','南歸  其六','李正民','宋','宋诗','song-poetry','','[]','南北飄零三十秋，亂離重到舊揚州。',32,'全唐诗/poet.song.89000.json','["南北飄零三十秋，亂離重到舊揚州。", "田園蕪沒身空老，却羡如今馬少游。"]'),
('fc1b675a-424e-4dad-976f-e985b5a5c156','南歸  其七','李正民','宋','宋诗','song-poetry','','[]','投老耽書未肯休，世間萬緒判悠悠。',32,'全唐诗/poet.song.89000.json','["投老耽書未肯休，世間萬緒判悠悠。", "草堂盖罷渾無事，猶待翻修五鳯樓。"]'),
('dc847f2c-3606-45cd-b15e-2ec190bc4585','福廷村','李正民','宋','宋诗','song-poetry','','[]','雲海茫茫天一涯，田園蕪沒竟何歸。',64,'全唐诗/poet.song.89000.json','["雲海茫茫天一涯，田園蕪沒竟何歸。", "福廷自可求靈藥，夜月虛傳掩少微。", "莫訝長鬚尋不得，只緣雙鯉別來稀。", "三間茅屋何時辦，白髮相看傍釣磯。"]'),
('66a57fa9-e629-46a3-8ffc-3d4eef18616d','大宋中興雅','李正民','宋','宋诗','song-poetry','','[]','炎正中微，泰極而否。',240,'全唐诗/poet.song.89000.json','["炎正中微，泰極而否。", "邊陲雲擾，中原糜沸。", "靖康之元，逼我京師。", "金湯弛備，兵纏紫微。", "天方佑宋，帝在濟陽。", "貔貅十萬，左右陳行。", "旌旗蔽野，戈鋋彗雲。", "八神警蹕，七萃駿奔。", "移師商丘，億兆樂推。", "謳歌獄訟，竭蹶咸歸。", "爰登寶位，爰紹丕基。", "兢兢業業，一日萬機。", "既巡淮甸，乃涖浙江。", "遣使聘問，原隰相望。", "兩宮未復，夙夜靡遑。", "經之營之，十有餘年。", "戊午之秋，使車來旋。", "謂彼鄰國，遠達溫言。", "欲講盟好，厥志已堅。", "使在淮浦，衆言盈庭。", "如蜩如螗，如沸如羹。", "更唱迭和，萬口狺狺。", "帝若不聞，默與神謀。", "聖志先定，惟相是諏。"]'),
('d3fcf6d3-29f3-4412-a2a4-28bf5c1c4c3a','中興','李正民','宋','宋诗','song-poetry','','[]','中興功業竟如何，決勝終疑算未多。',64,'全唐诗/poet.song.89000.json','["中興功業竟如何，決勝終疑算未多。", "使者出疆思陸賈，君王當饋憶廉頗。", "深思社稷堪流涕，聞說風塵合枕戈。", "自嘆書生無遠略，五湖煙浪整漁蓑。"]'),
('66ce9709-3517-4216-a40e-e4c34496837d','送汪彥章之宜興','李正民','宋','宋诗','song-poetry','','[]','春江渺渺草芊芊，曉色晴嵐映客船。',64,'全唐诗/poet.song.89000.json','["春江渺渺草芊芊，曉色晴嵐映客船。", "結綬相先真偶爾，盍簪易失故依然。", "獲麟筆削閑中斷，吐鳳文詞海外傳。", "行李同途不同發，消魂回首各風煙。"]'),
('6dccca7f-f165-4eaf-b538-867e962e0cea','句  其一','李正民','宋','宋诗','song-poetry','','[]','黄樹性堅正，枝葉已剛願。',48,'全唐诗/poet.song.89000.json','["黄樹性堅正，枝葉已剛願。", "三十六旬久，增生才方寸。", "今何成修林，左右映霞蔓。", "良材豈一二，所期在不鈍。"]'),
('b2973b10-f3bf-43d3-a165-c33eb67c8532','句  其二','李正民','宋','宋诗','song-poetry','','[]','令人卻憶漫浪翁。',8,'全唐诗/poet.song.89000.json','["令人卻憶漫浪翁。"]'),
('ee688145-7ca9-4d9a-944d-4d97d7f9ac23','句  其一','方維','宋','宋诗','song-poetry','','[]','青膽雄於金斗大，赤心堅比鐵山高。',16,'全唐诗/poet.song.89000.json','["青膽雄於金斗大，赤心堅比鐵山高。"]'),
('def6b264-d243-40ba-ab74-426775293e50','句  其二','方維','宋','宋诗','song-poetry','','[]','身在江城抑何暮，心遊魏闕不崇朝。',16,'全唐诗/poet.song.89000.json','["身在江城抑何暮，心遊魏闕不崇朝。"]'),
('df3fe281-a47c-4975-abf0-d6e19bda8404','句  其三','方維','宋','宋诗','song-poetry','','[]','垣墉角占樓臺近，城郭心藏洞府深。',16,'全唐诗/poet.song.89000.json','["垣墉角占樓臺近，城郭心藏洞府深。"]'),
('5132f3ee-1ff1-45d3-af75-48083ae76c32','晚醉口占','譚知柔','宋','宋诗','song-poetry','','[]','晚醉扶筇過竹村，數家殘雪想法籬根。',33,'全唐诗/poet.song.89000.json','["晚醉扶筇過竹村，數家殘雪想法籬根。", "風前有恨梅千點，沙上無人月一痕。"]'),
('40541ede-f108-4dd3-9995-c3b61e13559a','絕句  其一','譚知柔','宋','宋诗','song-poetry','','[]','麥隴風來翠浪浮，霏微小雨似深秋。',32,'全唐诗/poet.song.89000.json','["麥隴風來翠浪浮，霏微小雨似深秋。", "野亭終日捲簾坐，清樾對啼黄栗留。"]'),
('674fdbeb-16cd-44be-b069-62737a35bf35','絕句  其二','譚知柔','宋','宋诗','song-poetry','','[]','漫郎無處覓歸田，江北江南水拍天。',32,'全唐诗/poet.song.89000.json','["漫郎無處覓歸田，江北江南水拍天。", "斗摟十年塵土夢，秋風吹上釣魚船。"]'),
('150e5123-a794-4c05-b8ba-a6d0e5c4ee27','絕句','譚知柔','宋','宋诗','song-poetry','','[]','低昂綠樹春驕我，偃蹇青山氣壓人。',32,'全唐诗/poet.song.89000.json','["低昂綠樹春驕我，偃蹇青山氣壓人。", "遠山故作低眉恨，好鳥能爲緩頰聲。"]'),
('51fd03a4-e78d-4c6c-9aba-c5dfbf78ee3e','練湖春霽','譚知柔','宋','宋诗','song-poetry','','[]','春入池塘綠漲初，蒲根水暖戲鷗鳬。',64,'全唐诗/poet.song.89000.json','["春入池塘綠漲初，蒲根水暖戲鷗鳬。", "雜花開處自深淺，細雨漾空如有無。", "風外鍾聲聞遠寺，柳間帆影出平湖。", "冥搜竟日耽佳句，不負宗生來畫圖。"]'),
('ae5f5d40-7d97-4f32-832a-fdf34b62be41','存目','譚知柔','宋','宋诗','song-poetry','','[]','詩題：印纍纍首句：印纍纍，綬若若。',17,'全唐诗/poet.song.89000.json','["詩題：印纍纍首句：印纍纍，綬若若。"]'),
('2e2f7d99-300b-4d09-81e0-8fcc7ece00a1','五洩山','郭亢','宋','宋诗','song-poetry','','[]','不到茲山三十年，重來風物自依然。',64,'全唐诗/poet.song.89000.json','["不到茲山三十年，重來風物自依然。", "兩源秋色排千嶂，五級泉聲落半天。", "絕唱尚傳閑老句，幽棲猶想默詩禪。", "回頭迥與塵寰隔，何必蓬萊始是仙。"]'),
('13880258-7528-4ffc-8123-ca399a5d9033','和榴皮題壁韻  其一','郭椿年','宋','宋诗','song-poetry','','[]','回仙畫像留東壁，薜荔團圞拱尺餘。',32,'全唐诗/poet.song.89000.json','["回仙畫像留東壁，薜荔團圞拱尺餘。", "昔日丹青今是否，斷編何處覓全書。"]'),
('8f039e4b-0252-4e09-a9b8-5c82b6c64999','和榴皮題壁韻  其二','郭椿年','宋','宋诗','song-poetry','','[]','欲知古寺傳神處，便是東庵飲酒餘。',32,'全唐诗/poet.song.89000.json','["欲知古寺傳神處，便是東庵飲酒餘。", "誰道逍遙蓬島客，最能提唱竺乾書。"]'),
('a3cd9c05-1a07-4d7f-8706-cb598c20b369','和榴皮題壁韻  其三','郭椿年','宋','宋诗','song-poetry','','[]','百歲光陰殊迅速，滿堂金玉謾謳吟贏餘。',34,'全唐诗/poet.song.89000.json','["百歲光陰殊迅速，滿堂金玉謾謳吟贏餘。", "豈無白日昇天事，未有陰功紫府書。"]'),
('ccde994e-d5b0-4748-8c7e-4234b1529aae','題王司理持平堂','王俊','宋','宋诗','song-poetry','','[]','淑問皋陶晞在泮，奉公不撓幕中參。',64,'全唐诗/poet.song.89000.json','["淑問皋陶晞在泮，奉公不撓幕中參。", "仰思弼教刑明五，深念求情法以三。", "虞詡爲卿宜有自，于公比德蓋無慚。", "圄空草茂庭柯綠，行詠甘棠踵召南。"]'),
('8f281efc-3585-4d78-8480-f00e0fd50df3','依韻和董彌大郎中禱雨詩','王俊','宋','宋诗','song-poetry','','[]','雷嗔旱魃藴煩冤，海底驅龍碧浪翻。',32,'全唐诗/poet.song.89000.json','["雷嗔旱魃藴煩冤，海底驅龍碧浪翻。", "飛上九天作霖雨，端知昭格佑宸軒。"]'),
('9c7429ad-788f-4fb9-b51b-b4b17cce9057','林塘雙頭蓮  其一','雷孚','宋','宋诗','song-poetry','','[]','綠柄亭亭拆兩枝，開花成實亦如之。',32,'全唐诗/poet.song.89000.json','["綠柄亭亭拆兩枝，開花成實亦如之。", "詩翁想像渾無事，疑是昌宗總角時。"]'),
('ee7ac27b-db77-42f1-9058-5c6f1588397f','林塘雙頭蓮  其二','雷孚','宋','宋诗','song-poetry','','[]','一幹雙花一撲紅，穠花彫盡兩心同。',32,'全唐诗/poet.song.89000.json','["一幹雙花一撲紅，穠花彫盡兩心同。", "紅成珠實心猶苦，疑是英皇怨舞宮。"]'),
('5d4c3f5a-9231-4984-9e3f-3e4fa4cb0961','遊鯉湖','張𨊠','宋','宋诗','song-poetry','','[]','暝雲竹逕濕蒼苔，巖頂珠宮絕點埃。',64,'全唐诗/poet.song.89000.json','["暝雲竹逕濕蒼苔，巖頂珠宮絕點埃。", "澗水遠分山色斷，林猿時带笛聲來。", "唐朝百載惟詩在，漢事千年若夢回。", "湖鯉猶傳靈異跡，無人不道是天台。"]'),
('2a71fa81-ce1c-41f9-afae-cb816f0e81f8','曉望  其一','盧奎','宋','宋诗','song-poetry','','[]','武陵都會俗豪奢，井邑雲連幾萬家。',64,'全唐诗/poet.song.89000.json','["武陵都會俗豪奢，井邑雲連幾萬家。", "東望李洲餘橘實，西迎秦洞出桃花。", "宦游稔識衣冠盛，罷去猶憐道路賒。", "十九年來人事改，暮山依舊鎖煙霞。"]'),
('6126999b-3eb5-4ba5-9094-592f263942fd','曉望  其二','盧奎','宋','宋诗','song-poetry','','[]','郡枕寒江臥虎形，池饒千里勢寬平。',64,'全唐诗/poet.song.89000.json','["郡枕寒江臥虎形，池饒千里勢寬平。", "曾勞秦楚雄吞併，幾誤孫劉力戰爭。", "尚憶笙歌遊綠野，豈期牛馬牧蕪城。", "夕陽杖策閑登賞，懷古觀今一愴情。"]'),
('388b7cb0-724b-42b6-a05c-ce0beae1d659','曉望  其三','盧奎','宋','宋诗','song-poetry','','[]','郭外臨沅一水長，朝宗東下合瀟湘。',64,'全唐诗/poet.song.89000.json','["郭外臨沅一水長，朝宗東下合瀟湘。", "昔觀競渡皆遊舸，今聽鳴鼙盡戰航。", "自古勝妖無過德，到頭兼弱亦因強。", "看看一洗腥羶盡，千里還聞有芷香。"]'),
('d8b58747-cd47-4510-9b05-590a8fb0947a','自詠','任忠厚','宋','宋诗','song-poetry','','[]','有個官人靡恃己，著領藍袍罔談彼。',32,'全唐诗/poet.song.89000.json','["有個官人靡恃己，著領藍袍罔談彼。", "面上带些天地玄，眼中更有陳權委。"]'),
('53fb4db8-b0ec-468b-8fd9-63457a3dc1b9','萬歲山','吳致堯','宋','宋诗','song-poetry','','[]','赤藤可扶險，青藜堪照書。',24,'全唐诗/poet.song.89000.json','["赤藤可扶險，青藜堪照書。", "老師竟何爲，暮齒隨安車。"]'),
('f73fec76-cf2f-4a26-91f5-f75ad3ae8284','五蓋山','吳致堯','宋','宋诗','song-poetry','','[]','紫蓋修連延，五峰似隨軒。',24,'全唐诗/poet.song.89000.json','["紫蓋修連延，五峰似隨軒。", "何如惠我民，飛雪遍岡原。"]'),
('ddc9f5d6-94a7-4c8e-a66e-8855ee00ceb1','聖壽寺','馮安上','宋','宋诗','song-poetry','','[]','特起孤峰聳白雲，又環雙澗隔紅塵。',64,'全唐诗/poet.song.89000.json','["特起孤峰聳白雲，又環雙澗隔紅塵。", "枯崖有字唐元傑，古廟無碑舜二臣。", "草木怪靈千種藥，山川濃秀四時春。", "邦人競效封人頌，寺額金書聖壽新。"]'),
('4d7bdb04-9b00-496c-acfe-547e894b0a6f','凌煙嶂','馮安上','宋','宋诗','song-poetry','','[]','南山山下多佳石，過眼欣逢詩黨齡得。',33,'全唐诗/poet.song.89000.json','["南山山下多佳石，過眼欣逢詩黨齡得。", "最憐小嶂隔窗前，透出煙光露秋碧。"]'),
('8b973ba0-8af3-4e09-b367-ce3a92dd8aee','石門','洪壯','宋','宋诗','song-poetry','','[]','鎖斷山川秀，包藏雲霧深。',24,'全唐诗/poet.song.89000.json','["鎖斷山川秀，包藏雲霧深。", "只留禪客在，不許俗塵侵。"]'),
('315a27cb-843b-48bd-acd8-251307b0c8e3','半月池','洪壯','宋','宋诗','song-poetry','','[]','鑿破蒼苔地，灣灣月半邊。',24,'全唐诗/poet.song.89000.json','["鑿破蒼苔地，灣灣月半邊。", "既能清到底，何必十分圓。"]'),
('828cab5b-ee17-483e-80c8-cfbb6b420295','擁秀堂','洪壯','宋','宋诗','song-poetry','','[]','松带飛雪暮，簷支落日閑。',24,'全唐诗/poet.song.89000.json','["松带飛雪暮，簷支落日閑。", "重巖看不厭，絕勝五臺山。"]'),
('60d995c0-5b81-495c-a324-00eb2dc8629d','應制詠菊','黄宣','宋','宋诗','song-poetry','','[]','可訝東籬菊，能知節候芳。',48,'全唐诗/poet.song.89000.json','["可訝東籬菊，能知節候芳。", "細枝青玉潤，繁葉碎金香。", "爽氣浮朝露，濃姿带夜霜。", "泛杯傳壽酒，應共樂時康。"]'),
('529f0454-a786-4016-9a9f-44bbe39f0b48','括蒼洞','林晨','宋','宋诗','song-poetry','','[]','落日泉聲咽梵宮，依簷山色翠摩空。',32,'全唐诗/poet.song.89000.json','["落日泉聲咽梵宮，依簷山色翠摩空。", "劉晨去後門長啟，時見桃花滿地紅。"]'),
('4cc38b6d-5d67-448f-8c21-c9bed41d100d','止齋即事','婁寅亮','宋','宋诗','song-poetry','','[]','居與仙巖鄰，未悉仙巖路。',72,'全唐诗/poet.song.89000.json','["居與仙巖鄰，未悉仙巖路。", "片棹偶相及，山僧頻禮數。", "指點覓餘跡，行行道其故。", "是爲梅雨潭，排空成瀑布。", "常生六月寒，輶軒每相顧。", "嗟哉往來者，寧不忝尸素。"]'),
('0b9d1bc3-8797-42c2-a3b5-d2ba0421aab8','講易','丘程','宋','宋诗','song-poetry','','[]','易理分明在畫中，誰知易道畫難窮。',32,'全唐诗/poet.song.89000.json','["易理分明在畫中，誰知易道畫難窮。", "不知畫意空箋注，何異丹青欲畫風。"]'),
('de3d1efd-33fb-4f48-a124-b30295332d07','題大慈寺','陸煥','宋','宋诗','song-poetry','','[]','天下紛紛吹戰塵，我來佛隴悟修身。',32,'全唐诗/poet.song.89000.json','["天下紛紛吹戰塵，我來佛隴悟修身。", "依然猿鶴如相識，知是山中幾世人。"]'),
('f6b6f9a2-86f4-43e9-aeed-86622e911fd1','句  其一','歐陽燾','宋','宋诗','song-poetry','','[]','冰井有泓閑潄玉，火山無焰謾生煙。',16,'全唐诗/poet.song.89000.json','["冰井有泓閑潄玉，火山無焰謾生煙。"]'),
('ae94fe2d-fcfc-43f7-8006-6d9768bb5239','句  其二','歐陽燾','宋','宋诗','song-poetry','','[]','恭公遺治傳耆舊，元結雄文載簡編。',16,'全唐诗/poet.song.89000.json','["恭公遺治傳耆舊，元結雄文載簡編。"]'),
('41c07e20-fdcb-4a0a-9726-38aec78079a1','辭官','余嗣','宋','宋诗','song-poetry','','[]','試把人間比夢間，也須回首舊家山。',32,'全唐诗/poet.song.89000.json','["試把人間比夢間，也須回首舊家山。", "人生待足何時足，未老偷閑卻是閑。"]'),
('2ae7270d-58d6-459f-be42-fe3d8f145410','南龕山','鄭之才','宋','宋诗','song-poetry','','[]','一本修柟出萬蓬，挺生綿邈尚誰窮。',64,'全唐诗/poet.song.89000.json','["一本修柟出萬蓬，挺生綿邈尚誰窮。", "胡爲壯烈思嚴老，雅愛甘棠學召公。", "惟德自應存庇蔭，企賢那不念英雄。", "要知遺躅傳無盡，時聽龕崖度遠風。"]'),
('f4a3c187-1247-4208-920c-26edd245ed88','句','楊友','宋','宋诗','song-poetry','','[]','可憐鱗細閑驚躍，誤把新蟾作釣鈎。',16,'全唐诗/poet.song.89000.json','["可憐鱗細閑驚躍，誤把新蟾作釣鈎。"]'),
('d043ed56-7c5f-43c6-965c-c2618f387498','重遊超化寺','黄覲','宋','宋诗','song-poetry','','[]','西山背水古招提，經歲重來覓舊堤。',64,'全唐诗/poet.song.89000.json','["西山背水古招提，經歲重來覓舊堤。", "槭槭鼓秋黄葉下，陰陰結雨黑雲低。", "平生恐負林泉約，明日還愁步履迷。", "睡足一甌湯餅滿，更休作禮問曹溪。"]'),
('a87c5d12-55ea-4779-b6d4-0864f451b03f','句','政和太學生','宋','宋诗','song-poetry','','[]','博陵公子真文虎，占斷儒官第二人。',16,'全唐诗/poet.song.89000.json','["博陵公子真文虎，占斷儒官第二人。"]'),
('f758075b-deda-4d08-9dae-ea6a10e71167','句','范溶','宋','宋诗','song-poetry','','[]','蘭汀六雁圖。',6,'全唐诗/poet.song.89000.json','["蘭汀六雁圖。"]'),
('6676253c-eff0-40a7-86c1-a40175b58f9a','草堂','黄檥','宋','宋诗','song-poetry','','[]','徑入小庭迂，登登豈按圖。',48,'全唐诗/poet.song.89000.json','["徑入小庭迂，登登豈按圖。", "主人緣雅趣，有客愛規模。", "鷗與鄰翁狎，船從稚子呼。", "何當迎接汝，有夢隔江湖。"]'),
('8d2c599c-c5ef-4aa9-a893-3cf7962a1674','送士特兄下第之衡湘','李綱','宋','宋诗','song-poetry','','[]','都城三月春暮時，通津兩岸楊花飛。',128,'全唐诗/poet.song.89000.json','["都城三月春暮時，通津兩岸楊花飛。", "送君結束適南楚，使我歎息生長悲。", "男兒功名致須早，夫子聲譽久已馳。", "文章黼黻雖自許，時運齟齬將安施。", "霜蹄暫蹶未爲失，雲翮髙舉終非遲。", "人生且求適意處，天命會有不否期。", "瀟湘千里渺煙浪，浮家早逐秋鴻歸。", "娥英事實素難考，來時爲讀黄陵碑。"]'),
('02b72363-e870-4cd3-8a05-2833b7602da4','子房','李綱','宋','宋诗','song-poetry','','[]','漢楚存亡談笑中，子房初不有其功。',32,'全唐诗/poet.song.89000.json','["漢楚存亡談笑中，子房初不有其功。", "閉門辟穀思輕舉，肯歎淮陰犬與弓。"]'),
('ec6012f1-1ea9-44b0-b70c-1a356fb90aa8','讀楚元王傳','李綱','宋','宋诗','song-poetry','','[]','設醴當年爲穆生，偶忘微禮便辭榮。',32,'全唐诗/poet.song.89000.json','["設醴當年爲穆生，偶忘微禮便辭榮。", "固知申白無先見，衣赭髠鉗始自驚。"]'),
('2124d169-e205-4256-a168-262becfa905c','謁告迎奉聞親闈有醴泉之除不勝慶抃作詩寄叔易季言二弟','李綱','宋','宋诗','song-poetry','','[]','薄宦便甘旨，兩載官南徐。',228,'全唐诗/poet.song.89000.json','["薄宦便甘旨，兩載官南徐。", "江山富佳致，足以爲親娛。", "昆弟盡在傍，承顔懽有餘。", "寧知驛書召，結束趨征途。", "旅食寓京華，夢想懷庭除。", "宸恩賜清燕，天語聞都俞。", "蘭省幸備員，匪才慚冒居。", "思親動歸興，謁告之東吳。", "曉出通津門，輕舠泛汴渠。", "鶯花已爛熳，榆柳正扶疏。", "去去指苕霅，行行遠神都。", "中途聞吉語，動色觀除書。", "天子隆孝治，朝廷優老儒。", "犬馬志欲養，獲此伸區區。", "丘山恩施重，螻蟻輕捐軀。", "寓書東飛鴻，早早達吾廬。", "季也在親側，援琴方舞雩。", "聆音想慰懌，具駕無踟蹰。", "會言亦近止，期以薫風初。"]'),
('df1ac948-3a25-4074-aca7-dea97e013e0b','奉酬胡俊明博士見寄','李綱','宋','宋诗','song-poetry','','[]','載筆螭坳侍九天，謫來山澤作臞仙。',64,'全唐诗/poet.song.89000.json','["載筆螭坳侍九天，謫來山澤作臞仙。", "鳴岡敢並喈喈鳯，感氣聊同嘒嘒蟬。", "引義每慚爰叔直，著鞭常恐祖生先。", "庭闈一去三千里，自歎飄零曷日還。"]');
